-- Poems batch 121
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('177cda2f-258a-499c-a86c-2d5f4fcb9103','庚申元日口號六首  其五','陸游','宋','宋诗','song-poetry','','[]','去年迎客已蹣跚，今歲人扶出亦難。',32,'全唐诗/poet.song.132000.json','["去年迎客已蹣跚，今歲人扶出亦難。", "堪笑此翁衰到底，重裘絮帽尚言寒。"]'),
('3c87951b-1e1b-4848-8848-3d992b4c36d0','庚申元日口號六首  其六','陸游','宋','宋诗','song-poetry','','[]','仁和館外列鵷行，憶送龍舟幸建康。',32,'全唐诗/poet.song.132000.json','["仁和館外列鵷行，憶送龍舟幸建康。", "舍北老人同甲子，相逢揮泪說高皇。"]'),
('3437bf91-8a77-42bd-839b-dfd3111c94b5','視東皋歸','陸游','宋','宋诗','song-poetry','','[]','抱耒新湖葑，燒畬古廟壖。',48,'全唐诗/poet.song.132000.json','["抱耒新湖葑，燒畬古廟壖。", "宦遊悲骯髒，歸卧困沉綿。", "日隱啼鴉戍，舟回落雁天。", "衰殘知迫死，不忍負青編。"]'),
('217d820b-9afb-48b0-b76b-05557abe1548','晚步舍東','陸游','宋','宋诗','song-poetry','','[]','遇興穿叢竹，尋香折野梅。',48,'全唐诗/poet.song.132000.json','["遇興穿叢竹，尋香折野梅。", "暮天寒欲雪，幽徑綠生苔。", "栖雀爭枝噪，歸牛並塹來。", "高城角聲動，不盡古今哀。"]'),
('4c8ddd06-682d-4624-8dd9-34338039ee74','人日東園','陸游','宋','宋诗','song-poetry','','[]','歲首未入春，風氣已稍和。',96,'全唐诗/poet.song.132000.json','["歲首未入春，風氣已稍和。", "我睡意慵起，如此鳴禽何。", "駕言之東園，落梅亦已多。", "江南無堅冰，綠池生微波。", "挹彼蒲萄醅，酌我鸚鵡螺。", "雖無絲與竹，倚樹自高歌。", "矯首東南望，稽山鬰嵯峨。", "兒曹幸力穡，老子得婆娑。"]'),
('7d0e4f4a-e51a-4ed5-99da-25a47d77881d','逆旅行','陸游','宋','宋诗','song-poetry','','[]','古者謂死爲歸人，此身未死均是客。',80,'全唐诗/poet.song.132000.json','["古者謂死爲歸人，此身未死均是客。", "家爲逆旅身在途，久寓遽歸初不擇。", "逆旅相看隨薄厚，非意相干寧足責。", "世間何處無谿山，得酒盡醉當墮幘。", "傍觀嘲誚亦其宜，東海定非蠡可測。"]'),
('b1305ea5-a2ec-4941-a45e-edc7290e79e4','小雨初霽','陸游','宋','宋诗','song-poetry','','[]','歸來偶似老淵明，消渴誰憐病長卿。',64,'全唐诗/poet.song.132000.json','["歸來偶似老淵明，消渴誰憐病長卿。", "小雨染成芳草色，好風吹斷畫簷聲。", "剪燈院落晨猶冷，賣酒樓臺晚旋晴。", "莫道此翁遊興懶，蘭亭禹寺已關情。"]'),
('66f748fc-797b-4cc2-b065-9fdd973574dd','獨夜','陸游','宋','宋诗','song-poetry','','[]','村路泥淹雪，虛簷水結冰。',48,'全唐诗/poet.song.132000.json','["村路泥淹雪，虛簷水結冰。", "長征荷戈客，暫到放包僧。", "妖鵩鳴高樹，饑鼯觸闇燈。", "誰能問良苦，衰病正相乘。"]'),
('91da8695-6262-4028-b1ea-7ec158d604e0','忍窮','陸游','宋','宋诗','song-poetry','','[]','短褐財遮骭，孤烟僅續炊。',48,'全唐诗/poet.song.132000.json','["短褐財遮骭，孤烟僅續炊。", "久窮方有味，古語不吾欺。", "堅坐忘昏旦，殘年迫耄期。", "尚餘書滿屋，手校付吾兒。"]'),
('b9cc1da4-fecc-4efb-b142-04b884c14999','開歲半月湖村梅開無餘偶得五詩以烟溼落梅村爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','斷岸通別浦，孤舟入春烟。',48,'全唐诗/poet.song.132000.json','["斷岸通別浦，孤舟入春烟。", "與梅本無期，忽到醉眼邊。", "折花插紗帽，花重覺帽偏。", "居人空巷看，疑是湖中仙。"]'),
('24b6aeed-a7b0-4e9b-9113-2b783e3d2448','開歲半月湖村梅開無餘偶得五詩以烟溼落梅村爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','我來梅花村，倚杖久佇立。',48,'全唐诗/poet.song.132000.json','["我來梅花村，倚杖久佇立。", "惜哉風雨餘，零落綠苔溼。", "往年賦詩人，去袂不可執。", "明朝梅亦空，感舊百憂集。"]'),
('68997fbc-3306-431b-9d45-8cae19d24660','開歲半月湖村梅開無餘偶得五詩以烟溼落梅村爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','梅花如高人，妙在一丘壑。',48,'全唐诗/poet.song.132000.json','["梅花如高人，妙在一丘壑。", "林逋語雖工，竟未脫纏縛。", "乃知尤物側，天下無傑作。", "老我懷不紓，樽前幾開落。"]'),
('f570d898-c1b2-4124-9368-c211bc378e1a','開歲半月湖村梅開無餘偶得五詩以烟溼落梅村爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','斗柄忽東指，開盡湖邊梅。',48,'全唐诗/poet.song.132000.json','["斗柄忽東指，開盡湖邊梅。", "偉觀天下無，四顧雪千堆。", "時至當斂退，勿受曉角催。", "安知桃李輩，於子無嫌猜。"]'),
('98b4d207-3e7f-46d8-8b51-f27ecb1263cd','開歲半月湖村梅開無餘偶得五詩以烟溼落梅村爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','昨日春已來，盎盎滿江村。',48,'全唐诗/poet.song.132000.json','["昨日春已來，盎盎滿江村。", "落梅亦多情，點點浮清樽。", "語離聊一醉，不恨村酒渾。", "人生共如此，已矣兩忘言。"]'),
('13cd8489-c12d-4609-812a-ae0f6447eda4','老病','陸游','宋','宋诗','song-poetry','','[]','湖上歸耕一病翁，此心非復少年同。',64,'全唐诗/poet.song.132000.json','["湖上歸耕一病翁，此心非復少年同。", "讀書初恨歲時速，聞道始知身世空。", "匠石不能材社櫟，弋人何意慕冥鴻。", "新春愈覺支離甚，又付生涯藥裹中。"]'),
('ea3d0da8-26dd-4284-88b9-c7b032529a43','三二年來夜夢每過吾廬之西一士友家觀書飲酒方夢時亦自知其爲夢也二首  其一','陸游','宋','宋诗','song-poetry','','[]','西鄰好友工談笑，每見明知是夢中。',32,'全唐诗/poet.song.132000.json','["西鄰好友工談笑，每見明知是夢中。", "樽酒不空書滿架，何時真得與君同。"]'),
('b796544b-78bc-4993-a1ef-874fecea7cf7','三二年來夜夢每過吾廬之西一士友家觀書飲酒方夢時亦自知其爲夢也二首  其二','陸游','宋','宋诗','song-poetry','','[]','清言亹亹岸綸巾，久矣吾遊無若人。',32,'全唐诗/poet.song.132000.json','["清言亹亹岸綸巾，久矣吾遊無若人。", "自怪夢中來往熟，抱琴携酒過西鄰。"]'),
('1ea6bb90-71ca-4b45-8e56-ce0b490c8a28','上元雨','陸游','宋','宋诗','song-poetry','','[]','城中酒壚千百所，不憂不售惟憂雨。',64,'全唐诗/poet.song.132000.json','["城中酒壚千百所，不憂不售惟憂雨。", "今年上元燈滿城，曲巷深坊鬧歌舞。", "天公不借一日晴，風吹燈死雨如傾。", "家家移床避屋漏，不聞人聲聞屐聲。"]'),
('16ab28a9-78e3-40fc-b2cb-2fb3a431eac7','雜興二首  其一','陸游','宋','宋诗','song-poetry','','[]','造物乘除理固然，許將窮悴博頑堅。',64,'全唐诗/poet.song.132000.json','["造物乘除理固然，許將窮悴博頑堅。", "驥衰伏櫪心千里，龜冷搘床壽百年。", "好事時供沽酒費，擁途爭笑插花顛。", "漁村宿願雖償盡，猶恨僧房欠晝眠。"]'),
('5ba91562-c833-40fa-94bf-6a8fa9ca1755','雜興二首  其二','陸游','宋','宋诗','song-poetry','','[]','散髮林間萬事輕，夢魂安穩氣和平。',64,'全唐诗/poet.song.132000.json','["散髮林間萬事輕，夢魂安穩氣和平。", "只知秋菊有佳色，那問荒雞非惡聲。", "達士招呼同嘯傲，福人分付與功名。", "一篇說盡逍遥理，始信蒙莊是達生。"]'),
('de6bab72-3f13-4c46-86ee-1d0935aef24f','初春書喜','陸游','宋','宋诗','song-poetry','','[]','我生本癡絕，萬事不繫懷。',96,'全唐诗/poet.song.132000.json','["我生本癡絕，萬事不繫懷。", "一朝蛻形去，豈問棄與薶。", "遊宦三十年，所向無一諧。", "偶然有天幸，自退非人排。", "黄紙如鴉字，君恩賜殘骸。", "剡溪回雪舫，雲門散青鞋。", "兩犢掀春泥，一鉢隨午齋。", "更當擁布被，高枕聽鳴蛙。"]'),
('e8507857-b5d8-4c48-8954-437c9922d676','幽居無一事戲作','陸游','宋','宋诗','song-poetry','','[]','長鬚僅有玉川奴，禿尾猶無漫漢驢。',64,'全唐诗/poet.song.132000.json','["長鬚僅有玉川奴，禿尾猶無漫漢驢。", "萬事已隨春枕斷，故人何啻曉星疏。", "出乘微雨鉏畬粟，歸傍荒畦擷野蔬。", "一字不看方睡美，任人搜去帳中書。"]'),
('f49bdb2e-2a33-4ea6-a7e7-43fd9100af04','贈道流','陸游','宋','宋诗','song-poetry','','[]','烟雲深處作生涯，回首人間歲月賒。',64,'全唐诗/poet.song.132000.json','["烟雲深處作生涯，回首人間歲月賒。", "留得朱顔憑綠酒，掃空白髮賴丹砂。", "七弦指下泠泠久，雙袖風中獵獵斜。", "他日相尋不知處，會從漁父問桃花。"]'),
('cf763fa0-4779-4ee1-85bf-d2492a928bdf','病中作','陸游','宋','宋诗','song-poetry','','[]','床席呻吟裏，衡茅隱約中。',48,'全唐诗/poet.song.132000.json','["床席呻吟裏，衡茅隱約中。", "空興年往嘆，未著日新功。", "世遠言猶在，身危道豈窮。", "但能無愧怍，天地本來公。"]'),
('fbe64ae2-43cd-4dc4-9bbc-dc4b704a3713','病愈偶書','陸游','宋','宋诗','song-poetry','','[]','枯蓬萬里寄飄風，晚落江頭號放翁。',64,'全唐诗/poet.song.132000.json','["枯蓬萬里寄飄風，晚落江頭號放翁。", "冉冉流年秋鏡裏，悠悠殘夢曉笳中。", "掃除藥裹病良已，棄置酒杯愁自空。", "閑處固應容老子，卧看年少起新豐。"]'),
('92bfe1a5-fc44-433a-8fb3-66fa9925b225','小圃獨酌','陸游','宋','宋诗','song-poetry','','[]','少時裘馬競豪華，豈料今爲老圃家。',64,'全唐诗/poet.song.132000.json','["少時裘馬競豪華，豈料今爲老圃家。", "數點霏微社公雨，兩叢閑淡女郎花。", "詩成枕上常難記，酒滿街頭却易賒。", "自笑邇來能用短，只將獨醉作生涯。"]'),
('8b1c6d5c-86d6-47b1-9f39-11edc649aac1','飯罷戲示鄰曲','陸游','宋','宋诗','song-poetry','','[]','今日山翁自治厨，嘉殽不似出貧居。',64,'全唐诗/poet.song.132000.json','["今日山翁自治厨，嘉殽不似出貧居。", "白鵝炙美加椒後，錦雉羹香下豉初。", "箭茁脆甘欺雪菌，蕨芽珍嫩壓春蔬。", "平生責望天公淺，捫腹便便已有餘。"]'),
('f63a4b4a-1991-4188-83ac-0528a0af2382','春日六首  其一','陸游','宋','宋诗','song-poetry','','[]','開盡梅花柳漸青，東風又滿會稽城。',32,'全唐诗/poet.song.132000.json','["開盡梅花柳漸青，東風又滿會稽城。", "放翁晨起有佳思，婭姹林鶯初試聲。"]'),
('5874d1fc-5173-4c03-abca-212986a50c5e','春日六首  其二','陸游','宋','宋诗','song-poetry','','[]','方池瀲瀲碧波平，曲徑纖纖細草生。',32,'全唐诗/poet.song.132000.json','["方池瀲瀲碧波平，曲徑纖纖細草生。", "席地幕天君但醉，苦無多日是清明。"]'),
('b2837178-ba10-4483-9651-5303c0a3a3f2','春日六首  其三','陸游','宋','宋诗','song-poetry','','[]','桃花輕薄柳花狂，蛺蝶翩翩燕子忙。',32,'全唐诗/poet.song.132000.json','["桃花輕薄柳花狂，蛺蝶翩翩燕子忙。", "惟有龜堂無一事，閉門白日不勝長。"]'),
('dd9e7aea-e916-4922-a756-97b328760d84','春日六首  其四','陸游','宋','宋诗','song-poetry','','[]','巷口東風吹酒旗，老人也惜早春時。',32,'全唐诗/poet.song.132000.json','["巷口東風吹酒旗，老人也惜早春時。", "雨來三日泥沒踝，過盡梅花渾不知。"]'),
('e1de44eb-f079-42ea-91e9-4b70c315fe96','春日六首  其五','陸游','宋','宋诗','song-poetry','','[]','雪山萬疊看不厭，雪盡山青又一奇。',32,'全唐诗/poet.song.132000.json','["雪山萬疊看不厭，雪盡山青又一奇。", "今代江南無畫手，矮箋移入放翁詩。"]'),
('baab9a40-3da3-4922-a952-f49d934aa982','春日六首  其六','陸游','宋','宋诗','song-poetry','','[]','怕見公卿懶入城，野橋孤店跨驢行。',32,'全唐诗/poet.song.132000.json','["怕見公卿懶入城，野橋孤店跨驢行。", "天公遣足看山願，白盡髭鬚却眼明。"]'),
('366130fc-8788-4023-ae02-abd2116db1b0','新晴野步','陸游','宋','宋诗','song-poetry','','[]','吹盡浮雲旋作晴，郊原高下水縱橫。',64,'全唐诗/poet.song.132000.json','["吹盡浮雲旋作晴，郊原高下水縱橫。", "烟蕪漫漫如添色，谷鳥關關已變聲。", "迨酒賤時須痛飲，得人扶處儘閑行。", "隔湖遥指蘭亭路，鄰叟追隨羨眼明。"]'),
('8e9e667f-e351-45ed-accd-f9171920ed90','湖上作二首  其一','陸游','宋','宋诗','song-poetry','','[]','鵝兒涇口曉山橫，蜻蜓港頭春水生。',32,'全唐诗/poet.song.132000.json','["鵝兒涇口曉山橫，蜻蜓港頭春水生。", "蘭亭之北是茶市，柯橋以西多櫓聲。"]'),
('b1804b70-1f79-4ebe-8841-509a2c3c6cd0','湖上作二首  其二','陸游','宋','宋诗','song-poetry','','[]','東涇西涇花極望，紅雲照波錦裹山。',32,'全唐诗/poet.song.132000.json','["東涇西涇花極望，紅雲照波錦裹山。", "路似掌平身自倦，酒如土賤篋常慳。"]'),
('b7c119f6-f121-43c8-baf3-06b526fca49c','夜行過一大姓家值其樂飲戲作','陸游','宋','宋诗','song-poetry','','[]','村豪聚飲自相歡，燈火歌呼鬧夜闌。',32,'全唐诗/poet.song.132000.json','["村豪聚飲自相歡，燈火歌呼鬧夜闌。", "醉飽要勝饑欲死，看渠也復面團團。"]'),
('a4baca85-43c3-4554-a4d8-63bd0a4071b5','枕上作二首  其一','陸游','宋','宋诗','song-poetry','','[]','水漲池新滿，山寒屋儘低。',48,'全唐诗/poet.song.132000.json','["水漲池新滿，山寒屋儘低。", "愁多憎夜雨，睡少喜晨雞。", "社肉初分胙，春蕪已再犁。", "明朝尋父老，不怕蹋街泥。"]'),
('6d899b88-4f1d-4afd-9fa9-3c64c90cee5a','枕上作二首  其二','陸游','宋','宋诗','song-poetry','','[]','山雨蕭蕭過，沙泉咽咽流。',48,'全唐诗/poet.song.132000.json','["山雨蕭蕭過，沙泉咽咽流。", "夢中無遠道，醉裏失孤愁。", "貧賣相如騎，寒思季子裘。", "兒童報新霽，裹飯出閑遊。"]'),
('37d36cad-5c00-4c6e-9cfb-fa5dc3ce0f0e','悽悽行','陸游','宋','宋诗','song-poetry','','[]','悽悽重悽悽，惻惻復惻惻。',72,'全唐诗/poet.song.132000.json','["悽悽重悽悽，惻惻復惻惻。", "我愧思曠傍，人誰子思側。", "興邦在人材，巖穴當物色。", "如何清廟器，老死山南北。", "小儒雖微陋，一飯亦憂國。", "豈無一得愚，欲獻懼非職。"]'),
('5a5d5bde-6b97-4e8d-96a3-5a2fa80f1083','春薺','陸游','宋','宋诗','song-poetry','','[]','食案何蕭然，春薺花若雪。',72,'全唐诗/poet.song.132000.json','["食案何蕭然，春薺花若雪。", "從今日老硬，何以供采擷。", "山翁垂八十，忍貧心似鐵。", "那須萬錢筯，養此三寸舌。", "軟炊香秔飯，幸免煩祝噎。", "一瓢亦已泰，陋巷時小啜。"]'),
('97164963-5d7b-45f0-8fd1-470de102c4b8','答客','陸游','宋','宋诗','song-poetry','','[]','人生各有營，爲吏最無策。',96,'全唐诗/poet.song.132000.json','["人生各有營，爲吏最無策。", "其間小黠者，但肯乘下澤。", "絕筆光範書，掃迹翹才客。", "早收畏塗身，未老歸阡陌。", "嗟予昧擇術，誤計真累百。", "衰病始知悔，泯默每自責。", "孤舟寄渺莽，尚恨江湖迮。", "客來勿多談，窮命不禁嚇。"]'),
('e1faa5d2-5ea1-4b7a-be7f-965db10ec0a1','閑中自詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','小艇上時皆綠水，短筇到處即青山。',32,'全唐诗/poet.song.132000.json','["小艇上時皆綠水，短筇到處即青山。", "二十四考中書令，不換先生半日閑。"]'),
('7b2ce69c-8c6a-4743-a62d-fa29e17f17f7','閑中自詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','聲名本自不關身，富貴元知與禍鄰。',32,'全唐诗/poet.song.132000.json','["聲名本自不關身，富貴元知與禍鄰。", "但恨平生閑不足，再來真作卧雲人。"]'),
('a9077be1-9e61-4ac9-ad93-446bb30a3cbc','甲申雨','陸游','宋','宋诗','song-poetry','','[]','老農十口傳爲古，春遇甲申常畏雨。',96,'全唐诗/poet.song.132000.json','["老農十口傳爲古，春遇甲申常畏雨。", "風來東北雲行西，雨勢已成那得禦。", "山陰泆湖二百歲，坐使膏腴成瘠鹵。", "陂塘遺迹今悉存，嘆息當官誰可語。", "甲申畏雨古亦然，湖之未廢常豐年。", "小人那知古來事，不怨豪家惟怨天。"]'),
('9e068744-c626-425b-9a67-de048f1b3761','今歲游花涇差晚戲作','陸游','宋','宋诗','song-poetry','','[]','滿地殘紅點綠苔，花涇弭棹小裴回。',64,'全唐诗/poet.song.132000.json','["滿地殘紅點綠苔，花涇弭棹小裴回。", "春風又作匆匆別，老病無端衮衮來。", "亦悟百窮緣骯髒，終羞萬事學低摧。", "吾文自欲忘憂耳，那博人間水一杯。"]'),
('e6a2b548-64ff-407f-8930-d1851b1b8311','枕上口占三首  其一','陸游','宋','宋诗','song-poetry','','[]','五十年前詩酒身，山陰風月尚如新。',32,'全唐诗/poet.song.132000.json','["五十年前詩酒身，山陰風月尚如新。", "閑愁已是無闌障，一枕春寒更惱人。"]'),
('a4a51cf2-1351-452b-b1b7-a5a111573b2c','枕上口占三首  其二','陸游','宋','宋诗','song-poetry','','[]','蹋雨敲門覓季夷，襞箋同和仲高詩。',32,'全唐诗/poet.song.132000.json','["蹋雨敲門覓季夷，襞箋同和仲高詩。", "回思五十年前事，恰似今宵夢裏時。"]'),
('ac1bdfe5-c349-4637-b3d0-bab9f910cb41','枕上口占三首  其三','陸游','宋','宋诗','song-poetry','','[]','五十年間萬事空，懶將白髮對青銅。',32,'全唐诗/poet.song.132000.json','["五十年間萬事空，懶將白髮對青銅。", "故人只有桃花在，惆悵無情一夜風。"]'),
('cbcb28dd-e9b5-4b26-a62a-bd9186a17294','贈謝正之秀才','陸游','宋','宋诗','song-poetry','','[]','君家麻源第三谷，我在鏡湖分一曲。',96,'全唐诗/poet.song.132000.json','["君家麻源第三谷，我在鏡湖分一曲。", "平生夢亦不相接，忽然懷中瀉珠玉。", "誠齋老子主詩盟，片言許可天下服。", "長歌爲君定聲價，賞音但須一夔足。", "蹋泥過我君豈誤，拱璧何至求凡目。", "只愁明日遽來索，北窗連夜挑燈讀。"]'),
('ef92b9ba-2b9a-4778-b627-e1a3bb7fcb4b','連日往來湖山間頗樂即席有作','陸游','宋','宋诗','song-poetry','','[]','晚春光景亦佳哉，野老蒼顔一笑開。',64,'全唐诗/poet.song.132000.json','["晚春光景亦佳哉，野老蒼顔一笑開。", "莫問此生猶幾屐，但知相遇且銜杯。", "偶携兒女祈蠶去，又逐鄉鄰賽麥回。", "不信年華如轉轂，城頭君聽角聲哀。"]'),
('7ec0dd37-2444-446b-ad6c-297412f7ab59','贈貓','陸游','宋','宋诗','song-poetry','','[]','鹽裹聘狸奴，常看戲座隅。',48,'全唐诗/poet.song.132000.json','["鹽裹聘狸奴，常看戲座隅。", "時時醉薄荷，夜夜占氍毹。", "鼠穴功方列，魚餐賞豈無。", "仍當立名字，喚作小於菟。"]'),
('6c892fd7-c8c4-4e80-9550-6ebd68fe4c9f','嘆老','陸游','宋','宋诗','song-poetry','','[]','小筑依林藪，殘年迫耄期。',48,'全唐诗/poet.song.132000.json','["小筑依林藪，殘年迫耄期。", "衣寬方覺瘦，步蹇始悲衰。", "食飲常多忌，方書動自隨。", "園花幾分在，睡起問吾兒。"]'),
('b280f317-49ed-4d76-afef-3b5c4655ef23','殘春','陸游','宋','宋诗','song-poetry','','[]','章甫從諸老，今爲兩世人。',48,'全唐诗/poet.song.132000.json','["章甫從諸老，今爲兩世人。", "惟書尚開眼，非酒孰關身。", "遠水涵清鏡，晴雲蹙細鱗。", "籬邊花未盡，作意醉殘春。"]'),
('e7c0f93f-2ef6-4e61-96e7-794e6de10c4d','東村','陸游','宋','宋诗','song-poetry','','[]','雨霽山爭出，泥乾路漸通。',48,'全唐诗/poet.song.132000.json','["雨霽山爭出，泥乾路漸通。", "稍從牛屋後，却過鸛巢東。", "决决沙溝水，翻翻麥野風。", "欲歸還小立，爲愛夕陽紅。"]'),
('b5ddea0c-90d0-4052-b815-e3a100144465','晚步舍北歸','陸游','宋','宋诗','song-poetry','','[]','昨日海棠開，今朝燕子來。',48,'全唐诗/poet.song.132000.json','["昨日海棠開，今朝燕子來。", "偶行沙際去，却傍柳陰回。", "酒是治愁藥，書爲引睡媒。", "吾生不乏此，外物信悠哉。"]'),
('80e54cca-bea2-4aee-b23d-d70396f6b57c','記夢','陸游','宋','宋诗','song-poetry','','[]','夜夢遊名山，翠壁開巖扉。',48,'全唐诗/poet.song.132000.json','["夜夢遊名山，翠壁開巖扉。", "主人喜迎客，劇談皆造微。", "下臨萬里空，渺渺一鶴飛。", "安得棄家去，丹竈常相依。"]'),
('18fc21b7-611d-4c50-bc74-d4f11975cf7d','寄題揚州九曲池','陸游','宋','宋诗','song-poetry','','[]','清汴長淮莽蒼中，揚州畫戟擁元戎。',64,'全唐诗/poet.song.132000.json','["清汴長淮莽蒼中，揚州畫戟擁元戎。", "南連近甸觀秋稼，北撫中原掃夕烽。", "茶發蜀岡雷殷殷，水通隋苑月溶溶。", "懸知帳下多豪傑，一醉何因及老農。"]'),
('0e811b61-f169-4d01-b8dc-cfba3e721a8b','投老','陸游','宋','宋诗','song-poetry','','[]','投老百無成，山林送此生。',48,'全唐诗/poet.song.132000.json','["投老百無成，山林送此生。", "薄才元易盡，古道竟難行。", "陋巷牛羊迹，衡門鳥雀聲。", "新年幸差健，作意事春耕。"]'),
('72e7b184-5847-47e1-850c-6ff0e97819af','茅亭','陸游','宋','宋诗','song-poetry','','[]','終日坐茅亭，蕭然倚素屏。',48,'全唐诗/poet.song.132000.json','["終日坐茅亭，蕭然倚素屏。", "兒圓點茶夢，客授養魚經。", "馬以鳴當斥，龜緣久不靈。", "詩成作吳詠，及此醉初醒。"]'),
('054248e0-fe0d-46fe-bde9-1d69d095819f','貧甚賣常用酒杯作詩自戲','陸游','宋','宋诗','song-poetry','','[]','桃李成塵渾不數，海棠也作胭脂雨。',96,'全唐诗/poet.song.132000.json','["桃李成塵渾不數，海棠也作胭脂雨。", "清明未到春已空，枝上流鶯替人語。", "逢春日日合醉歸，莫笑典衣窮杜甫。", "生時不肯澆舌本，死後空持酹墳土。", "門前三百里湖光，天與先生作醉鄉。", "銀杯羽化不須嘆，多錢使人生窟郎。"]'),
('50bf2be8-b5fe-4116-bb32-c287c93ef975','春晚泛湖歸偶賦','陸游','宋','宋诗','song-poetry','','[]','十日雨晴湖水深，暖催新綠上橫林。',64,'全唐诗/poet.song.132000.json','["十日雨晴湖水深，暖催新綠上橫林。", "分泥海燕穿花徑，带犢吳牛傍柳陰。", "夏近漸低遊舫價，日斜殊費寺樓吟。", "歸來支枕還無事，一縷微烟看水沉。"]'),
('47b25700-d8a9-48c7-ab25-c34ee92cc29d','東園小飲四首  其一','陸游','宋','宋诗','song-poetry','','[]','少年萬里走塵埃，歸卧柴荆晝不開。',64,'全唐诗/poet.song.132000.json','["少年萬里走塵埃，歸卧柴荆晝不開。", "十事真成九敗意，一春知復幾銜杯。", "波清憑檻觀魚樂，風緊鈎簾待燕回。", "催喚比鄰同晚酌，旋燒筀筍摘青梅。"]'),
('29d5bac4-9502-49b3-bbdc-bc59cc432b76','東園小飲四首  其二','陸游','宋','宋诗','song-poetry','','[]','入東又見幾春風，茆屋蘆藩寂寞中。',64,'全唐诗/poet.song.132000.json','["入東又見幾春風，茆屋蘆藩寂寞中。", "道業雖如詩不進，世緣已與夢俱空。", "高枝濯濯辛夷紫，密葉深深躑躅紅。", "村巷斷無軒蓋到，一樽猶得伴鄰翁。"]'),
('2c556385-d0cf-49b2-8d28-dbae894c12af','東園小飲四首  其三','陸游','宋','宋诗','song-poetry','','[]','三月園林日漸長，閑從鄰曲答年光。',64,'全唐诗/poet.song.132000.json','["三月園林日漸長，閑從鄰曲答年光。", "酴醿獨殿群芳後，醽醁能令萬事忘。", "下豉蓴羹誇舊俗，供鹽梅子喜初嘗。", "烏靴席帽知何樂，自古京塵瞇眼黄。"]'),
('badfa9ea-e50d-461a-8e81-ebb7b36c7c5f','東園小飲四首  其四','陸游','宋','宋诗','song-poetry','','[]','乞得殘骸老故山，草亭終日對孱顔。',64,'全唐诗/poet.song.132000.json','["乞得殘骸老故山，草亭終日對孱顔。", "孤雲百尺起江際，幽鳥數聲鳴竹間。", "眾死一身今獨健，人忙萬物本常閑。", "此心欲語知誰聽，賴有漁樵日往還。"]'),
('318a467c-3af3-49dc-bb01-2ef042e17e40','病退頗思遠遊信筆有作','陸游','宋','宋诗','song-poetry','','[]','平日身如不繫舟，曾從楚尾客秦頭。',64,'全唐诗/poet.song.132000.json','["平日身如不繫舟，曾從楚尾客秦頭。", "風生江浦千帆曉，月落山城一笛秋。", "萬事只能催白髮，百年終是卧荒丘。", "扶衰强項君休笑，尚憶人間汗漫遊。"]'),
('15e2f3ab-1323-4d0d-bd82-967d630fa2a2','春晚閑步門外','陸游','宋','宋诗','song-poetry','','[]','病退扶行力尚微，悠然隨意出荆扉。',64,'全唐诗/poet.song.132000.json','["病退扶行力尚微，悠然隨意出荆扉。", "蜂貪釀蜜爭花去，燕喜分泥傍水飛。", "午渴坼瓶嘗煮酒，晴暄開笥換單衣。", "躊躇已久歸猶懶，更向溪頭坐釣磯。"]'),
('6e4587a7-c660-4cb3-aea8-9bd0e79f72fb','嘲布穀','陸游','宋','宋诗','song-poetry','','[]','時令過清明，朝朝布穀鳴。',48,'全唐诗/poet.song.132000.json','["時令過清明，朝朝布穀鳴。", "但令春促駕，那爲國催耕。", "紅紫花枝盡，青黄麥穗成。", "從今可無語，傾耳舜弦聲。"]'),
('05d7b135-635c-4b7e-92a3-afd57bc88925','題齋壁','陸游','宋','宋诗','song-poetry','','[]','出郭無十里，結廬纔數間。',48,'全唐诗/poet.song.132000.json','["出郭無十里，結廬纔數間。", "每將窮博健，不遣樂妨閑。", "賣藥雲邊市，尋僧雨外山。", "何妨摇檝去，却作跨驢還。"]'),
('3df08445-f388-408f-a18e-90aa1ff02926','龜堂晚興','陸游','宋','宋诗','song-poetry','','[]','九日春陰一日晴，回塘閑院愜幽情。',64,'全唐诗/poet.song.132000.json','["九日春陰一日晴，回塘閑院愜幽情。", "小魚出水圓紋見，輕燕穿簾折勢成。", "今日掩關真佚老，向來涉世亦遺名。", "巡簷更有欣然處，新筍初抽四五莖。"]'),
('d2420037-ffde-4543-8793-6b8359ee8c82','長干行','陸游','宋','宋诗','song-poetry','','[]','裙腰綠如草，衫色石榴花。',72,'全唐诗/poet.song.132000.json','["裙腰綠如草，衫色石榴花。", "十二學彈箏，十三學琵琶。", "寧嫁與商人，夫婦各天涯。", "朝朝問水神，夜夜夢三巴。", "聘金雖如山，不願入侯家。", "鄣袖庭花下，東風吹鬢斜。"]'),
('42cda6c0-cb9f-4d47-8352-1af60824c3c9','養生','陸游','宋','宋诗','song-poetry','','[]','受廛故里老爲氓，三十餘年學養生。',64,'全唐诗/poet.song.132000.json','["受廛故里老爲氓，三十餘年學養生。", "倩盼作妖狐未慘，肥甘藏毒酖猶輕。", "忠言何啻千金藥，赤口能燒萬里城。", "陋巷藜羹心自樂，傍觀虛說傲公卿。"]'),
('8071edc5-c29e-49f4-adc3-b3b837eb28ed','園中觀草木有感','陸游','宋','宋诗','song-poetry','','[]','木筆枝已空，玉簪殊未花。',96,'全唐诗/poet.song.132000.json','["木筆枝已空，玉簪殊未花。", "赬桐時更晚，春盡始萌芽。", "老人多感慨，俯仰悲歲華。", "兩曜如奔輪，疾去不可遮。", "城頭插雙旗，疊鼓催清笳。", "兀然一室間，不復過鄰家。", "午睡或至暮，亂髮垂髿髿。", "所嗟瘦僧死，莫致茶山茶。"]'),
('d43f6b96-4038-46d7-b2eb-b44480ab6794','恩赐龜紫二首  其一','陸游','宋','宋诗','song-poetry','','[]','憶昔青衫上赤墀，頷間未有一莖絲。',32,'全唐诗/poet.song.132000.json','["憶昔青衫上赤墀，頷間未有一莖絲。", "豈知晚拜金龜賜，却是霜髯雪鬢時。"]'),
('6c4d8deb-c0f4-4ecf-90d7-e6fba55e1421','恩赐龜紫二首  其二','陸游','宋','宋诗','song-poetry','','[]','已挂朝衣神武門，暫紆紫綬拜君恩。',32,'全唐诗/poet.song.132000.json','["已挂朝衣神武門，暫紆紫綬拜君恩。", "兒孫賀罷還無事，雨笠烟蓑自灌園。"]'),
('3375f158-47c1-48d1-89e1-a08caf491ab6','自警','陸游','宋','宋诗','song-poetry','','[]','少年不自量，妄意慕管葛。',72,'全唐诗/poet.song.132000.json','["少年不自量，妄意慕管葛。", "晚節雖知難，猶覬終一豁。", "悲哉老病馬，解縱誰復秣。", "既辭箠轡勞，始愛原野闊。", "飲澗嚙霜菅，亦可數年活。", "勿復思長途，嘶鳴望天末。"]'),
('2cbcf0b3-4df3-4df7-a27b-e656f007e2ca','獨夜','陸游','宋','宋诗','song-poetry','','[]','一生食太倉，蠹耗均雀鼠。',96,'全唐诗/poet.song.132000.json','["一生食太倉，蠹耗均雀鼠。", "雖云久置散，饑飽尚撐拄。", "兩年失微祿，始覺困羈旅。", "傾身營薪米，得食已過午。", "人觀不堪憂，意氣終自許。", "藜羹若大庖，草廬如萬礎。", "平生師顔原，本自藐晉楚。", "悠然卧北窗，殘燈翳還吐。"]'),
('414706c4-95dd-45cf-b0f3-d708598d252c','雨夕枕上作','陸游','宋','宋诗','song-poetry','','[]','鬢毛日夜雪霜稠，冉冉年光逝肯留。',64,'全唐诗/poet.song.132000.json','["鬢毛日夜雪霜稠，冉冉年光逝肯留。", "酒力但資愁作祟，雨聲偏與睡爲仇。", "銘旌官職眼前事，史冊姓名身後憂。", "畢竟此生何處是，江湖萬里有孤舟。"]'),
('60b28ccd-9a39-4964-bac9-8773e6f333cb','喜晴','陸游','宋','宋诗','song-poetry','','[]','澤國風雨多，春盡尚裘褐。',72,'全唐诗/poet.song.132000.json','["澤國風雨多，春盡尚裘褐。", "閉門不能出，飽受鳩婦聒。", "今朝雲忽歸，溝水清活活。", "偶爲東園行，魚鳥間何闊。", "婦女蠶事終，桑柘光如潑。", "布穀汝勿憂，吾袴真可脫。"]'),
('0ba7f703-0d9c-4026-a11f-d96ecb6b4c62','觀運糧圖','陸游','宋','宋诗','song-poetry','','[]','王師北伐如宣王，風馳電擊復土疆。',96,'全唐诗/poet.song.132000.json','["王師北伐如宣王，風馳電擊復土疆。", "中軍歌舞入洛陽，前軍已渡河流黄。", "馬聲蕭蕭陣堂堂，直跨井陘登太行。", "壺漿簞食滿道傍，芻粟豈復煩車箱。", "不須絕漠追敗亡，亦勿分兵取河湟。", "但令中夏歌時康，千年萬年無饋糧。"]'),
('81e28112-b418-462c-97b3-74ee3318385b','宇文衮臣吏部予在蜀日與之遊至厚契闊死生二十年矣庚申三月忽夢相從如平生愴然有賦','陸游','宋','宋诗','song-poetry','','[]','英姿爽氣宇邛州，雖古人中豈易求。',32,'全唐诗/poet.song.132000.json','["英姿爽氣宇邛州，雖古人中豈易求。", "六月長途將暍死，一天風雹起龍湫。"]'),
('c4ab3399-6782-4733-9f9c-8ab14d839370','阿姥','陸游','宋','宋诗','song-poetry','','[]','城南倒社下湖忙，阿姥龍鍾七十强。',32,'全唐诗/poet.song.132000.json','["城南倒社下湖忙，阿姥龍鍾七十强。", "猶有塵埃嫁時鏡，東塗西抹不成妝。"]'),
('76ca870f-c128-40d6-82c8-c72b1359dd28','初夏','陸游','宋','宋诗','song-poetry','','[]','雨足移秧後，風和剝繭初。',48,'全唐诗/poet.song.132000.json','["雨足移秧後，風和剝繭初。", "昏昏時就枕，貿貿却尋書。", "晚步身須杖，晨興髮廢梳。", "滿城車馬客，誰復問何如。"]'),
('c36af7c5-5652-476d-a874-ff2850340898','讀書','陸游','宋','宋诗','song-poetry','','[]','稽古衰猶力，翻書夜達晨。',48,'全唐诗/poet.song.132000.json','["稽古衰猶力，翻書夜達晨。", "思人頻掩卷，感事忽霑巾。", "世閱幾春夢，身今一老民。", "忍窮端已慣，蔬食又經旬。"]'),
('8a2e6af0-474b-4c5a-87d4-d2c2c9b2f0cd','喜晴','陸游','宋','宋诗','song-poetry','','[]','江湖春暮多風雨，點滴空階實厭聽。',32,'全唐诗/poet.song.132000.json','["江湖春暮多風雨，點滴空階實厭聽。", "剩喜今朝有奇事，一窗晴日寫黄庭。"]'),
('45961f2e-9d4f-4ef2-be60-5028baecee3c','初夏北窗二首  其一','陸游','宋','宋诗','song-poetry','','[]','作墨無聲紫玉池，年光又入放翁詩。',64,'全唐诗/poet.song.132000.json','["作墨無聲紫玉池，年光又入放翁詩。", "風和柳岸吹綿後，雨足瓜畦引蔓時。", "病酒相如無奈渴，清言叔寶不勝羸。", "此生豈復功名事，付與城頭畫角悲。"]'),
('03f3f675-aa58-4468-b060-0455960b98b9','初夏北窗二首  其二','陸游','宋','宋诗','song-poetry','','[]','水際柴荆晝不開，卧聽微雨雜輕雷。',64,'全唐诗/poet.song.132000.json','["水際柴荆晝不開，卧聽微雨雜輕雷。", "春蠶滿箔眠初起，社燕爭巢去復來。", "海檜屈蟠依怪石，山榴零落點蒼苔。", "一樽及此風光美，車下長坡底用推。"]'),
('aceebaea-22c6-4da3-9ca6-77f4f1bf775e','書適','陸游','宋','宋诗','song-poetry','','[]','老人去健羨，飯足便有餘。',96,'全唐诗/poet.song.132000.json','["老人去健羨，飯足便有餘。", "此外一壺酒，薦以園中蔬。", "手種數畦花，時開一編書。", "近者苦足蹇，復營一柴車。", "時時訪溪父，亦或遊僧廬。", "上下山澤間，視身等禽魚。", "既歸則浩歌，幽抱亦少攄。", "一笑謂兒子，不須起犁鋤。"]'),
('a20ebb0d-2211-4d30-8eb5-f26a5732edc3','幽居初夏四首  其一','陸游','宋','宋诗','song-poetry','','[]','路繚長堤北，家居小市西。',48,'全唐诗/poet.song.132000.json','["路繚長堤北，家居小市西。", "陂塘晨飲犢，門巷午鳴雞。", "婦喜蠶三幼，兒誇雨一犁。", "衰翁亦放浪，未怕屐霑泥。"]'),
('95b77481-dbd3-43f6-9f22-4befe3138512','幽居初夏四首  其二','陸游','宋','宋诗','song-poetry','','[]','梅塢青黄子，草陂紅紫花。',48,'全唐诗/poet.song.132000.json','["梅塢青黄子，草陂紅紫花。", "雙鵝朝戲浦，群鴨暮還家。", "赤脚挑殘筍，蒼頭摘晚茶。", "出門逢野老，滿意說桑麻。"]'),
('a469f657-0e6a-4169-aaac-e573fece75c4','幽居初夏四首  其三','陸游','宋','宋诗','song-poetry','','[]','詰曲穿桑徑，謳啞響竹門。',48,'全唐诗/poet.song.132000.json','["詰曲穿桑徑，謳啞響竹門。", "疏泉灌藜莧，倚杖牧雞豚。", "江步橫新舸，茅簷弄幼孫。", "太平端有象，誰與畫吾村。"]'),
('73ea12da-4243-47a1-a04e-d5872e5df50e','幽居初夏四首  其四','陸游','宋','宋诗','song-poetry','','[]','大耋光陰短，南訛日月長。',48,'全唐诗/poet.song.132000.json','["大耋光陰短，南訛日月長。", "松枯宜倒壑，龜老慣搘床。", "寂寂三升稷，悠悠百本桑。", "饑寒猶骯髒，何術砭吾肓。"]'),
('11555980-9be2-490f-ad56-a4037c62c389','獨醉','陸游','宋','宋诗','song-poetry','','[]','老伴死欲盡，少年誰肯親。',48,'全唐诗/poet.song.132000.json','["老伴死欲盡，少年誰肯親。", "自憐真長物，何啻是陳人。", "江市魚初上，村場酒亦醇。", "頹然北窗下，不覺墮紗巾。"]'),
('e49652e5-0530-43ab-b524-3973cc97d42f','獨立','陸游','宋','宋诗','song-poetry','','[]','午醉初醒後，回廊獨立時。',48,'全唐诗/poet.song.132000.json','["午醉初醒後，回廊獨立時。", "斜陽明雨葉，乳鵲裊風枝。", "違俗雖堪笑，師心頗自奇。", "傍人疑徙倚，向道是尋詩。"]'),
('6d5bae3f-6afc-4771-9274-54b8bb06ae03','高卧','陸游','宋','宋诗','song-poetry','','[]','省戶歸來不計年，悠然高卧鏡湖邊。',64,'全唐诗/poet.song.132000.json','["省戶歸來不計年，悠然高卧鏡湖邊。", "鈎簾每對千峰雨，接竹新分一脈泉。", "學問誠身元有道，阨窮知我豈非天。", "虛名自古能爲累，正恐人看直一錢。"]'),
('5b1c15bf-1b24-4628-b534-8b4d0ab1bf85','趙彥膚修撰挽辭','陸游','宋','宋诗','song-poetry','','[]','朝路英聲早，宗盟宿望尊。',48,'全唐诗/poet.song.132000.json','["朝路英聲早，宗盟宿望尊。", "宴談推醞藉，大筆擅雄渾。", "許國心猶壯，安邊策具存。", "凄凉故時客，痛哭望秋原。"]'),
('c52ee649-f69d-422f-b600-4f595f3d0c4a','讀香奩集詩戲效其體','陸游','宋','宋诗','song-poetry','','[]','金鋪一閉幾春風，咫尺心知萬里同。',64,'全唐诗/poet.song.132000.json','["金鋪一閉幾春風，咫尺心知萬里同。", "麝枕何曾禳夢惡，玉壺空解貯啼紅。", "畫愁延壽丹青誤，賦欠相如筆墨工。", "一事目前差自慰，月明還似未央中。"]'),
('20393859-43e8-425c-aa7c-63d8fcbb54c7','野步至村舍暮歸','陸游','宋','宋诗','song-poetry','','[]','草徑盤紆入廢園，漲餘野水有殘痕。',64,'全唐诗/poet.song.132000.json','["草徑盤紆入廢園，漲餘野水有殘痕。", "新蒲漫漫藏孤艇，茂樹陰陰失近村。", "拄杖敲門求小憩，老盆盛酒瀉微渾。", "興闌却覓橋邊路，數點歸鴉已带昏。"]'),
('180e29fe-ea0d-470a-a397-a30f491605c4','述悲','陸游','宋','宋诗','song-poetry','','[]','屏居不出門，終歲袖手坐。',72,'全唐诗/poet.song.132000.json','["屏居不出門，終歲袖手坐。", "但怪意氣衰，那覺日月過。", "故人爲冢丘，老伴餘幾箇。", "天高鬼神惡，回夭夷齊餓。", "遺魂一零落，豈復聞楚些。", "且當醉濁醪，吾夢行亦破。"]'),
('282018b3-f6a4-40c5-879e-9bb66d320eab','江東韓漕晞道寄楊廷秀所贈詩來求同賦作此寄之','陸游','宋','宋诗','song-poetry','','[]','三朝巍巍韓侍中，爛然彝鼎書元功。',160,'全唐诗/poet.song.132000.json','["三朝巍巍韓侍中，爛然彝鼎書元功。", "西戎北狄問安否，九州萬里涵春風。", "子孫繼踵皆將相，我猶及拜西樞公。", "顧憐通家略貴賤，勞問教誨均兒童。", "西樞有孫又奇偉，凜然太華摩蒼穹。", "小試玉節江西東，文書如海到手空。", "政成蒲鞭亦不用，地上錢流倉粟紅。", "君持此手上廊廟，折衝禦侮知從容。", "桑乾不勞尺箠下，榆關正可丸泥封。", "却歸故里訪遺老，應記山陰九十翁。"]'),
('a8145842-8e33-4629-8e19-b267193bff8c','雨夜','陸游','宋','宋诗','song-poetry','','[]','麥熟家家喜墮涎，龜堂依舊突無烟。',32,'全唐诗/poet.song.132000.json','["麥熟家家喜墮涎，龜堂依舊突無烟。", "雨中更覺凄凉甚，一點殘燈守蠹編。"]'),
('092c8168-4ef7-482f-9fa3-5445d4d86861','小橋','陸游','宋','宋诗','song-poetry','','[]','漠漠輕陰隱隱雷，石榴半落點莓苔。',32,'全唐诗/poet.song.132000.json','["漠漠輕陰隱隱雷，石榴半落點莓苔。", "小橋西北闌干角，獨岸綸巾待雨來。"]'),
('cfc49190-9814-4150-a07b-77605a89c8f8','自笑','陸游','宋','宋诗','song-poetry','','[]','三間茅屋寄滄浪，鳥出樊籠馬脫韁。',64,'全唐诗/poet.song.132000.json','["三間茅屋寄滄浪，鳥出樊籠馬脫韁。", "灧灧陂塘秧水滿，陰陰門巷麥風凉。", "蔬盤旋采溪毛滑，篷艇新編露箬香。", "捐盡浮名方自喜，一生枉是伴人忙。"]'),
('b40ba78a-3267-4b0e-9857-9dd28f02f17c','入梅','陸游','宋','宋诗','song-poetry','','[]','微雨輕雲已入梅，石榴萱草一時開。',64,'全唐诗/poet.song.132000.json','["微雨輕雲已入梅，石榴萱草一時開。", "碑償宿諾淮僧去，卷錄新詩蜀使回。", "墨試小螺看斗硯，茶分細乳玩毫杯。", "客來莫誚兒嬉事，九陌紅塵更可哀。"]'),
('fb7285ba-4fac-4b73-96d5-7ea38451b04b','雨夜','陸游','宋','宋诗','song-poetry','','[]','小雨收仍落，孤燈翳復明。',48,'全唐诗/poet.song.132000.json','["小雨收仍落，孤燈翳復明。", "衰殘書易忘，憂患夢多驚。", "熠熠螢矜暗，翻翻雀轉更。", "閉門行老死，亦足慰平生。"]'),
('751c4fe6-9b72-434a-9724-30fecb6c5aad','燕','陸游','宋','宋诗','song-poetry','','[]','初見梁間牖戶新，銜泥已復哺雛頻。',32,'全唐诗/poet.song.132000.json','["初見梁間牖戶新，銜泥已復哺雛頻。", "只愁去遠歸來晚，不怕飛低打著人。"]'),
('3f58c762-0471-4c5f-8fce-1cb1cc9ad2f1','午枕','陸游','宋','宋诗','song-poetry','','[]','茅簷一杯淡藜粥，有底工夫希鼎餗。',64,'全唐诗/poet.song.132000.json','["茅簷一杯淡藜粥，有底工夫希鼎餗。", "書中至味人不知，雋永無窮勝粱肉。", "老夫享此七十年，每愧天公賦予偏。", "清泉洗鬴煎山茗，滿榻松風清晝眠。"]'),
('360c929c-7bef-490a-b8be-d561bae0d0cf','項里觀楊梅四首  其一','陸游','宋','宋诗','song-poetry','','[]','山前五月楊梅市，溪上千年項羽祠。',32,'全唐诗/poet.song.132000.json','["山前五月楊梅市，溪上千年項羽祠。", "小繖輕輿不辭遠，年年來及貢梅時。"]'),
('d26810d3-ed77-4e5f-9337-402d99eb467a','項里觀楊梅四首  其二','陸游','宋','宋诗','song-poetry','','[]','隔歲租園不計錢，楊梅海裏過年年。',32,'全唐诗/poet.song.132000.json','["隔歲租園不計錢，楊梅海裏過年年。", "癡人只競閑名利，那信三山是地仙。"]'),
('3827ad9a-d3ad-4ffd-855b-9e887456dae9','項里觀楊梅四首  其三','陸游','宋','宋诗','song-poetry','','[]','溪流曲曲樹陰陰，人語烟中覺塢深。',32,'全唐诗/poet.song.132000.json','["溪流曲曲樹陰陰，人語烟中覺塢深。", "把定山僧同一笑，明年强健更相尋。"]'),
('67b6a53c-bc11-4716-8a99-f4acc5b5ef8a','項里觀楊梅四首  其四','陸游','宋','宋诗','song-poetry','','[]','山中戶戶作梅忙，火齊驪珠入帝鄉。',32,'全唐诗/poet.song.132000.json','["山中戶戶作梅忙，火齊驪珠入帝鄉。", "細織筠籠相映發，華清虛說荔枝筐。"]'),
('16bbc9bd-b62f-43b5-8bd6-5501c28cef9d','夜歸','陸游','宋','宋诗','song-poetry','','[]','城角傳三弄，桑村喜獨歸。',48,'全唐诗/poet.song.132000.json','["城角傳三弄，桑村喜獨歸。", "雨多螢滿野，徑狹露沾衣。", "食儉鹽醯薄，年衰氣力微。", "青燈對兒女，撫事一歔欷。"]'),
('91ed467f-5774-4a83-9e16-7b00e1350a52','五月十一日睡起','陸游','宋','宋诗','song-poetry','','[]','病眼慵於世事開，虛堂高卧謝氛埃。',64,'全唐诗/poet.song.132000.json','["病眼慵於世事開，虛堂高卧謝氛埃。", "簾櫳無影覺雲起，草樹有聲知雨來。", "茶碗嫩湯初得乳，香篝微火未成灰。", "翛然自適君知否，一枕清風又過梅。"]'),
('2425015a-7923-4c6d-b1ff-b336e5ff829d','示客','陸游','宋','宋诗','song-poetry','','[]','世間可笑走踆踆，誤認虛空作汝身。',64,'全唐诗/poet.song.132000.json','["世間可笑走踆踆，誤認虛空作汝身。", "已覓餘名潤枯骨，更謀厚積遺何人。", "風旛畢竟非心境，瓦礫何妨是道真。", "新藕出泥瓜上市，爲君一醉墮紗巾。"]'),
('f995b4f0-9ac0-45ae-8101-213c9d8f9a9e','雨中作','陸游','宋','宋诗','song-poetry','','[]','雨聲一滴不肯住，客夢欲成還自驚。',64,'全唐诗/poet.song.132000.json','["雨聲一滴不肯住，客夢欲成還自驚。", "白水陂邊破茅屋，亂書堆裏老儒生。", "出行豈復有流輩，未死尚能躬釣耕。", "十日無魚亦何嘆，新菰幸可配吳秔。"]'),
('440f1d7e-17f7-4cbd-a911-ccf9b89b8805','舟中遣興','陸游','宋','宋诗','song-poetry','','[]','湖海渺雲濤，浮家得養高。',48,'全唐诗/poet.song.132000.json','["湖海渺雲濤，浮家得養高。", "方床展蘄簟，短褐束郿絛。", "酒裏亦何好，人間聊可逃。", "酣歌柁樓底，萬事一秋豪。"]'),
('bab476a7-845f-48a9-9444-f4448972d005','自嘲','陸游','宋','宋诗','song-poetry','','["\u52b1\u5fd7"]','少讀詩書陋漢唐，暮年身世寄農桑。',64,'全唐诗/poet.song.132000.json','["少讀詩書陋漢唐，暮年身世寄農桑。", "騎驢兩脚欲到地，愛酒一樽常在傍。", "老去形容雖變改，醉來意氣尚軒昂。", "太行王屋何由動，堪笑愚公不自量。"]'),
('13a1d8ce-abe3-49ff-a357-40a191a07ecb','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','成童入鄉校，諸老席函丈。',72,'全唐诗/poet.song.132000.json','["成童入鄉校，諸老席函丈。", "堂堂韓有功，英概今可想。", "從父有彥遠，早以直自養。", "始終臨川學，力守非有黨。", "紛紛名佗師，有泚在其顙。", "二公生氣存，千載可畏仰。"]'),
('ea3e476a-76d7-4f30-be05-20d3036a1d1c','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','士生學六經，是爲聖人徒。',72,'全唐诗/poet.song.132000.json','["士生學六經，是爲聖人徒。", "處當師顔原，出當致唐虞。", "斯文陣堂堂，臨敵獨援枹。", "異端滿天下，一掃可使無。", "乃知立事功，先要定規模。", "彼雖力移山，安能奪匹夫。"]'),
('383054dc-970a-4645-9e62-ecbb97c0586a','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','公議在天下，如人有元氣。',72,'全唐诗/poet.song.132000.json','["公議在天下，如人有元氣。", "平居失護養，一旦可勝諱。", "神丹卒難求，百疾起如猬。", "奄奄息僅屬，熟視吁可畏。", "大義在春秋，遺迹悲漢魏。", "君看徐孺子，底物視富貴。"]'),
('93f5687a-0e85-4b55-a53f-e05e1f83c9a8','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','昔我自蜀歸，耆舊已凋喪。',72,'全唐诗/poet.song.132000.json','["昔我自蜀歸，耆舊已凋喪。", "後來二三公，尚慰天下望。", "千里一紙書，殷勤問亡恙。", "嗚呼亦已矣，遺語寄悲愴。", "我亦迫桑榆，便恐無輩行。", "夜窗對青燈，力憊心尚壯。"]'),
('900b9027-d12f-4f3b-bf19-cb949b3b875e','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','餘齡垂八十，雖憊猶强飯。',72,'全唐诗/poet.song.132000.json','["餘齡垂八十，雖憊猶强飯。", "正如老病馬，風沙時一噴。", "玉關眇何許，道里何啻萬。", "目中堠歷歷，欲進不能寸。", "矯首望秋空，徒羨霜鶻健。", "薶骨亦何悲，吾非麒麟楦。"]'),
('3b197ab6-5f11-4646-a504-abac49d2221f','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','琅琅誦詩書，尚記兩髦髧。',72,'全唐诗/poet.song.132000.json','["琅琅誦詩書，尚記兩髦髧。", "誰料七十年，沉滯終坎窞。", "炊突映茅廬，日暮烟慘慘。", "忍窮端已熟，撫事空自感。", "狂言悔噬臍，眾訾驚破膽。", "尚有愛書心，還如嗜菖歜。"]'),
('ff3e27e6-0e08-47ae-b07a-1844ff0445e0','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','去國己酉冬，忽見十頒曆。',72,'全唐诗/poet.song.132000.json','["去國己酉冬，忽見十頒曆。", "衰殘口兩齒，困阨家四壁。", "時看溪雲生，飽聽簷雨滴。", "悠然度寒暑，何處著欣戚。", "幽人豈知我，月夕聞吹笛。", "何當五百歲，相與摩銅狄。"]'),
('c0e61bb6-cffd-4278-8fba-46b3254e5b7b','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','扁舟東下峽，日月去若飛。',72,'全唐诗/poet.song.132000.json','["扁舟東下峽，日月去若飛。", "當時筆硯舊，久已晨星稀。", "俊逸如伯渾，簡詣如知幾。", "天高鬼神惡，回首萬事非。", "我欲泝黄牛，買屋居青衣。", "九原不可作，哀哉誰與歸。"]'),
('eb2fe800-b94a-4afd-8bdd-3770eeed7891','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','荷鉏草堂東，藝花二百株。',72,'全唐诗/poet.song.132000.json','["荷鉏草堂東，藝花二百株。", "春風一朝來，白白兼朱朱。", "南列紅薇屏，北界綠芋區。", "偃蹇雙松老，森聳萬竹臞。", "餘地不忍茀，插援引瓠壺。", "何當拂東絹，畫作山園圖。"]'),
('e0054d49-3a82-49b4-b366-c04bcc6ce9ee','齋中雜興十首以丈夫貴壯健慘戚非朱顔爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','閑居寂無客，柴門晝常關。',72,'全唐诗/poet.song.132000.json','["閑居寂無客，柴門晝常關。", "孤舟小於葉，放浪烟水間。", "樹暗楊梅村，露下白蓮灣。", "釣魚樵風涇，買酒石帆山。", "向來支許輩，恐亦無此閑。", "道逢若耶叟，握手開蒼顔。"]'),
('717e477f-bedb-447f-b434-55362d0fddc5','夏五月方閔雨忽大風雨三日未止二首  其一','陸游','宋','宋诗','song-poetry','','[]','海風一夕狂拔木，山雨三朝猛穿屋。',64,'全唐诗/poet.song.132000.json','["海風一夕狂拔木，山雨三朝猛穿屋。", "向來望雲眼欲枯，雨甚還憂敗嘉穀。", "今年旱勢連吳中，吾州乃獨勞神龍。", "稽首龍公要斟酌，收雲歸山水歸壑。"]'),
('e36bf8eb-1b13-4287-9a23-b8ba7d4943ff','夏五月方閔雨忽大風雨三日未止二首  其二','陸游','宋','宋诗','song-poetry','','[]','五月晝晦天欲雨，街中人面不相睹。',64,'全唐诗/poet.song.132000.json','["五月晝晦天欲雨，街中人面不相睹。", "風聲撼山翻怒濤，雨點飛空射强弩。", "一雨三日姑可休，龍其玩珠歸故湫。", "千里連雲慶多稼，牲肥酒香作秋社。"]'),
('5fef034c-914d-456f-a9fe-a2fcaef3d2e9','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','外物元知等一塵，浮生何事最關身。',64,'全唐诗/poet.song.132000.json','["外物元知等一塵，浮生何事最關身。", "江山好處得新句，風月佳時逢故人。", "有酒一樽聊自適，藏書萬卷未爲貧。", "聖賢自古無如命，君看居東與在陳。"]'),
('f5b9dcb2-13c0-4151-9dd0-294c4ea72006','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','老向人間怯路岐，感今懷昔不勝悲。',64,'全唐诗/poet.song.132000.json','["老向人間怯路岐，感今懷昔不勝悲。", "詩無傑思知才盡，酒有殘杯覺氣衰。", "縣郭燈疏尋店夜，津亭雨細待船時。", "筋骸尚給春耕在，便買烏犍亦未遲。"]'),
('ac85c86b-3285-4bbd-a54b-bef57e15d8b2','六月一日曉賦','陸游','宋','宋诗','song-poetry','','[]','視夜明星高，蟬聲滿庭樹。',72,'全唐诗/poet.song.132000.json','["視夜明星高，蟬聲滿庭樹。", "殘骸幸差健，散髮穿兩屨。", "巖扉手自開，曳杖得徐步。", "碧瓦浮青烟，圜荷瀉殘露。", "草木無俗姿，雞犬共幽趣。", "兒來問晨炊，一笑揮使去。"]'),
('360a6cee-c562-4f74-8823-d18d384034e0','露坐','陸游','宋','宋诗','song-poetry','','[]','泠泠野水赴橫塘，坐久松風入髮凉。',32,'全唐诗/poet.song.132000.json','["泠泠野水赴橫塘，坐久松風入髮凉。", "月淡星疏天欲曉，未妨清嘯倚胡床。"]'),
('cd070c97-a083-46c5-84a9-11f8c6ce9ba7','夜賦','陸游','宋','宋诗','song-poetry','','[]','月暈知將雨，風聲報近秋。',48,'全唐诗/poet.song.132000.json','["月暈知將雨，風聲報近秋。", "暗廊行熠燿，深樹嘯鵂鶹。", "老幸傳家事，狂猶爲國憂。", "相齊雖已矣，且復飯吾牛。"]'),
('a985d21c-4041-4c67-a5ae-bc0506763bfe','乙夜納凉','陸游','宋','宋诗','song-poetry','','[]','幽人新製葛衣成，二寸藤冠覺髮輕。',64,'全唐诗/poet.song.132000.json','["幽人新製葛衣成，二寸藤冠覺髮輕。", "凈掃中庭延月色，緩拖拄杖聽蟬聲。", "微凉便欲疏紈扇，小醉何妨倒玉罌。", "八尺風漪真美睡，故應高枕到窗明。"]'),
('df1ffbd0-420f-4581-9e5d-8df965fb8f76','五鼓','陸游','宋','宋诗','song-poetry','','[]','夢斷華胥夜艾時，遶廊蕭散曳筇枝。',64,'全唐诗/poet.song.132000.json','["夢斷華胥夜艾時，遶廊蕭散曳筇枝。", "長空漸見明河落，短調猶殘畫角吹。", "世事又隨朝日出，釣船莫負早秋期。", "南湖五畝新菰熟，此味惟應老子知。"]'),
('1225de05-7772-448e-9cbe-107f8f5890a4','老態','陸游','宋','宋诗','song-poetry','','[]','齒如强留客，雖住無久理。',72,'全唐诗/poet.song.132000.json','["齒如强留客，雖住無久理。", "目如新募兵，臨敵烏可使。", "齒廢疏粱肉，目澀屏書史。", "浮世真幾何，老態遽如此。", "啜粥習安坐，用短亦自喜。", "作詩記吾衰，聊用調稚子。"]'),
('1a913b34-8313-446e-83af-04fa7813992d','枕上聞風鈴二首  其一','陸游','宋','宋诗','song-poetry','','[]','毒暑今年倍故常，蟁聲四合欲舁床。',32,'全唐诗/poet.song.132000.json','["毒暑今年倍故常，蟁聲四合欲舁床。", "老人不辦摇團扇，靜聽風鈴意已凉。"]'),
('92615eec-2ce6-4fd2-897a-3443c775c577','枕上聞風鈴二首  其二','陸游','宋','宋诗','song-poetry','','[]','流汗沾衣熱不勝，饞蚊乘勢更縱橫。',32,'全唐诗/poet.song.132000.json','["流汗沾衣熱不勝，饞蚊乘勢更縱橫。", "夢回忽覺南風起，時聽錚然一兩聲。"]'),
('a32a9e0e-6448-45f7-84c8-baad3f19b255','寄贈湖中隱者','陸游','宋','宋诗','song-poetry','','[]','高標絕世不容親，識面無由况卜鄰。',64,'全唐诗/poet.song.132000.json','["高標絕世不容親，識面無由况卜鄰。", "萬頃烟波鷗境界，九秋風露鶴精神。", "子推綿上終身隱，叔度顔回一輩人。", "無地得申床下拜，夜聞吹笛度烟津。"]'),
('7a13276b-35e0-4518-ac35-044c34b978fb','觀畫山水','陸游','宋','宋诗','song-poetry','','[]','古北安西志未酬，人間隨處送悠悠。',64,'全唐诗/poet.song.132000.json','["古北安西志未酬，人間隨處送悠悠。", "騎驢白帝城邊雨，挂席黄陵廟外秋。", "大網截江魚可膾，高樓臨路酒如油。", "老來無復當年快，聊對丹青作卧遊。"]'),
('bed43ae2-985f-440e-a7cf-83541c2c1810','六月十八日立秋未旦起行山園口占','陸游','宋','宋诗','song-poetry','','[]','北斗離離柄漸西，披衣出戶聽晨雞。',64,'全唐诗/poet.song.132000.json','["北斗離離柄漸西，披衣出戶聽晨雞。", "豈惟蒲柳先摇落，坐覺風雲已慘凄。", "斷簡不妨重料理，清樽隨處可提携。", "穿林莫惜衣霑露，爽徹靈臺勝寶犀。"]'),
('17e288bb-166c-4713-9413-32e1ccf61c78','新秋','陸游','宋','宋诗','song-poetry','','[]','衰髮成絲奈若何，更堪日月疾飛梭。',64,'全唐诗/poet.song.132000.json','["衰髮成絲奈若何，更堪日月疾飛梭。", "梧桐敗葉飄猶少，蟋蟀雕籠賣已多。", "歲樂喧呼沽酒市，夜凉凄斷采菱歌。", "老夫亦動秋風興，欲倩鄰翁買釣蓑。"]'),
('edd74224-1417-44e0-ba63-cb3024167c0f','晨起自山園歸書室','陸游','宋','宋诗','song-poetry','','[]','世事苦紛紛，村墟寂不聞。',48,'全唐诗/poet.song.132000.json','["世事苦紛紛，村墟寂不聞。", "穿林拾蟬蛻，隔浦數鷗群。", "摇落初飄葉，高舂未散雲。", "歸來書滿眼，猶足肆吾勤。"]'),
('68a94cda-aab0-4324-a3fd-60ce43aac191','初秋小雨','陸游','宋','宋诗','song-poetry','','[]','雨來一洗肺肝熱，風過遠吹禾黍香。',32,'全唐诗/poet.song.132000.json','["雨來一洗肺肝熱，風過遠吹禾黍香。", "誰識山翁歡喜處，短檠燈火夜初長。"]'),
('8c2ee922-1e28-4615-8272-55aacdf5499a','出遊','陸游','宋','宋诗','song-poetry','','[]','舉世誰能伴我閑，出游隨處一開顔。',64,'全唐诗/poet.song.132000.json','["舉世誰能伴我閑，出游隨處一開顔。", "繫船扛鼎將軍廟，秣蹇流觴內史山。", "小市况經摇落後，高城回望莽蒼間。", "歸來燈火湖塘晚，指點柴門未上關。"]'),
('83fcbd5b-6b79-40da-afae-ed3a9fefb0e3','對酒','陸游','宋','宋诗','song-poetry','','[]','平生但信緣，作計每不審。',72,'全唐诗/poet.song.132000.json','["平生但信緣，作計每不審。", "舂炊官倉粟，一飽輒甘寢。", "二年棄微祿，溝壑方懔懔。", "藜羹闕鹽酪，豆飯雜沙墋。", "偶然餓不死，得酒猶痛飲。", "捩回灧澦柁，喚省邯鄲枕。"]'),
('f55d80d0-688a-4ff3-8a0d-b264142d632f','自勉','陸游','宋','宋诗','song-poetry','','[]','曩歲讀隱書，妄意慕陶葛。',72,'全唐诗/poet.song.132000.json','["曩歲讀隱書，妄意慕陶葛。", "芝房及乳石，日夜躬采掇。", "飛舉固未能，死籍或可脫。", "那知事大謬，髮齒將禿豁。", "神僊豈棄汝，正坐自迂闊。", "餘年尚努力，勿待燭見跋。"]'),
('8a74c79a-801b-4a0e-b81d-f1ce9a2e2452','新凉','陸游','宋','宋诗','song-poetry','','[]','初卷含風八尺漪，井桐已復不禁吹。',32,'全唐诗/poet.song.132000.json','["初卷含風八尺漪，井桐已復不禁吹。", "蟬聲未用催殘日，最愛新凉滿袖時。"]'),
('2bad7346-5a62-4962-b7c1-020e0b79ec79','醉中題民家壁','陸游','宋','宋诗','song-poetry','','[]','壯歲羈遊厭故棲，暮年却愛草堂低。',64,'全唐诗/poet.song.132000.json','["壯歲羈遊厭故棲，暮年却愛草堂低。", "交情最向貧中見，世事常於醉後齊。", "松吹颼颼凉短髮，芒鞋策策響新泥。", "吾詩戲用寒山例，小市人家到處題。"]'),
('e4d66369-426f-4f7f-9ee3-924e881ea5d4','秋景','陸游','宋','宋诗','song-poetry','','[]','雨泣蘋花老，風摇稗穗長。',48,'全唐诗/poet.song.132000.json','["雨泣蘋花老，風摇稗穗長。", "昏林喧宿鳥，秋院咽啼螿。", "舊學成迂闊，初心墮渺茫。", "頹齡尚餘幾，誰與問蒼蒼。"]'),
('e72436e9-7693-4ab1-917e-c3046e958f3d','舟中作','陸游','宋','宋诗','song-poetry','','[]','會稽城上角嗚嗚，日落烟村暝欲無。',32,'全唐诗/poet.song.132000.json','["會稽城上角嗚嗚，日落烟村暝欲無。", "千載虛名笑張翰，一官元不直蓴鱸。"]'),
('19973a92-1c6a-4572-a07f-6e728b04a9af','雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','足弱僅能行，齒摇常欲墮。',48,'全唐诗/poet.song.132000.json','["足弱僅能行，齒摇常欲墮。", "扶持賴藥物，苟幸一日過。", "事來强酬答，其實惟欲卧。", "平生許文休，歲晚依馬磨。"]'),
('c7c01de0-bf1f-4b75-8b3e-d51a2084c141','雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','蘭臺遺漆書，汲冢收竹簡。',48,'全唐诗/poet.song.132000.json','["蘭臺遺漆書，汲冢收竹簡。", "辛勤萬卷讀，不負百年眼。", "圍座浩縱橫，插架高𡾰嵼。", "一笑顧吾兒，銀艾何足綰。"]'),
('29ceaaa7-13f0-4bcf-bf65-62b2e355a075','雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','壽年本偶爾，亦與富貴同。',48,'全唐诗/poet.song.132000.json','["壽年本偶爾，亦與富貴同。", "一日復一日，遂作八十翁。", "几杖稱大耋，貂蟬號三公。", "信手忽成盧，孰爲拙與工。"]'),
('ad30c68f-de0f-44a1-94f7-93967c14b500','雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','少年豈知酒，借醉以作狂。',48,'全唐诗/poet.song.132000.json','["少年豈知酒，借醉以作狂。", "中年狂已歇，始覺酒味長。", "湛湛癭樽綠，酌以紅螺觴。", "醒醉不可名，兀坐萬事忘。"]'),
('efd3dc4d-e1f2-47c6-8081-eb26d943a4a0','自詠閑適','陸游','宋','宋诗','song-poetry','','[]','殘年鄰曲幸相依，真似遼天老鶴歸。',64,'全唐诗/poet.song.132000.json','["殘年鄰曲幸相依，真似遼天老鶴歸。", "荷浦未疏魚正美，豆畦欲暗雉初肥。", "款門路近時看竹，送酒人多不典衣。", "最喜夕陽閑望處，數家垣屋鎖烟霏。"]'),
('62620b71-262c-4a11-bad1-1a7d9a7b95ad','近村暮歸','陸游','宋','宋诗','song-poetry','','[]','莫笑山翁雪鬢繁，歸休幸出上恩寬。',64,'全唐诗/poet.song.132000.json','["莫笑山翁雪鬢繁，歸休幸出上恩寬。", "鱟樽恰受三升醞，龜屋新裁二寸冠。", "僧閣煮茶同淡話，漁舟投釣卜清歡。", "還家欲作諸孫贈，村路纍纍柿未丹。"]'),
('bf5699c8-c990-40d6-b294-3169d0522ad0','秋興','陸游','宋','宋诗','song-poetry','','[]','扶衰又見素秋過，未死其如造物何。',64,'全唐诗/poet.song.132000.json','["扶衰又見素秋過，未死其如造物何。", "破屋頹垣那敢議，濁醪粗飯已爲多。", "佩刀但可償黄犢，作字安能博白鵝。", "龜紫拜恩如夢寐，殘年其實一漁蓑。"]'),
('e60f426b-c48c-4f1f-aa40-a41e4bd63478','讀史有感三首  其一','陸游','宋','宋诗','song-poetry','','[]','不肯低頭就世事，亦不作箋與天公。',32,'全唐诗/poet.song.132000.json','["不肯低頭就世事，亦不作箋與天公。", "惟須痛飲以醉死，亂山深處聽松風。"]'),
('ffd52b7e-85e9-4819-83de-8d8c431a1f65','讀史有感三首  其二','陸游','宋','宋诗','song-poetry','','[]','昔人識不過十字，富貴封侯渠自如。',32,'全唐诗/poet.song.132000.json','["昔人識不過十字，富貴封侯渠自如。", "龜堂閉門萬卷讀，一字不肯供時須。"]'),
('b7bd9c62-56ef-445b-b2f6-4007f8cadbf3','讀史有感三首  其三','陸游','宋','宋诗','song-poetry','','[]','蘇門長嘯不可親，鹿門采藥更絕塵。',32,'全唐诗/poet.song.132000.json','["蘇門長嘯不可親，鹿門采藥更絕塵。", "老死故山雖自許，掩書未免愧斯人。"]'),
('66d0db16-bcb2-4837-a116-2bc902c94fbd','讀何斯舉黄州秋居雜詠次其韵十首  其一','陸游','宋','宋诗','song-poetry','','[]','造請非所長，一带每懶束。',72,'全唐诗/poet.song.132000.json','["造請非所長，一带每懶束。", "揖客雖小殊，亦未勝僕僕。", "正須駕柴車，歸藝東籬菊。", "故山甘水泉，群飲友麋鹿。", "百年不堪玩，萬事要自燭。", "小人欺屋漏，吾輩當戒獨。"]'),
('402828f8-cd8c-40da-804a-08745234f3f3','讀何斯舉黄州秋居雜詠次其韵十首  其二','陸游','宋','宋诗','song-poetry','','[]','少從長者遊，粗聞聖人道。',72,'全唐诗/poet.song.132000.json','["少從長者遊，粗聞聖人道。", "日食雖一簞，頗覺顔色好。", "辛勤五十年，猶秉後凋操。", "風俗日已移，令人惡懷抱。", "紛紛堪一咍，驕我以旗纛。", "豈知江湖間，世襲散人號。"]'),
('1f73e66b-850c-46fc-954a-8c5f44e60108','讀何斯舉黄州秋居雜詠次其韵十首  其三','陸游','宋','宋诗','song-poetry','','[]','全家寄舴艋，結茅非始謀。',72,'全唐诗/poet.song.132000.json','["全家寄舴艋，結茅非始謀。", "江市得烟蓑，不博千金裘。", "道散俗日薄，老聃出衰周。", "治身去健羨，如稼必去蟊。", "吾身一隙塵，斯世一客郵。", "君能通其說，生死真浮休。"]'),
('c5d185ad-5fac-4a47-bc44-821268b0c66b','讀何斯舉黄州秋居雜詠次其韵十首  其四','陸游','宋','宋诗','song-poetry','','[]','眾星麗長空，惟月最爲傑。',72,'全唐诗/poet.song.132000.json','["眾星麗長空，惟月最爲傑。", "峨峨大圜鏡，粲粲白玉玦。", "穿林散珠璣，入戶凜霜雪。", "世方喜繁華，我獨慘不悅。", "清光真可友，肝肺冰欲結。", "彼哉市朝人，忿欲生內熱。"]'),
('3f3a5421-35f7-471f-a772-68d1fbb41b68','讀何斯舉黄州秋居雜詠次其韵十首  其五','陸游','宋','宋诗','song-poetry','','[]','夜靜我欲歌，四座且勿喧。',72,'全唐诗/poet.song.132000.json','["夜靜我欲歌，四座且勿喧。", "堯舜本得道，富貴何足捐。", "聖人久不作，學者墮語言。", "著書各專門，百家散如烟。", "一身有不知，况察魚與鳶。", "安得天下士，相與明忘筌。"]'),
('3d3ae813-dcc6-4ce2-85c5-f2e32f57b45b','讀何斯舉黄州秋居雜詠次其韵十首  其六','陸游','宋','宋诗','song-poetry','','[]','古人處丘園，如彼不嫁女。',72,'全唐诗/poet.song.132000.json','["古人處丘園，如彼不嫁女。", "終身秉大節，敢恨老環堵。", "嗟予晚乃覺，乞骸歸卒伍。", "去就講已熟，穴居宜知雨。", "百尺持汲綆，道長畏天暑。", "先見雖有慚，愛身亦自許。"]'),
('d5542068-114d-47c1-b731-821b4db885ff','讀何斯舉黄州秋居雜詠次其韵十首  其七','陸游','宋','宋诗','song-poetry','','[]','賦性本剛褊，直欲棲深山。',72,'全唐诗/poet.song.132000.json','["賦性本剛褊，直欲棲深山。", "晚乃稍悔悟，自恨不少寬。", "胡越本一家，禍福環無端。", "少忍萬事畢，孰爲熱與寒。", "我友爲我言，冠蓋滿長安。", "人人不如君，八十猶朱顔。"]'),
('427f71f9-592b-4dd6-9129-6377e48c4c0c','讀何斯舉黄州秋居雜詠次其韵十首  其八','陸游','宋','宋诗','song-poetry','','[]','倚牆有鉏耰，當戶有杼軸。',72,'全唐诗/poet.song.132000.json','["倚牆有鉏耰，當戶有杼軸。", "雖云生產薄，桑麻亦滿目。", "况承先人教，藏書令汝讀。", "求仁固不遠，所要念念熟。", "喟然語兒子，勿愧藜莧腹。", "亦勿慕虛名，守此不啻足。"]'),
('ce46ca83-60e3-4c75-8d5c-717651b93319','讀何斯舉黄州秋居雜詠次其韵十首  其九','陸游','宋','宋诗','song-poetry','','[]','人生天壤間，出處本異趣。',72,'全唐诗/poet.song.132000.json','["人生天壤間，出處本異趣。", "釋耒入市朝，徒失邯鄲步。", "昔人亦有言，刻足以適屨。", "奈何不自反，忽已迫霜露。", "我躬尚不閱，况爲子孫慮。", "歲晚故山寒，地爐可煨芋。"]'),
('8fabfd56-d938-4a4a-87d8-808e9283890e','讀何斯舉黄州秋居雜詠次其韵十首  其一○','陸游','宋','宋诗','song-poetry','','[]','少年去國時，不忍輕出晝。',72,'全唐诗/poet.song.132000.json','["少年去國時，不忍輕出晝。", "晚歸補省郎，但覺慚列宿。", "人豈不自揣，幸矣老雲岫。", "知止詎敢希，要且避嘲詬。", "誰將有限身，遺臭古今宙。", "人誅雖或逃，陰陽將汝寇。"]'),
('6361fbc8-9d60-4eda-9673-094fb077cd81','讀蘇叔黨汝州北山雜詩次其韵十首  其一','陸游','宋','宋诗','song-poetry','','[]','暑耘日炙背，寒耕泥沒脚。',72,'全唐诗/poet.song.132000.json','["暑耘日炙背，寒耕泥沒脚。", "眾人占膏腴，我獨治磽确。", "力盡功未見，厥土但如昨。", "豈惟窘糠粞，直恐轉溝壑。", "今年雨暘時，天如相耕穫。", "屋傾未暇扶，且復補籬落。"]'),
('b06aa0f5-9299-46e0-8a97-81aa60ed2bb7','讀蘇叔黨汝州北山雜詩次其韵十首  其二','陸游','宋','宋诗','song-poetry','','[]','舊絮補破襦，生薪續微火。',72,'全唐诗/poet.song.132000.json','["舊絮補破襦，生薪續微火。", "惸孤有凍死，自視亦已過。", "鄰翁冒風雪，斗酒持飲我。", "尖團擘霜蟹，丹漆飣山果。", "欣然共笑語，何止寬寒餓。", "布被擁更闌，招魂不須些。"]'),
('98e03dfb-219f-48f9-8d2d-3b45830ac73c','讀蘇叔黨汝州北山雜詩次其韵十首  其三','陸游','宋','宋诗','song-poetry','','[]','三山鏡湖上，出郭無十里。',72,'全唐诗/poet.song.132000.json','["三山鏡湖上，出郭無十里。", "結廬非所擇，但取便薪水。", "間亦出從宦，安能慕園綺。", "地主卜林塘，亦復異子美。", "籧篨方丈室，僅足容卧起。", "吾意本扁舟，陸居聊爾耳。"]'),
('16f91b82-8c17-402c-bff2-e633b6c27c91','讀蘇叔黨汝州北山雜詩次其韵十首  其四','陸游','宋','宋诗','song-poetry','','[]','祠官粟一囊，不贍軀七尺。',72,'全唐诗/poet.song.132000.json','["祠官粟一囊，不贍軀七尺。", "前年蒙寬恩，例許乞骸骨。", "聯翩三兒子，俱作鸛雀碧。", "賦祿雖尚遠，亦足慰衰白。", "幅巾茆簷下，稱病謝來客。", "從今門前路，永掃車馬迹。"]'),
('fe0d6345-8a27-4625-a2bd-c5bb87d1e9e1','讀蘇叔黨汝州北山雜詩次其韵十首  其五','陸游','宋','宋诗','song-poetry','','[]','舍北有漁磯，下臨清溪流。',72,'全唐诗/poet.song.132000.json','["舍北有漁磯，下臨清溪流。", "柳陰出朱橋，蓮浦橫蘭舟。", "蓴絲二三畝，采掇供晨羞。", "魚蝦雖瑣細，亦足贍吾州。", "人生常如此，安用萬戶侯。", "綠蓑幸可買，金印非所求。"]'),
('01865f6e-06eb-4cd2-8a23-6aa1c6b3f934','讀蘇叔黨汝州北山雜詩次其韵十首  其六','陸游','宋','宋诗','song-poetry','','[]','寓形百年中，如臂屈伸頃。',72,'全唐诗/poet.song.132000.json','["寓形百年中，如臂屈伸頃。", "少壯幾何時，已復墮衰境。", "老人喜自潔，臨澗漱綠凈。", "佛龕香事已，僧鉢供煮餅。", "山茶試芳嫩，野果薦甘冷。", "不學萬錢厨，長魚取淮潁。"]'),
('a09a7cd9-cee5-4a9e-b906-df6553b5b36e','讀蘇叔黨汝州北山雜詩次其韵十首  其七','陸游','宋','宋诗','song-poetry','','[]','巖石著幼輿，風月思玄度。',72,'全唐诗/poet.song.132000.json','["巖石著幼輿，風月思玄度。", "老子放浪心，常恐迫遲暮。", "安得世外人，握手相與語。", "吾宗甫里公，奇辭賦漁具。", "高風邈不嗣，徒有吟諷苦。", "霜風吹短衣，何山不堪住。"]'),
('7b283ace-04d6-4d97-82fa-6abe1489a09f','讀蘇叔黨汝州北山雜詩次其韵十首  其八','陸游','宋','宋诗','song-poetry','','[]','久病卧江村，髮白面黧黑。',72,'全唐诗/poet.song.132000.json','["久病卧江村，髮白面黧黑。", "艱難念溫飽，日夜積涓滴。", "聚壤糞園桑，荷鋤耘壟麥。", "苟失一日勤，農事深可惜。", "小兒念乃翁，卒歲共欣戚。", "跂望明年春，社雨泥一尺。"]'),
('96ab0d3c-078e-4927-9ffd-a3b1611a9bf4','讀蘇叔黨汝州北山雜詩次其韵十首  其九','陸游','宋','宋诗','song-poetry','','[]','德孫秀眉宇，慨然修初服。',72,'全唐诗/poet.song.132000.json','["德孫秀眉宇，慨然修初服。", "枯腸貯詩書，十飯九不肉。", "成童將覓舉，想見袍立鵠。", "先澤儻未衰，豈無五秉粟。", "汝能記吾言，併以告阿福。", "閉門勿雜交，一經萬事足。"]'),
('54564b55-da2e-43d0-87ed-de90a4114d1d','讀蘇叔黨汝州北山雜詩次其韵十首  其一○','陸游','宋','宋诗','song-poetry','','[]','吾幼從父師，所患經不明。',72,'全唐诗/poet.song.132000.json','["吾幼從父師，所患經不明。", "何嘗效侯喜，欲取能詩聲。", "亦豈劉隨州，五字矜長城。", "秋雨短檠夜，掉頭費經營。", "區區宇宙間，捨重取所輕。", "此身儻未死，仁義尚力行。"]'),
('03201f63-6198-4a8c-804c-0279e6990bfd','新治火閣','陸游','宋','宋诗','song-poetry','','[]','老子今朝喜有餘，房櫳新畢得安居。',64,'全唐诗/poet.song.132000.json','["老子今朝喜有餘，房櫳新畢得安居。", "爐紅氈暖不出戶，木落窗明常讀書。", "浮蟻撇嘗人散後，蹲鴟煨熟雪飛初。", "頹然自適還終日，殊勝隆中卧草廬。"]'),
('fc371dc6-e3be-4f68-8186-850beb5573ff','枕上作二首  其一','陸游','宋','宋诗','song-poetry','','[]','無地容錐四壁空，浩然亦未愴途窮。',64,'全唐诗/poet.song.132000.json','["無地容錐四壁空，浩然亦未愴途窮。", "夢回倦枕燈殘後，詩在空階雨滴中。", "徂歲易成雙鬢禿，故人難復一樽同。", "唐安萬里音塵絕，誰爲寒沙問斷鴻。"]'),
('c59fa681-a012-4855-98d4-ef270b135ea3','枕上作二首  其二','陸游','宋','宋诗','song-poetry','','[]','蕭蕭白髮卧扁舟，死盡中朝舊輩流。',64,'全唐诗/poet.song.132000.json','["蕭蕭白髮卧扁舟，死盡中朝舊輩流。", "萬里關河孤枕夢，五更風雨四山秋。", "鄭虔自笑窮耽酒，李廣何妨老不侯。", "猶有少年風味在，吳箋著句寫清愁。"]'),
('ceff9287-a06f-4d63-ab53-6f3c992b3dad','初睡起有作','陸游','宋','宋诗','song-poetry','','[]','喔喔曉雞鳴，迢迢殘漏聲。',48,'全唐诗/poet.song.132000.json','["喔喔曉雞鳴，迢迢殘漏聲。", "撥衾幽夢斷，褰幌小窗明。", "獠婢篝衣暖，山童擁篲行。", "老夫徐下榻，負火聽瓶笙。"]'),
('042148f7-ede7-4567-9d5f-462f50158882','示友','陸游','宋','宋诗','song-poetry','','[]','道向虛中得，文從實處工。',48,'全唐诗/poet.song.132000.json','["道向虛中得，文從實處工。", "凌空一鶚上，赴海百川東。", "氣骨真當勉，規模不必同。", "人生易衰老，君等勿匆匆。"]'),
('f8465141-a3b5-4926-a473-590f4f7da50e','述懷','陸游','宋','宋诗','song-poetry','','[]','宦遊輕用不貲身，斂退今爲省事人。',64,'全唐诗/poet.song.132000.json','["宦遊輕用不貲身，斂退今爲省事人。", "唾俟面乾元不校，羹憂手爛更誰嗔。", "時分鄰甕雙瓶綠，永謝官倉五斗陳。", "最好暮秋溪上路，柴門月色向人新。"]'),
('517fe5e7-dd11-4f7b-b237-5b8f548b6983','枕上二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘燈熠熠露螢明，落葉蕭蕭寒雨聲。',32,'全唐诗/poet.song.132000.json','["殘燈熠熠露螢明，落葉蕭蕭寒雨聲。", "堪笑衰翁睡眠少，小詩常向此時成。"]'),
('7b46f9c6-ab6b-4d15-b117-dde9fe915ba7','枕上二首  其二','陸游','宋','宋诗','song-poetry','','[]','斷香猶在夢初回，燈似孤螢闔復開。',32,'全唐诗/poet.song.132000.json','["斷香猶在夢初回，燈似孤螢闔復開。", "怪底詩情清徹骨，數聲新雁枕邊來。"]'),
('7477be86-0d1a-4f84-8cc7-e0a6334f34f2','病足久敗遊山之興山中道人多見問戲作示之','陸游','宋','宋诗','song-poetry','','[]','病侵腰股作蹣跚，九折途生布武間。',64,'全唐诗/poet.song.132000.json','["病侵腰股作蹣跚，九折途生布武間。", "東姥自無緣見佛，北公那有力移山。", "買來芒屨真虛費，扶上籃輿亦漸艱。", "賴有舂陵數峰在，虛窗高卧看孱顔。"]'),
('e9d3f726-77cb-4b9d-8e7f-457cf5069d0c','舟中作','陸游','宋','宋诗','song-poetry','','[]','三百里湖新月時，放翁艇子出尋詩。',64,'全唐诗/poet.song.132000.json','["三百里湖新月時，放翁艇子出尋詩。", "城頭蜃閣烟將合，波面虹橋柳未衰。", "漁唱蒼茫連禹穴，寒潮蕭瑟過娥祠。", "祖龍虛負求僊意，身到蓬萊却不知。"]'),
('0c4ae4ea-5486-4841-95e1-03be3b9b27dd','追懷胡基仲','陸游','宋','宋诗','song-poetry','','[]','高潔胡徵士，當時已絕無。',48,'全唐诗/poet.song.132000.json','["高潔胡徵士，當時已絕無。", "門庭謝殘客，薪水斥常奴。", "遺稿何由見，英魂不可呼。", "誰憐墓上草，又是一年枯。"]'),
('0d557432-6116-48f5-9dcb-1226d086e7f3','十月八日九日連夕雷雨','陸游','宋','宋诗','song-poetry','','[]','雨聲聒耳不停點，雲氣冒山殊未開。',64,'全唐诗/poet.song.132000.json','["雨聲聒耳不停點，雲氣冒山殊未開。", "敢恨終年惟短褐，但驚十月有奔雷。", "牽蘿且復補茆屋，飯豆何妨羹芋魁。", "莫笑賦詩無傑句，年來萬事學低摧。"]'),
('087bf3d5-602a-4661-a2fe-2e51a394b8cb','西村','陸游','宋','宋诗','song-poetry','','[]','今年四月天初暑，買蓑曾向西村去。',64,'全唐诗/poet.song.132000.json','["今年四月天初暑，買蓑曾向西村去。", "桑麻滿野陂水深，遥望人家不知路。", "再來桑落陂無水，閉門但見炊烟起。", "疑是羲黄上古民，又恐種桃來避秦。"]'),
('60ccd2c0-5879-4ff5-a6a9-3dfb85d78bed','感事示兒孫','陸游','宋','宋诗','song-poetry','','[]','人生讀書本餘事，惟要閉門修孝悌。',64,'全唐诗/poet.song.132000.json','["人生讀書本餘事，惟要閉門修孝悌。", "畜豚種菜養父兄，此風乃可傳百世。", "我聞長安官道傍，至今人指魏公莊。", "北方俗厚終可憙，一字不識勤耕桑。"]'),
('052fdb35-617a-4f68-b9d9-b91d1e8df515','或遺木瓜有雙實者香甚戲作','陸游','宋','宋诗','song-poetry','','[]','宣城繡瓜有奇香，偶得並蒂置枕傍。',32,'全唐诗/poet.song.132000.json','["宣城繡瓜有奇香，偶得並蒂置枕傍。", "六根互用亦何常，我以鼻嗅代舌嘗。"]'),
('1c41122f-519b-4c74-bf5a-a9cce02a56ab','十月','陸游','宋','宋诗','song-poetry','','[]','十月霜侵季子裘，吾詩又送一年秋。',64,'全唐诗/poet.song.132000.json','["十月霜侵季子裘，吾詩又送一年秋。", "風回斷續聞樵唱，木落參差見寺樓。", "久已浮雲看富貴，固應華屋等山丘。", "江邊海際多幽致，擬跨青騾處處遊。"]'),
('559fdbaa-adc8-4138-a870-2addd7bf65ab','初晴','陸游','宋','宋诗','song-poetry','','[]','袖手東窗初日明，殘編未負老書生。',64,'全唐诗/poet.song.132000.json','["袖手東窗初日明，殘編未負老書生。", "不勝多病畏寒雨，正得一霜方快晴。", "客戶餉羹提赤鯉，鄰家借碓擣新秔。", "柴荆莫怪無車馬，恰要無人識姓名。"]'),
('9abee549-95ee-420a-bd93-74bea9bee9e8','梅花五首  其一','陸游','宋','宋诗','song-poetry','','[]','造物作梅花，毫髮無遺恨。',24,'全唐诗/poet.song.132000.json','["造物作梅花，毫髮無遺恨。", "楚人稱芳蘭，細看終不近。"]'),
('e29577fa-be82-4c31-aea5-80533792509b','梅花五首  其二','陸游','宋','宋诗','song-poetry','','[]','五年作竹梢，十年作梅枝。',24,'全唐诗/poet.song.132000.json','["五年作竹梢，十年作梅枝。", "九泉子廉子，此語今誰知。"]'),
('9e1da37c-c9d1-4ce6-9ee3-c9d304b0887f','梅花五首  其三','陸游','宋','宋诗','song-poetry','','[]','欲與梅爲友，常憂不稱渠。',24,'全唐诗/poet.song.132000.json','["欲與梅爲友，常憂不稱渠。", "從今斷火食，飲水讀僊書。"]'),
('aa2ab087-10e4-45d5-a6df-a26089ec2e3e','梅花五首  其四','陸游','宋','宋诗','song-poetry','','[]','春信今年早，江頭昨夜寒。',24,'全唐诗/poet.song.132000.json','["春信今年早，江頭昨夜寒。", "已教清徹骨，更向月中看。"]'),
('d5703bd1-48c3-4fc4-9cdb-fe03db37e63d','梅花五首  其五','陸游','宋','宋诗','song-poetry','','[]','江上梅花吐，山頭霜月明。',24,'全唐诗/poet.song.132000.json','["江上梅花吐，山頭霜月明。", "摩挲古藤杖，三友可同盟。"]'),
('a9f236f1-63b9-4038-8a5e-fe3c4795da4c','對酒戲詠','陸游','宋','宋诗','song-poetry','','[]','淺傾西國蒲萄酒，小嚼南州豆蔻花。',32,'全唐诗/poet.song.132000.json','["淺傾西國蒲萄酒，小嚼南州豆蔻花。", "更拂烏絲寫新句，此翁可惜老天涯。"]'),
('b1ae7e54-e359-4587-a745-56b8e6d76d64','冬夜','陸游','宋','宋诗','song-poetry','','[]','北斗挂屋角，西風驚雁群。',48,'全唐诗/poet.song.132000.json','["北斗挂屋角，西風驚雁群。", "山寒歲云暮，人靜夜中分。", "酒滴糟床雨，香生紙帳雲。", "眼花書課減，舊學失鋤耘。"]'),
('c160856b-4874-47e7-8cce-b4b25a680924','冬晴稍理舊學有感于懷','陸游','宋','宋诗','song-poetry','','[]','天公元不吝光陰，付與書生遂本心。',64,'全唐诗/poet.song.132000.json','["天公元不吝光陰，付與書生遂本心。", "老已爲民猶學問，向雖作吏半山林。", "百年斷稿傳三世，一日晴窗抵萬金。", "努力更思恢道術，酒杯雖把不須深。"]'),
('3a61a82f-ca1d-4af1-beb4-b2c82ec67845','葺小圃及東齋','陸游','宋','宋诗','song-poetry','','[]','山翁作園沼，安樂及禽魚。',48,'全唐诗/poet.song.132000.json','["山翁作園沼，安樂及禽魚。", "凡草猶當養，芳蘭可得鋤。", "初非治一室，亦豈愛吾廬。", "暮境雖云迫，心期故有餘。"]'),
('fc1dc5ae-ca13-4a04-b5cb-8a9c0c5449ce','讀經示兒子','陸游','宋','宋诗','song-poetry','','[]','通經本訓詁，講字極聲形。',48,'全唐诗/poet.song.132000.json','["通經本訓詁，講字極聲形。", "未盡寸心苦，已銷雙鬢青。", "懼如臨戰陣，敬若在朝廷。", "此是吾家事，兒曹要細聽。"]'),
('55f0e921-5824-4b10-8d8c-8a1608dba4b3','出遊不果','陸游','宋','宋诗','song-poetry','','[]','天柱峰前水亂流，石棋渡口葉飛秋。',32,'全唐诗/poet.song.132000.json','["天柱峰前水亂流，石棋渡口葉飛秋。", "青鞋已是前身事，縱有籃輿亦懶遊。"]'),
('00a8916a-3d67-404b-9211-9ad5ffdd7426','夢行秦晉間有作','陸游','宋','宋诗','song-poetry','','[]','夜店紬衾暖，晨厨粟飯香。',48,'全唐诗/poet.song.132000.json','["夜店紬衾暖，晨厨粟飯香。", "驢肩雙酒榼，童背一琴囊。", "冰坼河聲壯，郊平塔影長。", "古今均夢境，不用弔興亡。"]'),
('0eb0f1c9-5d08-4d21-bf34-6f4be832f9e6','聞雞鳴自警','陸游','宋','宋诗','song-poetry','','[]','爲善孳孳進德新，雞鳴每念舜何人。',32,'全唐诗/poet.song.132000.json','["爲善孳孳進德新，雞鳴每念舜何人。", "此身强健直須勉，一日會當無此身。"]'),
('eaa38187-df1c-4eb6-9bee-6bb014d9cc6e','嘲子聿','陸游','宋','宋诗','song-poetry','','[]','講誦多吳語，鈎提學佐書。',48,'全唐诗/poet.song.132000.json','["講誦多吳語，鈎提學佐書。", "夜分燈未徹，晨起髮慵梳。", "飽食園官菜，少留溪友魚。", "能憐乃翁病，身自舉籃輿。"]'),
('349d1e99-dc4e-43c4-abf2-accb77aeb2d0','馬上口占','陸游','宋','宋诗','song-poetry','','[]','大耋光陰豈自期，即今堪喜亦堪悲。',64,'全唐诗/poet.song.132000.json','["大耋光陰豈自期，即今堪喜亦堪悲。", "關河隔絕初心負，憂患侵尋舊學衰。", "羸馬涉溪孤店路，栖鴉滿樹曉霜時。", "憑鞍殘夢悠然覺，又得浮生一首詩。"]'),
('0c6f3173-c444-422a-aab5-2f9a06487a27','幽居','陸游','宋','宋诗','song-poetry','','[]','莫笑茅茨陋，岡形接卧龍。',48,'全唐诗/poet.song.132000.json','["莫笑茅茨陋，岡形接卧龍。", "連娟鏡湖月，縹渺寶林鐘。", "閑約魚池釣，眠聽碓舍舂。", "他年好事客，過此訪遺蹤。"]'),
('4ea87939-b204-4d2a-a511-719ec4902628','感事','陸游','宋','宋诗','song-poetry','','[]','陋巷何須嘆一瓢，朱門能守亦寥寥。',64,'全唐诗/poet.song.132000.json','["陋巷何須嘆一瓢，朱門能守亦寥寥。", "衲衣先世曾調鼎，野褐家聲本珥貂。", "若悟死生均露電，未應富貴勝漁樵。", "千年回首俱陳迹，不向杯中何處消。"]'),
('c034d4f8-b09e-430f-87b3-a45373584131','初寒','陸游','宋','宋诗','song-poetry','','[]','逐祿天涯半此生，明時寬大許歸耕。',64,'全唐诗/poet.song.132000.json','["逐祿天涯半此生，明時寬大許歸耕。", "山圍魚市寒無色，雨掠蓬窗夜有聲。", "白髮青燈身潦倒，殘蕪落葉歲崢嶸。", "爾來有喜君知否，買得烏犍萬事輕。"]'),
('4cf2426b-4f27-4f02-8cc0-8016f98e0c67','寄題季長飾庵','陸游','宋','宋诗','song-poetry','','[]','近詔還中秘，新文記飾庵。',48,'全唐诗/poet.song.132000.json','["近詔還中秘，新文記飾庵。", "主盟君勿讓，賈勇我何堪。", "木落山容瘦，雲齊雪意酣。", "何由共杯酒，把蟹擘黄甘。"]'),
('f0487c61-ab68-4652-973f-d8fdd5deec18','對食書愧','陸游','宋','宋诗','song-poetry','','[]','連年寬水旱，天若相懸車。',48,'全唐诗/poet.song.132000.json','["連年寬水旱，天若相懸車。", "粗有芋魁豆，併忘熊掌魚。", "先生飯不足，賢者食無餘。", "老我知何幸，晨盤厭美蔬。"]'),
('e7c5e12f-d819-46dd-9e26-206c1ccbf831','戲題酒家壁三首  其一','陸游','宋','宋诗','song-poetry','','[]','漫道江南倚寺樓，豈如烟雨弄扁舟。',64,'全唐诗/poet.song.132000.json','["漫道江南倚寺樓，豈如烟雨弄扁舟。", "并刀不翦清愁斷，楚練難縻白日留。", "湖上采菰甘似蜜，街頭買酒滑如油。", "金丹九轉何時畢，且對梅花一醉休。"]'),
('ce7049b0-e447-4587-bd1a-0b69db80547f','戲題酒家壁三首  其二','陸游','宋','宋诗','song-poetry','','[]','送了春歸又送秋，人間隨處寄悠悠。',64,'全唐诗/poet.song.132000.json','["送了春歸又送秋，人間隨處寄悠悠。", "百年此際成遺老，萬里當時賦遠遊。", "筆力日衰慚陣馬，江天歲晚狎冥鷗。", "清狂自笑無時歇，又犯新寒上市樓。"]'),
('36d0c836-bea3-4c65-b36c-90f9d63d43c3','戲題酒家壁三首  其三','陸游','宋','宋诗','song-poetry','','[]','朋舊存亡寂不聞，年年江海愴離群。',64,'全唐诗/poet.song.132000.json','["朋舊存亡寂不聞，年年江海愴離群。", "時平酒價賤如水，病起老身閑似雲。", "飽食每慚荒舊學，後生誰可付斯文。", "案頭清鏡塵昏盡，殘髮知添白幾分。"]'),
('8441bcde-d96c-45cc-8397-57baa685a157','十月二十八日夜風雨大作','陸游','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u751f\u6d3b", "\u51ac\u5929", "\u5199\u98ce", "\u98ce", "\u8d2b\u7a77"]','風怒欲拔木，雨暴欲掀屋。',96,'全唐诗/poet.song.132000.json','["風怒欲拔木，雨暴欲掀屋。", "風聲翻海濤，雨點墮車軸。", "拄門那敢開，吹火不得燭。", "豈惟漲溝溪，勢已卷平陸。", "辛勤藝宿麥，所望明年熟。", "一飽正自艱，五窮故相逐。", "南鄰更可念，布被冬未贖。", "明朝甑復空，母子相持哭。"]'),
('17011f60-7c0d-4fcd-ad72-fe5b11ad9266','夜寒燃火有感','陸游','宋','宋诗','song-poetry','','[]','墮巢拾槁枝，微火吹孤螢。',96,'全唐诗/poet.song.132000.json','["墮巢拾槁枝，微火吹孤螢。", "風火一相得，須臾細烟青。", "暖焰遂騰上，凜冽回玄冥。", "君看金鼎火，其初亦熒熒。", "至理存橐籥，奇功挾風霆。", "笑談縛三彭，指顧役六丁。", "超然出塵世，豈獨制頹齡。", "勸君勿虛死，萬過誦黄庭。"]'),
('fcc5e327-7f1e-45d6-a404-a5852230e5f0','農事休小葺東園十韵','陸游','宋','宋诗','song-poetry','','[]','歸老心常逸，新寒體亦康。',120,'全唐诗/poet.song.132000.json','["歸老心常逸，新寒體亦康。", "幸當農事隙，稍治舊園荒。", "翦闢西山出，縈回北徑長。", "作欄扶弱蔓，換土植孤芳。", "霜霰篔簹碧，風烟薜荔蒼。", "蝶來翻小翅，鳥下囀幽吭。", "疏剔巖泉集，耘鋤藥草香。", "溪藤裁酒榼，番錦製詩囊。", "坐久雲生石，歸遲月滿廊。", "人間胡不樂，拔宅笑君房。"]'),
('7540716a-ecc8-4a1c-8383-7afb55b744f8','開東園路北至山脚因治路傍隙地雜植花草六首  其一','陸游','宋','宋诗','song-poetry','','[]','清溝東畔翦蓁菅，雖設柴門盡日關。',64,'全唐诗/poet.song.132000.json','["清溝東畔翦蓁菅，雖設柴門盡日關。", "遠引寒泉成碧沼，稍通密竹露青山。", "幽花泣露開仍落，好鳥穿林去復還。", "更上橫岡吾所愛，小兒試覓屋三間。"]'),
('c488adcf-96e5-4f1e-8eaa-1dad937c9927','開東園路北至山脚因治路傍隙地雜植花草六首  其二','陸游','宋','宋诗','song-poetry','','[]','魏野林逋久已僊，放翁寄傲鏡湖邊。',64,'全唐诗/poet.song.132000.json','["魏野林逋久已僊，放翁寄傲鏡湖邊。", "松根偃蹇支琴石，巖竇潺湲洗藥泉。", "半祿掃空雖在我，殘年健甚豈非天。", "遥遥桑苧家風在，重補茶經又一編。"]'),
('7291f434-81d2-4f16-bc36-efd9dd50cf3c','開東園路北至山脚因治路傍隙地雜植花草六首  其三','陸游','宋','宋诗','song-poetry','','[]','憶自南昌返故鄉，移家來就鏡湖凉。',64,'全唐诗/poet.song.132000.json','["憶自南昌返故鄉，移家來就鏡湖凉。", "鶴雛養得沖霄漢，松樹看成任棟梁。", "手版永拋貧亦樂，肩輿時上老何妨。", "平郊東望江城近，隱隱清笳送夕陽。"]'),
('4f261e77-67ac-4ff9-af59-6ca824999110','開東園路北至山脚因治路傍隙地雜植花草六首  其四','陸游','宋','宋诗','song-poetry','','[]','父子追隨一笑傾，東園東畔路初成。',64,'全唐诗/poet.song.132000.json','["父子追隨一笑傾，東園東畔路初成。", "夾栽芳草如繩直，前出籬門似砥平。", "春近野梅香欲動，雨餘溝水細無聲。", "今朝有憙誰能識，不用人扶亦自行。"]'),
('65caef18-7207-4034-b9b9-dff65fa5bc3d','開東園路北至山脚因治路傍隙地雜植花草六首  其五','陸游','宋','宋诗','song-poetry','','[]','病眼逢人每懶開，正須此地洗氛埃。',64,'全唐诗/poet.song.132000.json','["病眼逢人每懶開，正須此地洗氛埃。", "數枝梅向林梢出，一脈泉從嶺背來。", "藤杖有時緣石磴，風爐隨處置茶杯。", "殘軀自笑如春草，又喜天邊斗柄回。"]'),
('2dc6609a-4d86-4cba-a717-a36736f2532d','開東園路北至山脚因治路傍隙地雜植花草六首  其六','陸游','宋','宋诗','song-poetry','','[]','避俗從來恨不深，家園栽種偶成陰。',64,'全唐诗/poet.song.132000.json','["避俗從來恨不深，家園栽種偶成陰。", "西連幾曲菖蒲澗，東接無窮薝蔔林。", "烏桕谷寒迎野步，金沙泉冷洗塵襟。", "清音可寫吾詩拙，它日君來試抱琴。"]'),
('f56960f1-1486-4a52-8503-447abeb1e1f1','連日治圃至山亭又作五字四首  其一','陸游','宋','宋诗','song-poetry','','[]','薙圃課僮奴，爭前不待呼。',48,'全唐诗/poet.song.132000.json','["薙圃課僮奴，爭前不待呼。", "水泉經雨壯，蓁莽得霜枯。", "高樹鳴雙鵲，清池下兩鳧。", "暮年惟樂此，餘念一毫無。"]'),
('5a94b89e-9175-4d45-89a6-1b14ea3b6937','連日治圃至山亭又作五字四首  其二','陸游','宋','宋诗','song-poetry','','[]','富貴尋常事，天奚獨汝慳。',48,'全唐诗/poet.song.132000.json','["富貴尋常事，天奚獨汝慳。", "十分教懶拙，百倍與清閑。", "放鶴雲千頃，釣魚溪一灣。", "此詩雖信筆，它日不須刪。"]'),
('1be8f4bb-cd3b-4701-abd9-467746eb4fd8','連日治圃至山亭又作五字四首  其三','陸游','宋','宋诗','song-poetry','','[]','好竹千竿翠，新泉一勺冰。',48,'全唐诗/poet.song.132000.json','["好竹千竿翠，新泉一勺冰。", "殘蕪襯落日，老木上寒藤。", "細磴欹難過，危欄曲可憑。", "歸時忽已暮，點點數漁燈。"]'),
('ffdba209-9a11-43ba-bc44-4fa7df9fb585','連日治圃至山亭又作五字四首  其四','陸游','宋','宋诗','song-poetry','','[]','門開度略彴，路盡上坡陁。',48,'全唐诗/poet.song.132000.json','["門開度略彴，路盡上坡陁。", "農隙閑耕犢，樵歸起醉歌。", "青烟舞鸞鳳，白石伏黿鼉。", "剩有筇枝興，窮冬氣已和。"]'),
('e93d0601-56cf-4a19-9228-09ac4bbf8645','寒夜','陸游','宋','宋诗','song-poetry','','[]','敗屋頹垣對短檠，課書聊自限三更。',64,'全唐诗/poet.song.132000.json','["敗屋頹垣對短檠，課書聊自限三更。", "蕭條草木寒無色，窸窣狐狸出有聲。", "半榼濁醪求火暖，一篇疑義與兒評。", "未須遽起窮愁嘆，明日尋梅雪正晴。"]'),
('1466ae18-2cf2-4f14-a836-ba9a528e06c1','掩卷有感','陸游','宋','宋诗','song-poetry','','[]','少年雖讀書，每恨性疏懶。',72,'全唐诗/poet.song.132000.json','["少年雖讀書，每恨性疏懶。", "中年頗自勵，已嘆歲月短。", "學不到聖賢，此意終未滿。", "甑空不憂饑，衣垢不思浣。", "區區管晏事，端可付一莞。", "羸然八十翁，風雪卧空館。"]'),
('7c6afc54-88a1-4375-b3fc-e568a6417ec0','閑遊','陸游','宋','宋诗','song-poetry','','[]','出雜羊牛牧，歸隨鳥雀栖。',48,'全唐诗/poet.song.132000.json','["出雜羊牛牧，歸隨鳥雀栖。", "聊持數匙飯，就乞半盂齏。", "浩蕩凌原野，崎嶇歷澗溪。", "閑遊豈不好，客意自凄凄。"]'),
('d8d1cd50-0b35-4ed9-8159-d18052793f6a','野寺','陸游','宋','宋诗','song-poetry','','[]','閑行入野寺，僧飯鼓其鏜。',48,'全唐诗/poet.song.132000.json','["閑行入野寺，僧飯鼓其鏜。", "慘慘風剺面，暉暉日滿廊。", "去來元自在，賓主兩相忘。", "却下山坡路，樵歌出隴長。"]'),
('9fe36e3d-c922-4a5b-80bb-e9fcc6052480','三江','陸游','宋','宋诗','song-poetry','','[]','三江郡東北，古戍鬰嵯峨。',48,'全唐诗/poet.song.132000.json','["三江郡東北，古戍鬰嵯峨。", "漁子船浮葉，更人鼓應鼉。", "年豐坊酒賤，盜息海商多。", "老我無豪思，悠然寄醉歌。"]'),
('7d27b889-43a0-4fa6-bcee-b696c0da14f7','讀老子','陸游','宋','宋诗','song-poetry','','[]','放翁晨興坐龜堂，古銅匜燒海南香。',112,'全唐诗/poet.song.132000.json','["放翁晨興坐龜堂，古銅匜燒海南香。", "臨目接手精思床，身如槁木心如牆。", "八十一章獨置傍，徐起開讀聲琅琅。", "怳然親見古伯陽，袂屬關尹肩庚桑。", "孰能試之出毫芒，末俗可復躋羲黄。", "陰符僞書實荒唐，稚川金丹空有方。", "人生忽如瓦上霜，勿恃强健輕年光。"]'),
('a0b146b7-0f10-4e2a-b6a9-1de2a064ea9e','新泉絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','掃石蔭雙松，岸巾穿萬竹。',24,'全唐诗/poet.song.132000.json','["掃石蔭雙松，岸巾穿萬竹。", "爾來又一奇，巖泉寒可掬。"]'),
('d4c24dad-dcd9-4fcb-a0a6-56fdda76ee7b','新泉絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','𣂏泉可瀹茗，就泉可洗藥。',24,'全唐诗/poet.song.132000.json','["𣂏泉可瀹茗，就泉可洗藥。", "楚人曾未知，但謂纓可濯。"]'),
('cc775630-d5a4-41ef-a201-7d6d25f82134','風雨','陸游','宋','宋诗','song-poetry','','[]','七十年來樂太平，白頭父子事春耕。',64,'全唐诗/poet.song.132000.json','["七十年來樂太平，白頭父子事春耕。", "因思世事悲身事，更聽風聲雜雨聲。", "四海故人强半死，一襟清泪對誰傾。", "新春要覓燒丹處，不住青城住赤城。"]'),
('a9babca1-356b-495b-a510-5611d68a92f5','題庵壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','萬疊青山繞鏡湖，數椽自愛野人居。',64,'全唐诗/poet.song.132000.json','["萬疊青山繞鏡湖，數椽自愛野人居。", "風來松度龍吟曲，雨過庭餘鳥迹書。", "小疾不妨尋酒去，豐年偶及挂冠初。", "有金可散還多事，四壁蕭然計未疏。"]'),
('4045b505-26bd-4f7b-ae03-8be75293a1e1','題庵壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','衰髮蕭疏雪滿巾，君恩乞與自由身。',64,'全唐诗/poet.song.132000.json','["衰髮蕭疏雪滿巾，君恩乞與自由身。", "身并猿鶴爲三友，家託烟波作四鄰。", "十日風號未成雪，一年梅發又催春。", "漁舟底用勤相覓，本避浮名不避人。"]'),
('e2cd2562-be89-4b60-8287-86762fb8383c','讀僊書作','陸游','宋','宋诗','song-poetry','','[]','與世已如風馬牛，松風終日聽颼飀。',64,'全唐诗/poet.song.132000.json','["與世已如風馬牛，松風終日聽颼飀。", "一爐丹熟定不死，半甕酒香安得愁。", "腰带鞓前秋萬頃，香爐峰下水交流。", "人間事事皆須命，惟有神仙可自求。"]'),
('6118ae55-1884-471f-95ed-87daf6ac11df','讀淵明詩','陸游','宋','宋诗','song-poetry','','[]','淵明甫六十，遽覺前途迮。',120,'全唐诗/poet.song.132000.json','["淵明甫六十，遽覺前途迮。", "作詩頗感槩，自謂當去客。", "吾年久過此，霜雪紛滿幘。", "豈惟僕整駕，已迫牛負軛。", "奈何不少警，玩此白駒隙。", "傾身事詩酒，廢日弄泉石。", "梅花何預汝，一笑從渠索。", "顧以有限身，兒戲作無益。", "一床寬有餘，虛室自生白。", "要當棄百事，言從老聃役。"]'),
('72475531-7418-4237-a825-78e30abf5b87','寒夜枕上','陸游','宋','宋诗','song-poetry','','[]','屋老霜寒睡不成，迢迢漏鼓過三更。',64,'全唐诗/poet.song.132000.json','["屋老霜寒睡不成，迢迢漏鼓過三更。", "烏啼林外月初上，犬吠水邊船夜行。", "市有歌呼知歲樂，亭無枹鼓喜時平。", "吾詩欲寫還慵起，卧看殘燈翳復明。"]'),
('7970ec10-0bc9-4d7c-988e-480afc1820e2','新晴出門閑步','陸游','宋','宋诗','song-poetry','','[]','一夜風號作快晴，披裘扶杖出門行。',64,'全唐诗/poet.song.132000.json','["一夜風號作快晴，披裘扶杖出門行。", "青山繞舍雪封盡，丹葉滿街霜染成。", "廢寺僧寒多晏起，近村農惰闕冬耕。", "窮人旋畫膨脝計，自買蹲鴟煮糝羹。"]'),
('4ea10482-b18a-466c-a9b5-46c46db705c4','聞笛','陸游','宋','宋诗','song-poetry','','[]','雪飛數片又成晴，透瓦清霜伴月明。',32,'全唐诗/poet.song.132000.json','["雪飛數片又成晴，透瓦清霜伴月明。", "一曲忽聞高士笛，臨窗和以讀書聲。"]'),
('730c3fa6-4faf-4f15-95f5-e177c93415b1','鳴禽','陸游','宋','宋诗','song-poetry','','[]','小徑霜泥結凍時，幽人十日廢筇枝。',32,'全唐诗/poet.song.132000.json','["小徑霜泥結凍時，幽人十日廢筇枝。", "新晴池館春來早，簾外鳴禽聖得知。"]'),
('d76759aa-573c-4759-87e9-eaee89514642','食晚','陸游','宋','宋诗','song-poetry','','[]','日高得米喚兒舂，苦雨園蔬久闕供。',32,'全唐诗/poet.song.132000.json','["日高得米喚兒舂，苦雨園蔬久闕供。", "省事家風君看取，半饑半飽過殘冬。"]'),
('73bfce4d-f130-45db-b14a-7dc13a9cb0dc','午坐戲詠','陸游','宋','宋诗','song-poetry','','[]','貯藥葫蘆二寸黄，煎茶橄欖一甌香。',32,'全唐诗/poet.song.132000.json','["貯藥葫蘆二寸黄，煎茶橄欖一甌香。", "午窗坐穩摩癡腹，始覺龜堂白日長。"]'),
('cbdaf07f-e594-4e98-8130-18dc5f1a01b0','戲詠鄉里食物示鄰曲','陸游','宋','宋诗','song-poetry','','[]','山陰古稱小蓬萊，青山萬疊環樓臺。',165,'全唐诗/poet.song.132000.json','["山陰古稱小蓬萊，青山萬疊環樓臺。", "不惟人物富名勝，所至地產皆奇瓌。", "茗芽落磑壓北苑，藥苗入饌逾天台。", "明珠百舸載芡實，火齊千擔裝楊梅。", "湘湖蓴長涎正滑，秦望蕨生拳未開。", "箭萌蟄藏待時雨，桑蕈菌蠢驚春雷。", "{糭米=木}花蒸煮蘸醯醬，薑茁披剝腌糟醅。", "細研罌粟具湯液，溼裹山蕷供炮煨。", "老饞自覺筆力短，得一忘十真堪咍。", "從今置之勿復道，一瓢陋巷師顔回。"]'),
('823b944a-c5fd-4120-a8b5-a1335724dc76','歲暮貧甚戲作','陸游','宋','宋诗','song-poetry','','[]','得米還求澗底薪，始知天地有窮人。',64,'全唐诗/poet.song.132000.json','["得米還求澗底薪，始知天地有窮人。", "年開八秩寧賒死，官及三兒不救貧。", "藥盡無如醫偃蹇，囊空那辦酒逡巡。", "柳條萱草添愁思，不似尋常見早春。"]'),
('1e990343-1a62-4873-a9c7-76ccd218b04c','汪叔潜教授挽辭','陸游','宋','宋诗','song-poetry','','[]','江南有奇士，英譽早飛騰。',96,'全唐诗/poet.song.132000.json','["江南有奇士，英譽早飛騰。", "未見心先契，相從氣倍增。", "時煩問字酒，屢共讀書燈。", "下榻延徐孺，同舟得李膺。", "百年期永好，一旦失良朋。", "稚子初何取，龍門亦許登。", "流光疾於鳥，舊社冷如冰。", "欲作千言誄，衰遲愧未能。"]'),
('f2279cca-ac1f-420c-9e4f-cb8a1ab307d0','汪給事太夫人程氏挽辭','陸游','宋','宋诗','song-poetry','','[]','爵邑恩榮盛，鄉閭譽望尊。',48,'全唐诗/poet.song.132000.json','["爵邑恩榮盛，鄉閭譽望尊。", "儒科傳累葉，上壽萃高門。", "阡茂新栽柏，堂餘舊樹萱。", "故民何以報，沾灑望秋原。"]'),
('011800f4-9171-428c-b1a2-b76ce4203c7f','太恭人諭氏挽辭','陸游','宋','宋诗','song-poetry','','[]','耄齒人誰及，高門世共榮。',48,'全唐诗/poet.song.132000.json','["耄齒人誰及，高門世共榮。", "始終膺備福，稚老遇昇平。", "綸綍褒嘉事，鄉閭惻愴情。", "吾詩儻傳世，亦足見平生。"]'),
('4423e3eb-0249-42bb-8b8d-b4325bdc2c72','路乾','陸游','宋','宋诗','song-poetry','','[]','日曬霜融步步泥，旬餘不到石泉西。',32,'全唐诗/poet.song.132000.json','["日曬霜融步步泥，旬餘不到石泉西。", "連朝和暖得乾路，喚取鄰翁來杖藜。"]'),
('4745d298-c661-4181-bcd4-dc225c43b8b6','寒夜','陸游','宋','宋诗','song-poetry','','[]','閉戶歲云暮，翻書夜向闌。',48,'全唐诗/poet.song.132000.json','["閉戶歲云暮，翻書夜向闌。", "足僵知火盡，目鈍覺燈殘。", "躍浦魚驚獺，穿林犬逐獾。", "三年納微祿，無愧得心安。"]'),
('3541b1ae-0754-456e-b9f9-2ff9f02f301a','乍晴至園中','陸游','宋','宋诗','song-poetry','','[]','藥笈漁竿每自隨，枯筇短帽恰相宜。',64,'全唐诗/poet.song.132000.json','["藥笈漁竿每自隨，枯筇短帽恰相宜。", "投林但有窮猿喜，伏櫪元無老驥悲。", "巖溜甘寒通碧沼，野梅清絕隔疏籬。", "放翁老甚情懷懶，那辦題詩寄所思。"]'),
('9a4b4d68-5bcf-4f44-b6c2-e966a4d89c57','十二月三日夜橋上看月','陸游','宋','宋诗','song-poetry','','[]','常時新月有無間，今夕清暉抵半環。',32,'全唐诗/poet.song.132000.json','["常時新月有無間，今夕清暉抵半環。", "柳外橋高最堪望，憑闌目送下西山。"]'),
('6cced75b-09f8-4b58-a09a-522dab9fca7a','流年','陸游','宋','宋诗','song-poetry','','[]','流年及耄敢前期，浮世如漚只自知。',64,'全唐诗/poet.song.132000.json','["流年及耄敢前期，浮世如漚只自知。", "多貯閑愁持抵酒，剩遊好景擬供詩。", "海東藥到寬衰疾，岷下書稀愴別離。", "約束春盤莫草草，又當梅發兩京時。"]'),
('a8918c22-ae2c-4ae3-8f3b-a903ca418009','山家五首  其一','陸游','宋','宋诗','song-poetry','','[]','風月寬閑地，溪山隱遯身。',48,'全唐诗/poet.song.132000.json','["風月寬閑地，溪山隱遯身。", "雲邊安井臼，竹裏過比鄰。", "洗朮分巖瀑，烹芝束澗薪。", "柴門敲不應，疑是避秦人。"]'),
('5888ff86-12a4-4e30-a11f-d20351b090fd','山家五首  其二','陸游','宋','宋诗','song-poetry','','[]','種藥爲生業，彈琴悅性靈。',48,'全唐诗/poet.song.132000.json','["種藥爲生業，彈琴悅性靈。", "中宵煮白石，平旦誦黄庭。", "茶熟眠初起，兒扶酒半醒。", "意行無定處，猿鳥共忘形。"]'),
('ab15dc95-b3a7-474c-b3c7-2a8f74a03cd1','山家五首  其三','陸游','宋','宋诗','song-poetry','','[]','長生固非道，得道自長生。',48,'全唐诗/poet.song.132000.json','["長生固非道，得道自長生。", "書不傳關尹，言誰契廣成。", "羅浮觀日出，句曲聽松聲。", "聞說長安好，何妨醉太平。"]'),
('6b74e4fc-be97-409c-9c2f-4b88e63e14ca','山家五首  其四','陸游','宋','宋诗','song-poetry','','[]','陶葛金丹訣，千年秘不傳。',48,'全唐诗/poet.song.132000.json','["陶葛金丹訣，千年秘不傳。", "人皆肖天地，世豈乏神仙。", "擾擾生趨死，悠悠食復眠。", "微言誰復領，浩嘆撫遺編。"]'),
('8e3b7054-3917-42cc-923a-b460a113a0f0','山家五首  其五','陸游','宋','宋诗','song-poetry','','[]','清絕更誰如，松風小閣虛。',48,'全唐诗/poet.song.132000.json','["清絕更誰如，松風小閣虛。", "氎巾參几杖，鶴毳落琴書。", "新鑿淘丹井，常携斸藥鉏。", "身閑隨處樂，何况是吾廬。"]'),
('d8c57099-d1ee-4b28-92f2-d04645776580','小舟白竹篷蓋保長所乘也偶借至近村戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','茅簷細雨溼炊烟，江路清寒欲雪天。',32,'全唐诗/poet.song.132000.json','["茅簷細雨溼炊烟，江路清寒欲雪天。", "不愛相公金絡馬，羨他亭長白篷船。"]'),
('ff6ba5e3-b035-449e-98ea-77f251f0be92','小舟白竹篷蓋保長所乘也偶借至近村戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','雪雲無際暗長空，小市孤村禹廟東。',32,'全唐诗/poet.song.132000.json','["雪雲無際暗長空，小市孤村禹廟東。", "一段荒寒端可畫，白篷籠底白頭翁。"]'),
('e664f370-ab04-4385-83a7-8fbd803cae54','稻飯','陸游','宋','宋诗','song-poetry','','[]','買得烏犍遇歲穰，此身永免屬官倉。',32,'全唐诗/poet.song.132000.json','["買得烏犍遇歲穰，此身永免屬官倉。", "塘南塘北九千頃，八月村村稻飯香。"]'),
('a78ce0e0-ffd1-4808-9550-590129dd3dd5','殘臘二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘臘無多寒漸薄，新春已近日微長。',64,'全唐诗/poet.song.132000.json','["殘臘無多寒漸薄，新春已近日微長。", "棋枰散後軒窗靜，梅塢歸來襟袖香。", "海霧籠山青淡淡，河堤潴水白茫茫。", "鷺飛前導生遊興，笑岸綸巾上野航。"]'),
('8c14bff6-0e4d-4c14-add6-c1fc26192627','殘臘二首  其二','陸游','宋','宋诗','song-poetry','','[]','殘臘去春纔十日，衰翁告老已三年。',64,'全唐诗/poet.song.132000.json','["殘臘去春纔十日，衰翁告老已三年。", "乳糜但喜分香鉢，銀勝那思映綵鞭。", "萬里當時嗟漫浪，一窗此日困沉綿。", "清泉白石無人到，且結梅花淡淡緣。"]'),
('59fa4091-87c9-40f4-9695-67dd1a4e68cf','書志','陸游','宋','宋诗','song-poetry','','[]','著書汗馬牛，不如守道力。',120,'全唐诗/poet.song.132000.json','["著書汗馬牛，不如守道力。", "賣文取卿相，詎是儒者職。", "孔光豈不學，千載汙簡冊。", "通塞本細事，于我奚失得。", "袁安卧空廬，亦度風雪夕。", "如何慕溫飽，撓節不自惜。", "我突無炊烟，或至日中昃。", "小兒抱遺經，衣短兩脛赤。", "吟誦何琅琅，聲如出金石。", "掩卷語乃翁，聖有陳蔡厄。"]'),
('dad86d53-14c0-44a9-8ee5-c181c6b38583','數日不出門偶賦三首  其一','陸游','宋','宋诗','song-poetry','','[]','衰甚身如作繭蠶，經旬不省出茅庵。',64,'全唐诗/poet.song.132000.json','["衰甚身如作繭蠶，經旬不省出茅庵。", "老僧遣信分茶串，隱士敲門致酒甔。", "看鶴松陰賞高潔，疏泉石罅得清甘。", "地偏心遠無車馬，賴有吾兒與劇談。"]'),
('891acee0-5ded-4535-b658-02344a4b264b','數日不出門偶賦三首  其二','陸游','宋','宋诗','song-poetry','','[]','十二年來一日同，飯蔬略似誦經翁。',64,'全唐诗/poet.song.132000.json','["十二年來一日同，飯蔬略似誦經翁。", "居家不擬依鄰富，報國惟思祝歲豐。", "冰澗乍通寒溜碧，蘭叢新放露芽紅。", "閑門萬化俱觀盡，那用瞿曇更說空。"]'),
('6cb4bbf9-482b-471b-9bbd-4f51c39498c3','數日不出門偶賦三首  其三','陸游','宋','宋诗','song-poetry','','[]','湖上蝸廬僅自容，寸懷無奈百憂攻。',64,'全唐诗/poet.song.132000.json','["湖上蝸廬僅自容，寸懷無奈百憂攻。", "補衣未竟迫秋露，待飯不來聞午鐘。", "稚子挾書勤質問，鄰翁釋耒間過從。", "今朝一笑君知否，滿甕新醅粥面醲。"]'),
('afb7a558-f68b-4e32-abf8-447e166ad10d','寄題嚴居厚伴釣軒','陸游','宋','宋诗','song-poetry','','[]','人生有至樂，莫若江湖中。',96,'全唐诗/poet.song.132000.json','["人生有至樂，莫若江湖中。", "千錢買短胕，青箬織孤篷。", "潮生鼓棹去，烟波浩無窮。", "長歌送夕陽，回首萬事空。", "伴釣君已奇，我乃真釣翁。", "君出羊裘家，散人亦吾宗。", "一見即定交，正以氣味同。", "何時溪莊路，共醉蘆花風。"]'),
('ad65794f-aa90-4815-abf8-82af321a61d3','寄趙昌甫并簡徐斯遠','陸游','宋','宋诗','song-poetry','','[]','我詩非大手，我酒亦小戶。',108,'全唐诗/poet.song.132000.json','["我詩非大手，我酒亦小戶。", "得游名勝間，獨以用心苦。", "趙子乃宿士，山立誰敢侮。", "寓名祝融祠，蓑笠卧烟雨。", "高吟三千篇，一字無塵土。", "朱先少許可，書每說昌甫。", "雖云忍饑瘦，得喪亦相補。", "嗟君與斯遠，文中真二虎。", "我老日益衰，想像氣如縷。"]'),
('e56f6568-90e7-4ec1-abb4-c7e4f653c1fe','南園觀梅','陸游','宋','宋诗','song-poetry','','[]','幽徑疏籬洗世塵，眼明見此數枝新。',64,'全唐诗/poet.song.132000.json','["幽徑疏籬洗世塵，眼明見此數枝新。", "橫斜恰受三更月，璀璨先回萬物春。", "洛浦凌波矜絕態，緱山騎鶴想前身。", "放翁著句煩君記，畫在生綃却未真。"]'),
('26ec3b24-7eee-4396-a1e2-d50adab70cca','老身','陸游','宋','宋诗','song-poetry','','[]','老身無處著，登望憶閑遊。',48,'全唐诗/poet.song.132000.json','["老身無處著，登望憶閑遊。", "白浪浮天遠，黄雲出塞秋。", "百年殊鼎鼎，萬事只悠悠。", "歲晚長亭路，寒侵季子裘。"]'),
('c4fc70e4-74b6-44a7-bf2b-2cd7068f2745','獨處','陸游','宋','宋诗','song-poetry','','[]','老夫閉門衰疾嬰，小兒適有南山行。',96,'全唐诗/poet.song.132000.json','["老夫閉門衰疾嬰，小兒適有南山行。", "一奴入市暮未返，愔愔不聞鳥雀鳴。", "地爐火死凍脚硬，欲作薄粥愁空鎗。", "平生遣日賴詩句，久矣無復吟哦聲。", "但餘一點真正念，照了萬象猶精明。", "欲論此事向何許，眾中倘遇千人英。"]'),
('b88a8753-8bdc-44fc-85bd-7a8d3d46d6ae','醉中歌','陸游','宋','宋诗','song-poetry','','[]','文章日益近衰陋，風節久己嗟陵夷。',64,'全唐诗/poet.song.132000.json','["文章日益近衰陋，風節久己嗟陵夷。", "元祐大蘇逝不返，慶曆小范今誰知。", "閉門學古人共笑，低頭就俗我却疑。", "脫衣幸可買漁艇，爛醉浩歌隨所之。"]'),
('b7bbddad-acf5-49e4-92e3-7aa133d5c3fd','排悶','陸游','宋','宋诗','song-poetry','','[]','人間歲月莽悠悠，老大悲傷只涕流。',64,'全唐诗/poet.song.132000.json','["人間歲月莽悠悠，老大悲傷只涕流。", "民饜糟糠寧細事，俗忘節義更深憂。", "潦歸宿麥猶難望，雪少同雲未易求。", "自嘆此生真已矣，且偷暇日弄孤舟。"]'),
('21666d65-c4ef-4e69-8926-96186d6b8c51','庚申十二月二十一日西和州健步持子布書報已取安康襄陽路將至九江矣悲喜交懷作長句二首  其一','陸游','宋','宋诗','song-poetry','','[]','吳蜀相望萬里程，征鞍忽報近湓城。',64,'全唐诗/poet.song.132000.json','["吳蜀相望萬里程，征鞍忽報近湓城。", "角巾已入三更夢，老眼先增十倍明。", "告至徧爲親舊問，勞還深愧里閭情。", "追思二紀睽離事，憙極翻成涕泗橫。"]'),
('68d13f86-2a3d-40f3-b636-667b4cb53c6e','庚申十二月二十一日西和州健步持子布書報已取安康襄陽路將至九江矣悲喜交懷作長句二首  其二','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','萬里東來雙鯉魚，衰翁悲喜得兒書。',64,'全唐诗/poet.song.132000.json','["萬里東來雙鯉魚，衰翁悲喜得兒書。", "聞過峴首已冬至，想到匡廬將歲除。", "辛苦山行穿雪履，凄凉旅飯嚼冰蔬。", "此行身歷艱難遍，莫厭東皋共荷鉏。"]'),
('18a81ed1-bcf6-48b7-b607-833087f3b771','園中作','陸游','宋','宋诗','song-poetry','','[]','幽禽啼不去，紅蕊落還開。',48,'全唐诗/poet.song.132000.json','["幽禽啼不去，紅蕊落還開。", "意適時時醉，身閑日日來。", "著書增水品，披句覓榿栽。", "消息吾兒近，扶衰又上臺。"]'),
('1ac7aa93-9bab-4e97-8150-aff2e8cc8418','足疾','陸游','宋','宋诗','song-poetry','','[]','足疾惟妨拜，登臨故自如。',48,'全唐诗/poet.song.132000.json','["足疾惟妨拜，登臨故自如。", "深知造物意，遣遂此心初。", "東塢閑看竹，西溪獨釣魚。", "暮歸猶未倦，把卷繞前除。"]'),
('c1c4d7d7-76e7-4e18-b33e-195c1cf64a32','歲暮書懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','世事從來不可常，把茆猶幸得深藏。',64,'全唐诗/poet.song.132000.json','["世事從來不可常，把茆猶幸得深藏。", "床頭酒甕寒難熟，瓶裏梅花夜更香。", "薄命元知等蟬翼，畏途何處不羊腸。", "詩成讀罷仍無用，聊滿山家骨董囊。"]'),
('c9c55f30-78d3-4eb9-aa5e-8dc86f9e7bc1','歲暮書懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','憶昔初辭鵷鷺行，慨然誓墓老耕桑。',64,'全唐诗/poet.song.132000.json','["憶昔初辭鵷鷺行，慨然誓墓老耕桑。", "蓼汀夜宿夢魂爽，梅塢暮歸襟袖香。", "窮巷每多閑日月，小兒時誦古文章。", "吾儕窮死從來事，敢變胸中百鍊剛。"]'),
('12af0cd3-ae62-4bf0-a0fb-2774310e0dbb','除夜','陸游','宋','宋诗','song-poetry','','[]','守歲全家夜不眠，杯盤狼藉向燈前。',32,'全唐诗/poet.song.132000.json','["守歲全家夜不眠，杯盤狼藉向燈前。", "相看更覺光陰速，笑語逡巡即隔年。"]'),
('c6f23c46-05b4-40a5-ac82-231a8dd006f4','修路','陸游','宋','宋诗','song-poetry','','[]','雨霪道壞困泥塗，木石紛然賴里閭。',32,'全唐诗/poet.song.132000.json','["雨霪道壞困泥塗，木石紛然賴里閭。", "但使僅堪行便足，我無長戟與高車。"]'),
('a071f2c0-ed02-4be1-8689-1694630b859b','金丹','陸游','宋','宋诗','song-poetry','','[]','子有金丹鍊即成，人人各自具長生。',64,'全唐诗/poet.song.132000.json','["子有金丹鍊即成，人人各自具長生。", "施行要使俗仁壽，收斂猶能心太平。", "劇飲似鯨身不倦，細書如蟻眼常明。", "更餘一事君難學，富貴真同涕唾輕。"]'),
('d4f4e2b1-c6af-4b03-ae2f-74a0ae3001b7','平昔','陸游','宋','宋诗','song-poetry','','[]','平昔飄然林下僧，更堪衰與病相乘。',64,'全唐诗/poet.song.132000.json','["平昔飄然林下僧，更堪衰與病相乘。", "殘年已任身生死，一念猶關道廢興。", "皎皎初心質天地，兢兢晚節蹈淵冰。", "子孫勿厭藜羹薄，此是吾家無盡燈。"]'),
('cf93ef08-8f95-4fb7-9073-ca9e02aa5346','二月三日春色粲然步至湖上','陸游','宋','宋诗','song-poetry','','[]','不愧衰翁雪鬢新，出門也復整烏巾。',64,'全唐诗/poet.song.132000.json','["不愧衰翁雪鬢新，出門也復整烏巾。", "梅花隔水香撩客，野鳥穿林語喚人。", "長日難消惟泥酒，災年不死又違春。", "吾兒已到新安未，想掬清溪洗客塵。"]'),
('2c502035-f400-4db3-87cf-f630f020d310','計子布歸程已過新安入畿縣界','陸游','宋','宋诗','song-poetry','','[]','憶昔初登下峽船，一回望汝一凄然。',64,'全唐诗/poet.song.132000.json','["憶昔初登下峽船，一回望汝一凄然。", "夢魂南北略萬里，人世短長無百年。", "强遣老懷終兀兀，忽聞歸騎已翩翩。", "今朝屈指無窮喜，歷盡江山近日邊。"]'),
('4208f654-db85-4d8d-993d-6e3c457eabb2','東園觀梅','陸游','宋','宋诗','song-poetry','','[]','出世仙姝下草堂，高標肯學漢宮妝。',64,'全唐诗/poet.song.132000.json','["出世仙姝下草堂，高標肯學漢宮妝。", "數苞冷蕊愁渾破，一寸殘枝夢亦香。", "問訊不嫌泥濺屐，端相每到月侵廊。", "高樓吹角成何事，只替詩人說斷腸。"]'),
('28cb328f-c412-44b0-a235-9422c589a280','喜得建茶','陸游','宋','宋诗','song-poetry','','[]','玉食何由到草萊，重奩初喜坼封開。',64,'全唐诗/poet.song.132000.json','["玉食何由到草萊，重奩初喜坼封開。", "雪霏庾嶺紅絲磑，乳泛閩溪綠地材。", "舌本常留甘盡日，鼻端無復鼾如雷。", "故應不負朋遊意，手挈風爐竹下來。"]'),
('05aff281-f6e3-4f05-9568-75b0c6ad7a82','春雨','陸游','宋','宋诗','song-poetry','','[]','細雨吞平野，餘寒勒早春。',48,'全唐诗/poet.song.132000.json','["細雨吞平野，餘寒勒早春。", "未增豪飲興，先著苦吟身。", "幽徑萱芽短，方橋柳色新。", "閉門非爲老，半世是閑人。"]'),
('c11bf38a-4b3e-4058-b958-d6355f2b82d9','春雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','擁被聽春雨，殘燈一點青。',24,'全唐诗/poet.song.132000.json','["擁被聽春雨，殘燈一點青。", "吾兒歸漸近，何處宿長亭。"]'),
('f22a1d98-2615-464d-9aaf-9976af015506','春雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','湖上新春柳，摇摇欲喚人。',24,'全唐诗/poet.song.132000.json','["湖上新春柳，摇摇欲喚人。", "多情今夜雨，先洗馬蹄塵。"]'),
('65c0f283-0ef4-4d36-bf98-428703fee843','初春感事二首  其一','陸游','宋','宋诗','song-poetry','','[]','馬迹車聲是處忙，經旬無客到龜堂。',64,'全唐诗/poet.song.132000.json','["馬迹車聲是處忙，經旬無客到龜堂。", "水初泛溢黏天綠，梅欲飄零特地香。", "世事紛紛人自老，歲華冉冉日初長。", "百錢不辦旗亭醉，空愛鵝兒似酒黄。"]'),
('9eda4c5c-795f-4fba-a2df-4d4c71b26d28','初春感事二首  其二','陸游','宋','宋诗','song-poetry','','[]','一樹紅梅已半殘，破裘也復敵春寒。',64,'全唐诗/poet.song.132000.json','["一樹紅梅已半殘，破裘也復敵春寒。", "忍窮過日却差易，負愧終身良獨難。", "活火靜看茶鼎熟，清泉自注研池寬。", "人生樂處君知否，萬事當從心所安。"]'),
('5b7e4666-2adc-45f8-830e-f19635a9c2eb','道室書事','陸游','宋','宋诗','song-poetry','','[]','五十餘年讀道書，老來所得定何如。',64,'全唐诗/poet.song.132000.json','["五十餘年讀道書，老來所得定何如。", "目光焰焰夜穿帳，胎髮青青晨映梳。", "甚畏蝮蛇寧斷手，已烹熊掌敢兼魚。", "春蕪二畝扶犁去，空憶高皇賜對初。"]'),
('6b0d840d-6b22-45b5-9378-2d6dbca9e960','先少師宣和初有贈晁公以道詩云奴愛才如蕭頴士婢知詩似鄭康成晁公大愛賞今逸全篇偶讀晁公文集泣而足之','陸游','宋','宋诗','song-poetry','','[]','仕不逢時勇退耕，閉門自號景迂生。',64,'全唐诗/poet.song.132000.json','["仕不逢時勇退耕，閉門自號景迂生。", "遠聞佳士輒心許，老見異書猶眼明。", "奴愛才如蕭頴士，婢知詩似鄭康成。", "早孤遇事偏多感，欲續殘章涕已傾。"]'),
('d3bf5bc0-7961-4ba4-a717-952ef6586489','春日雜題六首  其一','陸游','宋','宋诗','song-poetry','','[]','梅花三十本，圍以疏竹籬。',48,'全唐诗/poet.song.132000.json','["梅花三十本，圍以疏竹籬。", "入春甫十日，開遍南北枝。", "少年輕節物，老大復苦衰。", "坐見零落盡，一杯初未持。"]'),
('0d1c14c2-149e-463b-af53-326fc32076c3','春日雜題六首  其二','陸游','宋','宋诗','song-poetry','','[]','春雨路易乾，雨止即可行。',48,'全唐诗/poet.song.132000.json','["春雨路易乾，雨止即可行。", "梅花落無餘，蘭芽亦已生。", "好鳥何山來，向我飛復鳴。", "行矣東郊路，藉草作清明。"]'),
('7c0920b5-8d69-4615-9f9c-4ea66674be7d','春日雜題六首  其三','陸游','宋','宋诗','song-poetry','','[]','野水如棋枰，所至各成村。',48,'全唐诗/poet.song.132000.json','["野水如棋枰，所至各成村。", "炊烟出茆屋，碓聲隔柴門。", "樹陰同戲兒，多已長子孫。", "安居無暴斂，何以報國恩。"]'),
('058c25b0-2927-4098-85e1-a448e9bea731','春日雜題六首  其四','陸游','宋','宋诗','song-poetry','','[]','春陰不成雨，正作卵色天。',48,'全唐诗/poet.song.132000.json','["春陰不成雨，正作卵色天。", "花開路無塵，楊柳摇輕烟。", "佳哉冷淘時，槐芽雜豚肩。", "長安墮胡虜，况說野狐泉。"]'),
('b0999d9d-9fb0-4907-a779-081b2862e4d0','春日雜題六首  其五','陸游','宋','宋诗','song-poetry','','[]','客路行無窮，漁唱聽不厭。',48,'全唐诗/poet.song.132000.json','["客路行無窮，漁唱聽不厭。", "濤江西限吳，雲岫南入剡。", "蹇驢過小市，高柳擁孤店。", "去去望前村，鴉歸烟欲斂。"]'),
('d414657a-b517-4c9d-a050-78576b0bb551','春日雜題六首  其六','陸游','宋','宋诗','song-poetry','','[]','蒲柳深復淡，桃李白間紅。',48,'全唐诗/poet.song.132000.json','["蒲柳深復淡，桃李白間紅。", "東皇一稅駕，萬物酣春風。", "烟村在何許，小屏團扇中。", "一笑喚稚子，相扶上短篷。"]'),
('3e038057-2b58-4ef6-b8d2-1bd2517e3f83','春日暄甚戲作','陸游','宋','宋诗','song-poetry','','[]','桃杏酣酣蜂蝶狂，兒童相喚踏春陽。',32,'全唐诗/poet.song.132000.json','["桃杏酣酣蜂蝶狂，兒童相喚踏春陽。", "老人自笑還多事，預恐明朝雨壞牆。"]'),
('9d3ce643-ed8e-41b1-86bf-f93884725630','春日','陸游','宋','宋诗','song-poetry','','[]','遲日園林嘗煮酒，和風庭院㫰新絲。',64,'全唐诗/poet.song.132000.json','["遲日園林嘗煮酒，和風庭院㫰新絲。", "已過燕子穿簾後，又見鮰魚上市時。", "排悶與兒聯小句，破閑留客戰枯棋。", "殘年自覓安排處，除却歸休總不宜。"]'),
('25610309-f75f-409b-bccd-968b48d699cd','書室獨夜','陸游','宋','宋诗','song-poetry','','[]','忽忽新春過，愔愔一室幽。',48,'全唐诗/poet.song.132000.json','["忽忽新春過，愔愔一室幽。", "銅燈立雁趾，石鼎揭龍頭。", "老愧人扶拜，貧無食足謀。", "退居消日月，太半付莊周。"]'),
('207381e7-8c30-49de-9602-d823de1ad4ae','追感往事五首  其一','陸游','宋','宋诗','song-poetry','','[]','太平翁翁十九年，父子氣焰可熏天。',32,'全唐诗/poet.song.132000.json','["太平翁翁十九年，父子氣焰可熏天。", "不如茅舍醉村酒，日與鄰翁相枕眠。"]'),
('acd8abc2-8bee-4694-9c78-5437ed55ef20','追感往事五首  其二','陸游','宋','宋诗','song-poetry','','[]','世事紛紛過眼新，九衢依舊漲紅塵。',32,'全唐诗/poet.song.132000.json','["世事紛紛過眼新，九衢依舊漲紅塵。", "桃花夢破劉郎老，燕麥摇風別是春。"]'),
('4250d2bd-5078-4570-b7fc-46958cfa72d1','追感往事五首  其三','陸游','宋','宋诗','song-poetry','','[]','渡江之初不暇給，諸老文辭今尚傳。',32,'全唐诗/poet.song.132000.json','["渡江之初不暇給，諸老文辭今尚傳。", "六十年間日衰靡，此事安可付之天。"]'),
('2974c00d-2cfa-4afb-b818-738ff789bdde','追感往事五首  其四','陸游','宋','宋诗','song-poetry','','[]','文章光焰伏不起，甚者自謂宗晚唐。',32,'全唐诗/poet.song.132000.json','["文章光焰伏不起，甚者自謂宗晚唐。", "歐曾不生二蘇死，我欲痛哭天茫茫。"]'),
('626aa8fc-33de-4c88-9f1a-d2417747ce53','追感往事五首  其五','陸游','宋','宋诗','song-poetry','','[]','諸公可嘆善謀身，誤國當時豈一秦。',32,'全唐诗/poet.song.132000.json','["諸公可嘆善謀身，誤國當時豈一秦。", "不望夷吾出江左，新亭對泣亦無人。"]'),
('e6c14311-a203-4e27-be69-154403a92fc8','書意二首  其一','陸游','宋','宋诗','song-poetry','','[]','我本三生世外人，幻軀其實强冠巾。',64,'全唐诗/poet.song.132000.json','["我本三生世外人，幻軀其實强冠巾。", "稍能閉戶學種菜，時亦長歌行負薪。", "一醉却非身外事，百年終是冢中塵。", "君知夢境無根底，莫信人言想與因。"]'),
('37ddbefc-8f66-4dcd-9a8a-3cb2b1f1c56b','書意二首  其二','陸游','宋','宋诗','song-poetry','','[]','病眼猶堪閱世人，難將雪鬢著烏巾。',64,'全唐诗/poet.song.132000.json','["病眼猶堪閱世人，難將雪鬢著烏巾。", "囊中錢盡罷沽酒，澗底雨寒愁束薪。", "老子那辭徙牛屋，癡人自喜拜車塵。", "窮通要是兒嬉事，懶就山僧講宿因。"]'),
('3e0fad32-9bf4-4099-9f85-cf7f72414b20','清都行','陸游','宋','宋诗','song-poetry','','[]','積雨初收曉寒重，野人忽作清都夢。',96,'全唐诗/poet.song.132000.json','["積雨初收曉寒重，野人忽作清都夢。", "宮牆柳色綠如染，仰視修門岌飛動。", "元章久已葬岷山，安得翩翩並馳鞚。", "春光如昔交舊少，肺肝欲寫誰堪共。", "頗聞天閽有疑事，通明殿下方僉議。", "約君切勿負初心，天上人間均一是。"]'),
('3d06b4d3-c215-4c68-a313-e786ed241ade','春來食不繼戲作','陸游','宋','宋诗','song-poetry','','[]','久卧窮閻困負薪，何妨掃盡太倉陳。',64,'全唐诗/poet.song.132000.json','["久卧窮閻困負薪，何妨掃盡太倉陳。", "瘦如飯顆吟詩面，饑似柴桑乞食身。", "犧象未應殊斷木，江湖底處有窮鱗。", "大冠長劍人看好，不換茅簷一幅巾。"]'),
('ec5607f6-f214-4b0a-b65a-27f5c408a119','紹興辛酉予年十七矣距今已六十年追感舊事作絕句','陸游','宋','宋诗','song-poetry','','[]','常憶初年十七時，朝朝烏帽出從師。',32,'全唐诗/poet.song.132000.json','["常憶初年十七時，朝朝烏帽出從師。", "忽逢寒食停供課，正寫礬書作贗碑。"]'),
('a72ab130-f891-414e-9ff1-0194f95a29bd','獨坐視老奴灌園','陸游','宋','宋诗','song-poetry','','[]','東窗日晚獨愁予，眼闇年來頗廢書。',32,'全唐诗/poet.song.132000.json','["東窗日晚獨愁予，眼闇年來頗廢書。", "賴有吾家老阿對，相從引水灌園蔬。"]'),
('267d2b4b-8f97-4d73-b12a-19ddf790bdfb','雨晴風日絕佳徙倚門外三首  其一','陸游','宋','宋诗','song-poetry','','[]','一雙芒屩伴筇枝，不用兒扶自出嬉。',32,'全唐诗/poet.song.132000.json','["一雙芒屩伴筇枝，不用兒扶自出嬉。", "貪看南山雲百變，舍西溪上立多時。"]'),
('f8340bd3-5f4b-4731-b2de-7710bf5b2ca4','雨晴風日絕佳徙倚門外三首  其二','陸游','宋','宋诗','song-poetry','','[]','茶釅無端廢午眠，杖藜信步到門前。',32,'全唐诗/poet.song.132000.json','["茶釅無端廢午眠，杖藜信步到門前。", "青裙溪女結蠶卦，白髮廟巫催社錢。"]'),
('2e85a650-dccb-4705-a7ec-2089b7bc0620','雨晴風日絕佳徙倚門外三首  其三','陸游','宋','宋诗','song-poetry','','[]','章老三年病方死，吳翁一夕呼不醒。',32,'全唐诗/poet.song.132000.json','["章老三年病方死，吳翁一夕呼不醒。", "獨有此身頑似鐵，倚門常看暮山青。"]'),
('0f2af333-f61b-4c55-b2d8-2c51fcc0aa01','春遊','陸游','宋','宋诗','song-poetry','','[]','春風堤上草萋萋，草軟沙平護馬蹄。',64,'全唐诗/poet.song.132000.json','["春風堤上草萋萋，草軟沙平護馬蹄。", "似蓋微雲纔障日，如絲細雨不成泥。", "千秋觀裏逢新燕，九里山前聽午雞。", "追憶舊遊愁滿眼，綵船曾繫畫橋西。"]'),
('10236ead-f760-4b11-a123-5ea855ab9e32','春雨三首  其一','陸游','宋','宋诗','song-poetry','','[]','狼藉殘花滿地紅，擁衾孤夢雨聲中。',64,'全唐诗/poet.song.132000.json','["狼藉殘花滿地紅，擁衾孤夢雨聲中。", "人生十事九堪嘆，春色三分二已空。", "但有老盆傾濁酒，不辭衰鬢對青銅。", "長貧博得身强健，久矣無心咎化工。"]'),
('832cc669-7f1f-4841-812c-e929de4d161f','春雨三首  其二','陸游','宋','宋诗','song-poetry','','[]','藥爐茶竈淡生涯，聽雨猶能惜物華。',64,'全唐诗/poet.song.132000.json','["藥爐茶竈淡生涯，聽雨猶能惜物華。", "蘸岸頓添三尺水，沾泥不貸一城花。", "閑摩病眼開書卷，時傍危欄弄釣車。", "稚子孤行八千里，喜聞炊熟可還家。"]'),
('ca69b9e5-f059-4a82-b295-ba36c8e62c08','春雨三首  其三','陸游','宋','宋诗','song-poetry','','[]','自笑平生懶是真，閉門高枕動兼旬。',64,'全唐诗/poet.song.132000.json','["自笑平生懶是真，閉門高枕動兼旬。", "海棠千片已隨水，杜宇一聲無復春。", "綠酒盈樽足忘老，朱櫻上市正嘗新。", "今朝雨止通溪路，又向沙頭岸幅巾。"]'),
('72b41d6e-58a5-47d3-af2d-0c4b13d0a06c','書懷','陸游','宋','宋诗','song-poetry','','[]','謝客元無疾，深居似有憂。',48,'全唐诗/poet.song.132000.json','["謝客元無疾，深居似有憂。", "向空書咄咄，對竹送悠悠。", "出每思安卧，歸還念遠遊。", "春衣典已慣，斗酒不難謀。"]'),
('92087446-06d3-46f9-8142-852feb01ee23','三月十六日至柯橋迎子布東還二首  其一','陸游','宋','宋诗','song-poetry','','[]','江國常年秋雁飛，吾兒遠客寄書稀。',64,'全唐诗/poet.song.132000.json','["江國常年秋雁飛，吾兒遠客寄書稀。", "道途一見相持泣，鄰曲聚觀同載歸。", "草草杯盤更起舞，匆匆刀尺旋裁衣。", "從今父子茅簷下，回首人間萬事非。"]'),
('8b09b69b-1b96-4d1c-b79a-ca1a55dcd0f2','三月十六日至柯橋迎子布東還二首  其二','陸游','宋','宋诗','song-poetry','','[]','我似傷禽带箭飛，更憐汝作雁行稀。',64,'全唐诗/poet.song.132000.json','["我似傷禽带箭飛，更憐汝作雁行稀。", "異時恐抱終身恨，此日寧知徒步歸。", "萬里外應勞遠夢，三年前已挂朝衣。", "斷編蠹簡相從老，絕念功名亦未非。"]'),
('03fbe75f-6cfb-4a4a-9cf8-ce8ee0fe6d6e','題施武子所藏楊補之梅','陸游','宋','宋诗','song-poetry','','[]','補之寫生梅，至簡亦半樹。',24,'全唐诗/poet.song.132000.json','["補之寫生梅，至簡亦半樹。", "此幅獨不然，豈畫橫斜句。"]'),
('46b655ec-b2d5-4901-a1c2-2647c25d3920','食野菜二首  其一','陸游','宋','宋诗','song-poetry','','[]','野蔌山蔬次第嘗，超然氣壓大官羊。',32,'全唐诗/poet.song.132000.json','["野蔌山蔬次第嘗，超然氣壓大官羊。", "放翁此意君知否，要配吳粳曉甑香。"]'),
('63b8cdc3-b90e-454f-9901-b3cb04d8cfaa','食野菜二首  其二','陸游','宋','宋诗','song-poetry','','[]','萬里蕭條酒一杯，夢魂猶自度邛郲。',32,'全唐诗/poet.song.132000.json','["萬里蕭條酒一杯，夢魂猶自度邛郲。", "可憐龍鶴山中菜，不伴峨眉栮脯來。"]'),
('de592189-3192-48e0-865a-2ffc97dc4bb0','予十許歲即往來雲門諸山今復與諸子來追念凄然','陸游','宋','宋诗','song-poetry','','[]','經行猶記髧髦初，所至渾如過故墟。',64,'全唐诗/poet.song.132000.json','["經行猶記髧髦初，所至渾如過故墟。", "橋廢夕陽空鶴表，碑亡春草沒龜趺。", "荒郊渺渺羊牛下，叢木蕭蕭鳥雀呼。", "可恨一衰今至此，右携筇杖左人扶。"]'),
('52e8764d-8b6f-49e7-87c1-2a22df7ef6d0','雲門道中','陸游','宋','宋诗','song-poetry','','[]','度嶺穿林一徑斜，旋篝新火試新茶。',64,'全唐诗/poet.song.132000.json','["度嶺穿林一徑斜，旋篝新火試新茶。", "箬包粉餌祠寒食，雨溼青鞋上若耶。", "石罅微泉來滴瀝，溪涯老木卧槎牙。", "不須苦覓東柯谷，是處雲山可寄家。"]'),
('ed6aaa15-7e06-4a98-bd3e-d61090dbe280','龍瑞','陸游','宋','宋诗','song-poetry','','[]','多年不蹋陽明路，今日重來院院行。',32,'全唐诗/poet.song.132000.json','["多年不蹋陽明路，今日重來院院行。", "好在千秋馮觀主，修廊一見眼偏明。"]'),
('05876e47-5050-4818-b857-92582150cc3c','禹寺','陸游','宋','宋诗','song-poetry','','[]','暮春之初光景奇，湖平山遠最宜詩。',32,'全唐诗/poet.song.132000.json','["暮春之初光景奇，湖平山遠最宜詩。", "尚餘一恨無人會，不見蟬聲滿寺時。"]'),
('b3d09ddc-d034-40dc-85c9-c65285e98897','寄題張仲欽左司槃澗','陸游','宋','宋诗','song-poetry','','[]','劍谿之南有佳處，山靈尸之不輕付。',131,'全唐诗/poet.song.132000.json','["劍谿之南有佳處，山靈尸之不輕付。", "張公鼻祖晉司空，談笑得地開窗戶。", "谿光如鏡新拂拭，白雲青嶂無朝暮。", "伏几讀書時舉頭，萬象爭陳陶謝句。", "公今仙去有嗣子，關塞崎嶇方叱馭。", "山城何曾嘆如斗，皦皦不受世俗汙。", "君不見伾文往者勢如山，朝士幾人無汗顔。", "尊公遺事不須述，但看當時出處間。"]'),
('ea898a3b-4c31-4708-9368-775354d896d5','園中晚興','陸游','宋','宋诗','song-poetry','','[]','世故誰能必，書生妄自期。',48,'全唐诗/poet.song.132000.json','["世故誰能必，書生妄自期。", "年光卷中過，心事鬢邊知。", "零落花隨水，輪囷筍突籬。", "晚晴山盡出，徙倚獨移時。"]'),
('0b8b3a19-cca9-4f13-b3af-59e58ac96a5f','送陳希周赴安福令','陸游','宋','宋诗','song-poetry','','[]','補吏鶴嶺邊，尊公方玉立。',144,'全唐诗/poet.song.132000.json','["補吏鶴嶺邊，尊公方玉立。", "超遥籋風雲，餘子那可及。", "天高鬼神惡，聞訃三日泣。", "晚途見嗣子，握手悲喜集。", "乘桴掠鯨波，信矣勇可習。", "巉巉風骨峭，颶霧不能襲。", "謂當上臺省，豈復論等級。", "如何困無津，俛首臨一邑。", "顧嗟六朝民，龍鍾垂八十。", "肯來野水濱，半月解書笈。", "吾杯僅容龠，安得看鯨吸。", "佇立送歸鞍，霽日滿原隰。"]'),
('2539b37b-d1fb-4d30-885b-ccaf5f583b82','春晚久雨排悶','陸游','宋','宋诗','song-poetry','','[]','積雨暗村墟，幽居雜蛙蚓。',72,'全唐诗/poet.song.132000.json','["積雨暗村墟，幽居雜蛙蚓。", "泥潦欲升階，几席或生菌。", "壯年多重膇，况我抱宿疢。", "下床躡高屐，顧影輒自哂。", "客來入我戶，亦復爲嘆憫。", "胡不徙高原，再拜謝不敏。"]'),
('ee153343-7c38-4cf6-8cb8-9095b1f549e9','甲子日晴','陸游','宋','宋诗','song-poetry','','[]','澤國春多雨，閱月殊未止。',72,'全唐诗/poet.song.132000.json','["澤國春多雨，閱月殊未止。", "皇天俄悔禍，畀以晴甲子。", "山川相炳煥，桑柘鬰千里。", "壟麥行可穫，吳蠶亦三起。", "床頭醅甕香，大杓瀉浮蟻。", "醉醒日已晡，長歌識吾喜。"]'),
('d64b4864-e05b-4d74-82d8-956f3789ef76','三月二十日兒輩出謁孤坐北窗二首  其一','陸游','宋','宋诗','song-poetry','','[]','園林春已空，陂港雨新足。',48,'全唐诗/poet.song.132000.json','["園林春已空，陂港雨新足。", "泥深黄犢健，桑老紫椹熟。", "豐年逋負少，村社饜酒肉。", "微風吹醉醒，起和飯牛曲。"]'),
('72c53ab8-6a16-450f-81d4-c9b0fe6a976b','三月二十日兒輩出謁孤坐北窗二首  其二','陸游','宋','宋诗','song-poetry','','[]','歲月不相貸，布穀忽已鳴。',48,'全唐诗/poet.song.132000.json','["歲月不相貸，布穀忽已鳴。", "新夏亦自佳，北窗綠陰成。", "讀書老易倦，披衣繞階行。", "摩挲桄榔杖，與汝樂太平。"]'),
('7cae7683-2d85-4511-9abd-55f1ac9fd452','春盡記可喜數事','陸游','宋','宋诗','song-poetry','','[]','微雨洗浮埃，蒼顔一笑開。',48,'全唐诗/poet.song.132000.json','["微雨洗浮埃，蒼顔一笑開。", "僧招行藥圃，兒報得琴材。", "病退初嘗酒，春殘已過災。", "鄰家賽神會，自喜亦能來。"]'),
('f7b5b9db-cf49-4968-9dd3-317461d46dac','立夏前二日作','陸游','宋','宋诗','song-poetry','','[]','晨起披衣出草堂，軒窗已自喜微凉。',64,'全唐诗/poet.song.132000.json','["晨起披衣出草堂，軒窗已自喜微凉。", "餘春只有二三日，爛醉恨無千百埸。", "芳草自隨征路遠，遊絲不及客愁長。", "殘紅一片無尋處，分付年華與蜜房。"]'),
('cdd23494-2152-4677-b482-9c1a7b3b56b6','老民二首  其一','陸游','宋','宋诗','song-poetry','','[]','乞得不貲身，林間號老民。',48,'全唐诗/poet.song.132000.json','["乞得不貲身，林間號老民。", "兒因作詩瘦，家爲買書貧。", "村僕欺謾少，鄰翁語笑真。", "今朝鹽酪盡，薺糝更宜人。"]'),
('ad4cdef5-4ac7-42cc-b991-4f04e9f2f5ff','老民二首  其二','陸游','宋','宋诗','song-poetry','','[]','老民無一事，終日卧柴扉。',48,'全唐诗/poet.song.132000.json','["老民無一事，終日卧柴扉。", "鑿沼觀魚樂，鈎簾待燕歸。", "架高藤葉密，土潤藥苗肥。", "休退真吾分，無心學息機。"]'),
('002df6de-11da-490a-aaa0-f61fe18b99ee','貧甚自勵','陸游','宋','宋诗','song-poetry','','[]','忍病停朝藥，捐書省夜燈。',48,'全唐诗/poet.song.132000.json','["忍病停朝藥，捐書省夜燈。", "都門下第客，山寺退居僧。", "天每臨幽隱，人何與廢興。", "能輕馬千駟，肯慕稷三升。"]'),
('22d392ab-4455-4094-9489-be3145ae7abe','衡門','陸游','宋','宋诗','song-poetry','','[]','小聚風烟外，衡門水竹間。',48,'全唐诗/poet.song.132000.json','["小聚風烟外，衡門水竹間。", "疏溝分北澗，翦木見南山。", "人笑謀生拙，天教到死閑。", "猶存拄杖子，遇興即躋攀。"]'),
('1d79dc2f-3f05-4ecb-87b8-6a6c553f2a16','遊法雲','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','放船三家村，進棹十字港。',120,'全唐诗/poet.song.132000.json','["放船三家村，進棹十字港。", "雲山互吞吐，水草遥莽蒼。", "沙鷗下拍拍，野鶩浮兩兩。", "簫騷菰蒲中，小艇時來往。", "匡山如香爐，藍水似車輞。", "夢魂不可到，于此寄遐想。", "瘦僧迎寺門，爲我掃方丈。", "指似北窗凉，此味愧專享。", "我笑謝主人，聊可倚拄杖。", "吾廬已清絕，敢取魚熊掌。"]'),
('475ea7af-49f3-4beb-a15e-4ff2821c68b3','舟中作','陸游','宋','宋诗','song-poetry','','[]','短篷摇檝暮山昏，老怯年華易斷魂。',64,'全唐诗/poet.song.132000.json','["短篷摇檝暮山昏，老怯年華易斷魂。", "夾港蒲聲知小雨，隔林績火認孤村。", "奉祠累歲慚家食，謝事終身負國恩。", "惟有愚忠窮未替，尚餘一念在元元。"]'),
('7266f9ac-58ff-45a8-94e6-12a9d2fd5f41','貧居','陸游','宋','宋诗','song-poetry','','[]','囊空如客路，屋窄似僧寮。',48,'全唐诗/poet.song.132000.json','["囊空如客路，屋窄似僧寮。", "得飯多菰米，烹蔬半藥苗。", "草生初失徑，筍放欲干霄。", "不道弓旌誤，虞人自畏招。"]'),
('bcfd3612-ca89-41cd-b46c-77a8bc870b22','初夏野興三首  其一','陸游','宋','宋诗','song-poetry','','[]','得意烟霞不諱窮，一庵聊寄寂寥中。',64,'全唐诗/poet.song.132000.json','["得意烟霞不諱窮，一庵聊寄寂寥中。", "山從樹杪參差見，水過花陰曲折通。", "閑倚胡床遡新月，時停團扇受微風。", "元知夢境無真實，不待邯鄲覺後空。"]'),
('13c795fe-659b-405c-9964-a708e7fef8f0','初夏野興三首  其二','陸游','宋','宋诗','song-poetry','','[]','披衣清曉倚闌干，龜屋裁成二寸冠。',64,'全唐诗/poet.song.132000.json','["披衣清曉倚闌干，龜屋裁成二寸冠。", "盆檜雨餘抽嫩綠，研池風過起微瀾。", "愛書自笑心常在，去死懸知日尚寬。", "回視前修似無愧，不教一字入長安。"]'),
('f25a10d8-544a-48f6-805f-d0ccac4d5d92','初夏野興三首  其三','陸游','宋','宋诗','song-poetry','','[]','扇墮巾欹午夢回，鳴鳩又喚雨絲來。',64,'全唐诗/poet.song.132000.json','["扇墮巾欹午夢回，鳴鳩又喚雨絲來。", "數行褚帖臨窗學，一卷陶詩傍枕開。", "糠火就林煨苦筍，密罌沉井漬青梅。", "艾人行復巍然出，老大難堪節物催。"]'),
('5e415115-6a72-4285-bb6e-ea58bb88a9ad','孟夏方渴雨忽暴熱雨遂大作','陸游','宋','宋诗','song-poetry','','[]','蒸溽殊未解，雨來那可涯。',48,'全唐诗/poet.song.132000.json','["蒸溽殊未解，雨來那可涯。", "鵲驚無穩樹，燈暗不成花。", "處處躍秧馬，家家閑水車。", "兒童伴翁喜，聚首話桑麻。"]'),
('49b488eb-8caa-46a3-b984-04773c72b243','小池','陸游','宋','宋诗','song-poetry','','[]','荷鍤庭中破嫩苔，清溝一派引泉來。',32,'全唐诗/poet.song.132000.json','["荷鍤庭中破嫩苔，清溝一派引泉來。", "剪刀草長浮萍合，無數遊魚去復回。"]'),
('139f14a6-de20-456a-b741-65ee4859add2','衡門','陸游','宋','宋诗','song-poetry','','[]','曲徑衡門短短籬，槐楸陰裏倚筇枝。',32,'全唐诗/poet.song.132000.json','["曲徑衡門短短籬，槐楸陰裏倚筇枝。", "老來百事不入眼，惟愛青山如舊時。"]'),
('3f9eb3e0-caa8-4928-bd65-af5bca0e6070','海上作','陸游','宋','宋诗','song-poetry','','[]','厭逐紛紛兒女曹，挂帆江海寄吾豪。',32,'全唐诗/poet.song.132000.json','["厭逐紛紛兒女曹，挂帆江海寄吾豪。", "鯨吞鼉作渾閑事，要看秋濤天際高。"]'),
('0f6c086d-690f-4e99-8ef0-44e69bbdeba9','朝饑示子聿','陸游','宋','宋诗','song-poetry','','[]','水雲深處小茅茨，雷動空腸慣忍饑。',64,'全唐诗/poet.song.132000.json','["水雲深處小茅茨，雷動空腸慣忍饑。", "外物不移方是學，俗人猶愛未爲詩。", "生逢昭代雖虛過，死見先親幸有辭。", "八十到頭終强項，欲將衣鉢付吾兒。"]'),
('ec8537a4-28b2-490a-b4ae-5a70e0752cf3','養氣','陸游','宋','宋诗','song-poetry','','[]','養氣安心不計年，未嘗一念住愁邊。',64,'全唐诗/poet.song.132000.json','["養氣安心不計年，未嘗一念住愁邊。", "才疏屢掃朝中迹，命薄翻成世外緣。", "耐老尚能消劫石，放狂聊復醉江天。", "飽知句曲羅浮路，不訪初平即稚川。"]'),
('e40cd212-3071-46d3-9a49-3dbd2e8cb1c1','示友','陸游','宋','宋诗','song-poetry','','[]','黄卷青燈自幼童，長年頗亦有新功。',64,'全唐诗/poet.song.132000.json','["黄卷青燈自幼童，長年頗亦有新功。", "尚嘲孟顗遲成佛，那計辛毗不作公。", "學問更當窮廣大，友朋誰與共磨礱。", "諸君果未捐衰老，鄙語人當致一通。"]'),
('f8003551-c3de-4809-a51f-210817425831','早凉熟睡','陸游','宋','宋诗','song-poetry','','[]','靈臺虛湛氣和平，投枕逡巡夢即成。',64,'全唐诗/poet.song.132000.json','["靈臺虛湛氣和平，投枕逡巡夢即成。", "屋角鳴禽呼不覺，手中書冊墮無聲。", "百年日月飛雙轂，千古山河戰一枰。", "賴有蓮峰遺老在，白雲深處主齊盟。"]'),
('67b3d066-1b18-4ed1-a5e9-16a8cc3eb95e','初夏','陸游','宋','宋诗','song-poetry','','[]','麥秀微寒後，梅黄細雨前。',48,'全唐诗/poet.song.132000.json','["麥秀微寒後，梅黄細雨前。", "湖灘初集鷺，堤柳未鳴蟬。", "琴带輕陰潤，巾因小醉偏。", "晚來幽興極，又上釣魚船。"]'),
('ac0e2622-922f-4f3d-9aad-04e91bf3ca4e','夏雨','陸游','宋','宋诗','song-poetry','','[]','忽聞疏雨滴林梢，起看油雲滿四郊。',64,'全唐诗/poet.song.132000.json','["忽聞疏雨滴林梢，起看油雲滿四郊。", "行蟻君臣初徙穴，鳴鳩夫婦正爭巢。", "筑陂處處移新稻，乘屋家家補破茆。", "堪笑此翁惟美睡，孝先便腹任譏嘲。"]'),
('35118c7f-8aaa-4651-b723-1ef213497151','倚樓','陸游','宋','宋诗','song-poetry','','[]','千里江山入倚樓，高吟聊復寫吾憂。',64,'全唐诗/poet.song.132000.json','["千里江山入倚樓，高吟聊復寫吾憂。", "詩書幸有先人業，貧賤初非學者羞。", "數掩槿籬端可老，一杯藜粥尚何求。", "東陂未插青秧遍，且與鄰翁卜雨鳩。"]'),
('3da8a05b-73c7-42c1-b7ab-4c1e49277e6b','晚興二首  其一','陸游','宋','宋诗','song-poetry','','[]','偶扶藜杖過傍村，却倚禪床坐小軒。',64,'全唐诗/poet.song.132000.json','["偶扶藜杖過傍村，却倚禪床坐小軒。", "日落鴉栖津樹暗，人歸鶴踏釣船翻。", "挽弓從笑識丁字，刺繡終勝倚市門。", "羹芋一杯吾自飽，諸兒强爲置盤飧。"]'),
('5395b3c7-9573-4b09-b277-4f26fd6c3537','晚興二首  其二','陸游','宋','宋诗','song-poetry','','[]','身如病鶴謝樊籠，白盡衰髯臉尚紅。',64,'全唐诗/poet.song.132000.json','["身如病鶴謝樊籠，白盡衰髯臉尚紅。", "蒲葦陂塘新漲後，梧楸門巷夕陽中。", "遺名要耐千年看，快飲方誇百榼空。", "造物閔憐君會否，放教折臂老新豐。"]'),
('ad9e49e8-4fce-4c3f-978c-dcffea1e823d','晨雨','陸游','宋','宋诗','song-poetry','','[]','過雲生谷暗，既雨却窗明。',48,'全唐诗/poet.song.132000.json','["過雲生谷暗，既雨却窗明。", "低燕爭泥語，浮魚逆水行。", "山川增秀色，草木有奇聲。", "處處青秧滿，長歌樂太平。"]'),
('0f246c23-726b-4d41-aaaf-e065b6b5dfaf','戲作絕句以唐人句終之二首  其一','陸游','宋','宋诗','song-poetry','','[]','雨細穿梅塢，風和上柳橋。',24,'全唐诗/poet.song.132000.json','["雨細穿梅塢，風和上柳橋。", "山居無曆日，今日是何朝。"]'),
('ac934f32-0348-4826-b235-4c4dad1d7a2d','戲作絕句以唐人句終之二首  其二','陸游','宋','宋诗','song-poetry','','[]','靜對煎茶竈，閑疏洗藥泉。',24,'全唐诗/poet.song.132000.json','["靜對煎茶竈，閑疏洗藥泉。", "回頭問童子，今夕是何年。"]'),
('eeb2d1e5-811f-4665-8f8f-65f5e2a13e8b','述懷','陸游','宋','宋诗','song-poetry','','[]','情懷猶是昔年人，豈料侵尋八十身。',64,'全唐诗/poet.song.132000.json','["情懷猶是昔年人，豈料侵尋八十身。", "燈下看書方覺老，花前闕酒始知貧。", "玉非鼠朴何勞辨，魚與熊蹯各自珍。", "萬事回頭已陳迹，爲君一笑落紗巾。"]'),
('bdbfd64a-0500-4de9-a3ba-2927b599bc77','閑中自詠','陸游','宋','宋诗','song-poetry','','[]','鶴羨清癯鷗羨閑，衡門正在水雲間。',64,'全唐诗/poet.song.132000.json','["鶴羨清癯鷗羨閑，衡門正在水雲間。", "無求尚恨時賒酒，有癖應緣酷愛山。", "細繞坡頭行犖确，別分泉脈聽淙潺。", "三更不睡看江月，恐有高人夜叩關。"]'),
('aefd8ce2-5773-442e-aa6e-356393734fce','晨興','陸游','宋','宋诗','song-poetry','','[]','小雨過郊墟，晨興一事無。',48,'全唐诗/poet.song.132000.json','["小雨過郊墟，晨興一事無。", "殘榴重結蕊，新燕續生雛。", "書細猶能讀，行遲漸要扶。", "蔬畦恐蕪沒，且復課僮奴。"]'),
('a19dcf2e-6964-42f2-b534-b602626c894a','自詒二首  其一','陸游','宋','宋诗','song-poetry','','[]','愈老愈知生有涯，此時一念不容差。',64,'全唐诗/poet.song.132000.json','["愈老愈知生有涯，此時一念不容差。", "身如病鶴長停料，心似山僧已棄家。", "高枕時時聞解籜，卷簾片片數飛花。", "飯餘解带摩便腹，自取風爐煮晚茶。"]'),
('98ab37c5-4c71-4e50-afe5-db1cb47b7136','自詒二首  其二','陸游','宋','宋诗','song-poetry','','[]','行年耄及卧蝸廬，山水登臨亦已疏。',64,'全唐诗/poet.song.132000.json','["行年耄及卧蝸廬，山水登臨亦已疏。", "無可奈何猶食粟，未能免俗學澆蔬。", "蓬門時接漁樵話，塵几聊存種樹書。", "强欲入城還自笑，世間那有鶴乘車。"]'),
('6d64e7d7-719e-4261-b84c-33a070b0aa0b','西村','陸游','宋','宋诗','song-poetry','','[]','亂山深處小桃源，往歲求漿憶叩門。',64,'全唐诗/poet.song.132000.json','["亂山深處小桃源，往歲求漿憶叩門。", "高柳簇橋初轉馬，數家臨水自成村。", "茂林風送幽禽語，壞壁苔侵醉墨痕。", "一首清詩記今夕，細雲新月耿黄昏。"]'),
('d0c2a865-fb0c-43d1-bfc5-449b44e572d1','漁父','陸游','宋','宋诗','song-poetry','','[]','楚江茫茫新雨霽，殘雲蹙作魚鱗細。',64,'全唐诗/poet.song.132000.json','["楚江茫茫新雨霽，殘雲蹙作魚鱗細。", "老翁短楫去若飛，我欲從之已天際。", "從之不可况共語，醉眼知渠輕一世。", "直鈎去餌五十年，此意寧爲得魚計。"]'),
('9d07b75a-fc87-4e09-97ad-70d5171eeb76','放歌行','陸游','宋','宋诗','song-poetry','','[]','少年不知老境惡，意謂長如少年樂。',96,'全唐诗/poet.song.132000.json','["少年不知老境惡，意謂長如少年樂。", "朝歌夜舞狂不休，逢人欲覓長生藥。", "三二十年底難過，屈指朋儕餘幾箇。", "就令未死身日衰，朱顔已去誰能那。", "人間萬事如弈棋，我亦曾經少壯時。", "兒曹紛紛不須校，歲月推遷渠自知。"]'),
('ca809980-7d8d-4fec-a65a-0a669479af5d','苦貧','陸游','宋','宋诗','song-poetry','','[]','老作清時版籍民，深耕迨及故山春。',64,'全唐诗/poet.song.132000.json','["老作清時版籍民，深耕迨及故山春。", "熟思豈是天貧我，妄計還憂鬼笑人。", "但使甑中餘麥飯，何妨澗底采荆薪。", "此窮正坐清狂爾，莫向瞿曇問宿因。"]'),
('8e1620a0-d426-43e4-be20-056bf1162e2e','晨起至參倚齋示子聿','陸游','宋','宋诗','song-poetry','','[]','似仙猶火食，比古未巢居。',48,'全唐诗/poet.song.132000.json','["似仙猶火食，比古未巢居。", "老子粗全節，小兒能著書。", "下簾留乳燕，投飯出潜魚。", "幸好隆中客，無爲起草廬。"]'),
('16dfb370-248b-44c7-b90f-2818abc3035d','夏夜對月','陸游','宋','宋诗','song-poetry','','[]','薄雲歸欲盡，殘雨久猶滴。',72,'全唐诗/poet.song.132000.json','["薄雲歸欲盡，殘雨久猶滴。", "月入疏林間，庭戶粲珠璧。", "梅天苦蒸鬰，爽氣始此夕。", "豈無一舴艋，放浪江天碧。", "散髮黄鶴樓，醉弄白玉笛。", "真當舞魚龍，詎止裂金石。"]'),
('9ad8961a-ef7f-47fc-b780-19c02c314627','夏夜','陸游','宋','宋诗','song-poetry','','[]','酒力初消睡未厭，卧看香縷繞疏簾。',64,'全唐诗/poet.song.132000.json','["酒力初消睡未厭，卧看香縷繞疏簾。", "月高棲鵲重移樹，風勁流螢自入簷。", "長夏迢迢秋尚遠，孤愁冉冉病相兼。", "老人本是山中客，掃迹元非畏楚鉗。"]'),
('57dda70e-9ef8-475a-a8c6-ad13b41f4004','五月十日曉寒甚聞布穀鳴有感','陸游','宋','宋诗','song-poetry','','[]','弊袴久當脫，短褐竟未送。',72,'全唐诗/poet.song.132000.json','["弊袴久當脫，短褐竟未送。", "老怯五更寒，重衾擁殘夢。", "群虱方得意，飽血藏衣縫。", "竹簟何時陳，紈扇殆無用。", "長夏亹亹來，歲月疾飛鞚。", "妄懷畎畝憂，太息欲誰控。"]'),
('db7574e9-4f35-448e-96eb-1593e9271e07','老嘆','陸游','宋','宋诗','song-poetry','','[]','人生易衰老，萬事海濤翻。',48,'全唐诗/poet.song.132000.json','["人生易衰老，萬事海濤翻。", "但恨芳尊迮，寧悲雪鬢繁。", "諸儒輕古學，遺虜盜中原。", "有語誰能聽，毋矜舌尚存。"]'),
('6e7bb400-0f1c-4faa-bf3a-7425dd676138','閉戶','陸游','宋','宋诗','song-poetry','','[]','收身歸死鏡湖傍，閉戶悠悠白日長。',64,'全唐诗/poet.song.132000.json','["收身歸死鏡湖傍，閉戶悠悠白日長。", "巷僻斷非容駟路，腸枯那有蹴蔬羊。", "書生正可蹈東海，世事漫思移太行。", "睡起不知天早暮，坐看螢度篆盤香。"]'),
('e9a2cc5b-a0ee-476e-9cef-4167133c5b91','長饑','陸游','宋','宋诗','song-poetry','','[]','病卧窮閻負聖時，本來吾道合長饑。',64,'全唐诗/poet.song.132000.json','["病卧窮閻負聖時，本來吾道合長饑。", "朝不及夕未妨樂，死何如生行自知。", "早年羞學仗下馬，末路幸似泥中龜。", "烟波一葉會當逝，吹笛高人有素期。"]'),
('404fc910-4390-478d-ab6e-db6d984d1a2c','山齋書事','陸游','宋','宋诗','song-poetry','','[]','山榴子結又重開，巢燕雛飛却續回。',64,'全唐诗/poet.song.132000.json','["山榴子結又重開，巢燕雛飛却續回。", "雨足人畦千頃稻，日長風舞一庭槐。", "浩歌縱酒愁仍在，作意觀書睡已來。", "常恨流年不相貸，若爲更著暮蟬催。"]'),
('7e67fbc3-8d32-4c5c-bf00-967ef530b83f','贈道流','陸游','宋','宋诗','song-poetry','','[]','賣藥會稽市，不知今幾年。',48,'全唐诗/poet.song.132000.json','["賣藥會稽市，不知今幾年。", "身常雜庸保，世果有神仙。", "醉帽簪花舞，漁舟聽雨眠。", "放翁獨識子，肯向俗人傳。"]'),
('e833da18-dbd5-47fb-a9e4-f2ac3d4f6cf3','避暑松竹間','陸游','宋','宋诗','song-poetry','','[]','雙松五丈高，萬竹一尺圍。',72,'全唐诗/poet.song.132000.json','["雙松五丈高，萬竹一尺圍。", "上有林蟬鳴，下有磵鳥飛。", "正午不見日，我來每忘歸。", "清詩忽陳前，永與世俗違。", "直北有異境，烟汀連釣磯。", "何當霜雪時，散髮槲葉衣。"]'),
('a89ea734-1226-4dfd-89b7-d12899822040','連日大雨門外湖水渺然','陸游','宋','宋诗','song-poetry','','[]','趁朝把笏著烏靴，不似歸來買短蓑。',64,'全唐诗/poet.song.132000.json','["趁朝把笏著烏靴，不似歸來買短蓑。", "尚鄙朱公養魚術，肯爲甯戚飯牛歌。", "逢時有命求何益，觸事無心得最多。", "樂處却嫌兒輩覺，出門十步即烟波。"]'),
('18ccad76-6c83-46ab-a152-766dfef58de2','午睡','陸游','宋','宋诗','song-poetry','','[]','槐楸陰裏綠窗開，天與先生作睡媒。',64,'全唐诗/poet.song.132000.json','["槐楸陰裏綠窗開，天與先生作睡媒。", "流汗未乾衣上雨，大聲已發鼻端雷。", "枕鎸松石分琴薦，簟織風漪取笛材。", "却起岸巾看汲井，人間車馬正氛埃。"]'),
('333a5a73-1f7f-4d29-88ba-f264f694c326','窮居','陸游','宋','宋诗','song-poetry','','[]','阨窮心自樂，寂寞道常尊。',48,'全唐诗/poet.song.132000.json','["阨窮心自樂，寂寞道常尊。", "老病頻辭客，嬉遊不出村。", "淖糜均列鼎，徒步當華軒。", "不但終吾世，猶堪遺子孫。"]'),
('f0052dcf-0d71-4881-a81f-d8118b7a5fe8','梅雨','陸游','宋','宋诗','song-poetry','','[]','殘雨收還滴，低雲去復留。',48,'全唐诗/poet.song.132000.json','["殘雨收還滴，低雲去復留。", "護雛憐弱燕，喚婦笑鳴鳩。", "碓米舂初滑，園蔬摘復抽。", "誰知泥沒踝，也有客相求。"]'),
('5720108f-5327-4f17-99c4-994e455475d0','村居書事','陸游','宋','宋诗','song-poetry','','[]','困厄難希飽暖家，未妨隨事作生涯。',64,'全唐诗/poet.song.132000.json','["困厄難希飽暖家，未妨隨事作生涯。", "白鹽赤米已過足，早韭晚菘猶恐奢。", "鴨放競浮新漲水，牛歸正及暝棲鴉。", "年逾七十方辭祿，敢望高人挂齒牙。"]'),
('51a76c3c-d104-46d1-8e2a-03ff6fe684d1','閑中信筆二首其一追和陳去非韵其一追和王履道韵  其一','陸游','宋','宋诗','song-poetry','','[]','我看浮名如脫髮，誓墓收身老巖穴。',64,'全唐诗/poet.song.132000.json','["我看浮名如脫髮，誓墓收身老巖穴。", "座延窮鬼心不疑，鑪錘橫財渠自別。", "樂哉今爲八十翁，神交園綺商山中。", "烹葵剝棗及時序，爛醉黍酒歌邠風。"]'),
('38dbd54f-d33f-4ef5-aeb4-3b63337d07d9','閑中信筆二首其一追和陳去非韵其一追和王履道韵  其二','陸游','宋','宋诗','song-poetry','','[]','小江之上千峰立，潮回艇子爭來集。',64,'全唐诗/poet.song.132000.json','["小江之上千峰立，潮回艇子爭來集。", "飄風忽起白浪高，急雨橫吹綠蓑溼。", "歲豐斗酒纔百錢，茆店無人驚醉眠。", "醒來徑入亂雲去，異日出看東封年。"]'),
('9ef4ece7-9a25-46b1-92dd-2777f2bbefe7','題齋壁','陸游','宋','宋诗','song-poetry','','[]','鏡水西頭破茅屋，紹興初載舊書生。',64,'全唐诗/poet.song.132000.json','["鏡水西頭破茅屋，紹興初載舊書生。", "門無車馬終年靜，身卧雲山萬事輕。", "三釜昔傷貧藉祿，一廛今幸老爲氓。", "斷蓬不是無飛處，莫與飄風抵死爭。"]'),
('05169479-f213-4532-8b1b-6e64e57a9363','夏日雜題八首  其一','陸游','宋','宋诗','song-poetry','','[]','疏疏窗似秋蛩室，疊疊書如春鵲巢。',32,'全唐诗/poet.song.132000.json','["疏疏窗似秋蛩室，疊疊書如春鵲巢。", "大耋何妨尚弦誦，小詩時亦雜談嘲。"]'),
('a16b1513-faf9-49ad-b05a-94576a0fe2cf','夏日雜題八首  其二','陸游','宋','宋诗','song-poetry','','[]','耽耽醜石羆當道，矯矯長松龍上天。',32,'全唐诗/poet.song.132000.json','["耽耽醜石羆當道，矯矯長松龍上天。", "滿地凌霄花不掃，我來六月聽鳴蟬。"]'),
('33979266-fae3-41cf-8945-8dbf428103e7','夏日雜題八首  其三','陸游','宋','宋诗','song-poetry','','[]','情懷萬里長征客，身世連床旦過僧。',32,'全唐诗/poet.song.132000.json','["情懷萬里長征客，身世連床旦過僧。", "熟計書空成咄咄，不如任運去騰騰。"]'),
('d36487b3-a481-4490-baf6-4b726819f0c1','夏日雜題八首  其四','陸游','宋','宋诗','song-poetry','','[]','一枝黎峒桄榔杖，二寸羊城蝳蝐冠。',32,'全唐诗/poet.song.132000.json','["一枝黎峒桄榔杖，二寸羊城蝳蝐冠。", "萬里來爲老人壽，始知天地不勝寬。"]'),
('7425a3cf-7156-4366-9f45-22da7dcf04e4','夏日雜題八首  其五','陸游','宋','宋诗','song-poetry','','[]','天隨手不去朱黄，辟蠹芸編細細香。',32,'全唐诗/poet.song.132000.json','["天隨手不去朱黄，辟蠹芸編細細香。", "今夕短檠須暫設，北窗風雨送微凉。"]'),
('572a1ebe-4695-4d88-b354-e30e3b5095c2','夏日雜題八首  其六','陸游','宋','宋诗','song-poetry','','[]','身閑欲出無如懶，酒薄雖傾不敵愁。',32,'全唐诗/poet.song.132000.json','["身閑欲出無如懶，酒薄雖傾不敵愁。", "殘暑從今無一月，剩儲詩思待新秋。"]'),
('61bda391-b603-4428-af6c-f2c9c32f4546','夏日雜題八首  其七','陸游','宋','宋诗','song-poetry','','[]','憔悴衡門一禿翁，回頭無事不成空。',32,'全唐诗/poet.song.132000.json','["憔悴衡門一禿翁，回頭無事不成空。", "可憐萬里平戎志，盡付蕭蕭暮雨中。"]'),
('cfafcd71-d53b-4851-be90-b825eb8ed2e5','夏日雜題八首  其八','陸游','宋','宋诗','song-poetry','','[]','衰疾沉綿短鬢疏，凄凉圯上一編書。',32,'全唐诗/poet.song.132000.json','["衰疾沉綿短鬢疏，凄凉圯上一編書。", "中原久陷身垂老，付與囊中飽蠹魚。"]'),
('077730ae-775b-40eb-9b95-d57cb23ec356','夏雨嘆','陸游','宋','宋诗','song-poetry','','[]','蝸舍入門楣觸額，黄泥壁作龜兆坼。',96,'全唐诗/poet.song.132000.json','["蝸舍入門楣觸額，黄泥壁作龜兆坼。", "雨多潦水欲上階，卧聽鳧鴨聲拍拍。", "日高糴米奴未回，坐知薄飯未容索。", "仕羞捷徑耕不力，自取囊空欲誰責。", "富貴危機復可畏，世間果無第一策。", "雖然胸中有事在，片言可壽天下脈。"]'),
('58ea4f97-952c-412c-896c-ae4e44ed062b','物外雜題八首  其一','陸游','宋','宋诗','song-poetry','','[]','市墟沽斗酒，獨酌復高歌。',24,'全唐诗/poet.song.132000.json','["市墟沽斗酒，獨酌復高歌。", "一笑語觀者，比君更事多。"]'),
('3bc207a7-6c50-4e86-8298-23f870951076','物外雜題八首  其二','陸游','宋','宋诗','song-poetry','','[]','當年下沔鄂，回首幾秋風。',24,'全唐诗/poet.song.132000.json','["當年下沔鄂，回首幾秋風。", "景物渾如昨，千帆落照中。"]'),
('218c0b16-6eb5-49c9-a2a3-57a82e8e8071','物外雜題八首  其三','陸游','宋','宋诗','song-poetry','','[]','曉入姑蘇市，閶門繫短篷。',24,'全唐诗/poet.song.132000.json','["曉入姑蘇市，閶門繫短篷。", "老人元不食，買餅飼山童。"]'),
('28f3050e-c336-4215-b715-58538134df28','物外雜題八首  其四','陸游','宋','宋诗','song-poetry','','[]','送客停山步，尋僧立寺門。',24,'全唐诗/poet.song.132000.json','["送客停山步，尋僧立寺門。", "青鞋慣泥潦，却愛雨昏昏。"]'),
('707bafaa-9ea3-4bb0-aa17-b08628187f4e','物外雜題八首  其五','陸游','宋','宋诗','song-poetry','','[]','粉堞臨江渚，朱橋枕市樓。',24,'全唐诗/poet.song.132000.json','["粉堞臨江渚，朱橋枕市樓。", "長吟策小蹇，又度一年秋。"]'),
('c15a8db4-76af-4017-9789-6462174e6fc4','物外雜題八首  其六','陸游','宋','宋诗','song-poetry','','[]','飼驢留野店，買藥入山城。',24,'全唐诗/poet.song.132000.json','["飼驢留野店，買藥入山城。", "興盡飄然去，無人識姓名。"]'),
('0069aea8-9f22-4af1-b9ca-48cde23c1692','物外雜題八首  其七','陸游','宋','宋诗','song-poetry','','[]','高城今曠野，比屋昔朱門。',24,'全唐诗/poet.song.132000.json','["高城今曠野，比屋昔朱門。", "道上傳呼過，遥遥幾世孫。"]'),
('f74af593-a29e-4d36-b141-61be1d0aa5a0','物外雜題八首  其八','陸游','宋','宋诗','song-poetry','','[]','過市摩雙眼，驚嗟閱盛衰。',24,'全唐诗/poet.song.132000.json','["過市摩雙眼，驚嗟閱盛衰。", "朱樓倚霄漢，曾見始成時。"]'),
('ff2fdfc7-de14-4911-896d-37bcaa0f64c7','過村舍','陸游','宋','宋诗','song-poetry','','[]','碓舍臨山路，牛欄隔草烟。',24,'全唐诗/poet.song.132000.json','["碓舍臨山路，牛欄隔草烟。", "問今何歲月，恐是結繩前。"]'),
('c6ead0e5-630d-45a2-8f64-07f73b4a25e6','晝卧初起書事','陸游','宋','宋诗','song-poetry','','[]','歲華病思兩侵尋，靜看槐楸轉午陰。',64,'全唐诗/poet.song.132000.json','["歲華病思兩侵尋，靜看槐楸轉午陰。", "待睡不來聊小憩，煅詩未就且長吟。", "還山久洗天涯恨，謝事新諧物外心。", "忽有故人分祿米，呼兒先議贖雷琴。"]'),
('a4e0d760-87d7-455a-8bed-afcbe68eb5ab','夜雨有感','陸游','宋','宋诗','song-poetry','','[]','斷虹不隔江郊雨，一盞昏燈夜半時。',64,'全唐诗/poet.song.132000.json','["斷虹不隔江郊雨，一盞昏燈夜半時。", "多感生悲那爲酒，積衰成瘦錯冤詩。", "空階點滴何由止，倦枕凄凉只自知。", "平日故人零落盡，寄書誰與敘睽離。"]'),
('bc918e8a-722d-4936-a172-36b715d9a622','偶作夜雨詩明日讀而自笑別賦一首','陸游','宋','宋诗','song-poetry','','[]','俗情向者未全忘，洗以縈簾一縷香。',64,'全唐诗/poet.song.132000.json','["俗情向者未全忘，洗以縈簾一縷香。", "得失故應常浩浩，是非正可付蒼蒼。", "殘蟬不斷知秋近，雙燕歸來伴晝長。", "誰識龜堂新力量，東家却笑接輿狂。"]'),
('4126797d-899f-4437-abb6-7df808085ebe','舍西晚眺示子聿','陸游','宋','宋诗','song-poetry','','[]','秋濤常記犯靈胥，季子雙髦尚髧如。',64,'全唐诗/poet.song.132000.json','["秋濤常記犯靈胥，季子雙髦尚髧如。", "薄飯不爲明日計，短檠相對十年餘。", "嗟予久合墮鬼錄，憐汝猶能讀父書。", "西望牛頭渺天際，永懷吾祖起家初。"]'),
('38a22463-8148-4331-88e6-93df481bf001','自訟','陸游','宋','宋诗','song-poetry','','[]','年少寧知道廢興，摶風變化羨鯤鵬。',64,'全唐诗/poet.song.132000.json','["年少寧知道廢興，摶風變化羨鯤鵬。", "貪求但欲攀分寸，痛定方慚乞斗升。", "靈府已能澄似水，俗緣更覺薄于僧。", "挂冠且喜身蕭散，二頃寧須退可憑。"]'),
('80ef4aa8-9650-407e-a89d-838daabcc8e4','讀唐人樂府戲擬思婦怨','陸游','宋','宋诗','song-poetry','','[]','一自門前征馬嘶，此心常與斷雲西。',64,'全唐诗/poet.song.132000.json','["一自門前征馬嘶，此心常與斷雲西。", "雙飛空羨雉朝雊，獨泣忍聞烏夜啼。", "遼海晝昏塵漠漠，杜陵春到草萋萋。", "孤愁可爲鄰姬說，只有臨樽醉似泥。"]'),
('454244cd-772d-4198-8347-1ea452eeab19','南堂納凉二首  其一','陸游','宋','宋诗','song-poetry','','[]','環坐列胡床，兒曹共此凉。',48,'全唐诗/poet.song.132000.json','["環坐列胡床，兒曹共此凉。", "風生桐葉墜，露下稻花香。", "老幸返初服，窮宜歸故鄉。", "已無纓可濯，清嘯對滄浪。"]'),
('48e26190-6183-4733-9170-d79efd9a90b5','南堂納凉二首  其二','陸游','宋','宋诗','song-poetry','','[]','浴罷閑無事，悠然寄一床。',48,'全唐诗/poet.song.132000.json','["浴罷閑無事，悠然寄一床。", "水風凉醉頰，松月上虛廊。", "岸久烏紗側，熏餘細葛香。", "今宵一美睡，何止傲羲皇。"]'),
('397648f4-df7b-4018-a626-77fc0cb12f5f','中庭納凉二首  其一','陸游','宋','宋诗','song-poetry','','[]','紅映衡門夕照明，翠浮村巷暝烟生。',64,'全唐诗/poet.song.132000.json','["紅映衡門夕照明，翠浮村巷暝烟生。", "摇摇楸線風初緊，颭颭荷盤露欲傾。", "數酌濁醪留客醉，一編疑義與兒評。", "須臾散去人聲寂，獨數城頭長短更。"]'),
('ada95f74-c139-4e3a-9827-2f77cb5ad2fc','中庭納凉二首  其二','陸游','宋','宋诗','song-poetry','','[]','散髮江天懶出遊，衡門日落鎖梧楸。',64,'全唐诗/poet.song.132000.json','["散髮江天懶出遊，衡門日落鎖梧楸。", "火雲突兀方蒸暑，銀漢縱橫已報秋。", "熠熠露螢黏徑草，鼕鼕漏鼓下譙樓。", "追凉明日無奇策，聊向林間卜雨鳩。"]'),
('1cbe1e5a-2a67-493d-a8f8-27bcf0c4d11c','待旦二首  其一','陸游','宋','宋诗','song-poetry','','[]','東方星磊磊，西舍雞喔喔。',48,'全唐诗/poet.song.132000.json','["東方星磊磊，西舍雞喔喔。", "萬慮集五更，吾睡無由著。", "世事如飲酒，不獻自無酢。", "開窗起危坐，送月西南落。"]'),
('be3ca2d8-189c-44c3-9fea-223c7912e87e','待旦二首  其二','陸游','宋','宋诗','song-poetry','','[]','是身如浮烟，久聚要當散。',48,'全唐诗/poet.song.132000.json','["是身如浮烟，久聚要當散。", "吾年七十七，寒暑凡幾換。", "夏夜亦自佳，何必厭揮汗。", "推枕坐南窗，悠然待清旦。"]'),
('ffd4db34-9705-4f03-b93f-badcb770df27','晨興二首  其一','陸游','宋','宋诗','song-poetry','','[]','冬夕宜晚睡，夏日思晨興。',72,'全唐诗/poet.song.132000.json','["冬夕宜晚睡，夏日思晨興。", "磊落明星高，蒼凉朝日昇。", "正襟坐堂上，有几不敢憑。", "陳前聖人書，凜如蹈淵冰。", "平生不苟利，豈獨畏友朋。", "長饑君勿誚，人各有不能。"]'),
('a48a3de6-e7be-4f82-8192-be1ed6975b03','晨興二首  其二','陸游','宋','宋诗','song-poetry','','[]','欲曉不能寐，亟起坐北堂。',72,'全唐诗/poet.song.132000.json','["欲曉不能寐，亟起坐北堂。", "齋莊對斷簡，左右陳朱黄。", "湛湛一池墨，裊裊半篆香。", "老生不自逸，幸此夏日長。", "奇哉長頭兒，好勇不可當。", "安得數年健，與兒講虞唐。"]'),
('6ede80db-4d23-4b84-bf05-ff133399ff63','晚凉述懷','陸游','宋','宋诗','song-poetry','','[]','末學常憂墮吝驕，晚知鵬鷃本逍遥。',64,'全唐诗/poet.song.132000.json','["末學常憂墮吝驕，晚知鵬鷃本逍遥。", "屏醫却藥疾良已，破械空囹盜自消。", "父子終身美藜藿，交遊太半是漁樵。", "衡門日落清風起，又著藤冠度野橋。"]'),
('0a2ffc83-4710-4ac7-8950-a7f3a212d5ad','湖塘晚眺二首  其一','陸游','宋','宋诗','song-poetry','','[]','綠樹暗村墟，青山繞草廬。',48,'全唐诗/poet.song.132000.json','["綠樹暗村墟，青山繞草廬。", "奉祠神禹舊，馳道暴秦餘。", "浦色沉烟網，畦聲入雨遊。", "清秋又如許，幽憤若爲攄。"]'),
('71b1e979-fd5a-4440-93f3-0b7a72ee06ab','湖塘晚眺二首  其二','陸游','宋','宋诗','song-poetry','','[]','病起閑無事，時來古渡頭。',48,'全唐诗/poet.song.132000.json','["病起閑無事，時來古渡頭。", "烟中賣魚市，月下采蓮舟。", "帆鼓娥江晚，菱歌姥廟秋。", "長吟無傑句，聊以散吾愁。"]'),
('ca489280-ff15-47c5-9983-d0f88bcbfcf2','小集','陸游','宋','宋诗','song-poetry','','[]','烏桕遮山路，紅蕖滿野塘。',48,'全唐诗/poet.song.132000.json','["烏桕遮山路，紅蕖滿野塘。", "病蘇身漸健，秋近夜微凉。", "杯酌隨宜具，漁歌盡意長。", "兒曹娛老子，團坐說豐穰。"]'),
('1eed7a52-7398-4d66-9664-c1e39d8abcaa','出門與鄰人笑談久之戲作四首  其一','陸游','宋','宋诗','song-poetry','','[]','少時已嘆少歡娛，衰病經旬一笑無。',32,'全唐诗/poet.song.132000.json','["少時已嘆少歡娛，衰病經旬一笑無。", "今日出門逢父老，欣然隨眾强盧胡。"]'),
('fa9e460a-168f-485d-ba7e-1611cdaf742b','出門與鄰人笑談久之戲作四首  其二','陸游','宋','宋诗','song-poetry','','[]','暮靄昏昏半掩扉，偶逢鄰叟荷鉏歸。',32,'全唐诗/poet.song.132000.json','["暮靄昏昏半掩扉，偶逢鄰叟荷鉏歸。", "且令閑說鄉村事，莫問渠言是與非。"]'),
('4a05caa5-e7f3-4469-961d-28ea108a037b','出門與鄰人笑談久之戲作四首  其三','陸游','宋','宋诗','song-poetry','','[]','菽水欣欣每盡歡，仁賢不必襲衣冠。',32,'全唐诗/poet.song.132000.json','["菽水欣欣每盡歡，仁賢不必襲衣冠。", "出門邂逅移時語，未害龜堂取友端。"]'),
('fbc587e8-ee33-4ac8-902c-ed983d5cb183','出門與鄰人笑談久之戲作四首  其四','陸游','宋','宋诗','song-poetry','','[]','屋角時聞黄犢鳴，相逢但可說春耕。',32,'全唐诗/poet.song.132000.json','["屋角時聞黄犢鳴，相逢但可說春耕。", "一言誤及城中事，議罰應須便酌觥。"]'),
('d203c4c3-891e-4618-b6b2-bd5f175cdcfe','魚池將涸車水注之','陸游','宋','宋诗','song-poetry','','[]','清波溜溜入新渠，鄰曲來觀樂有餘。',64,'全唐诗/poet.song.132000.json','["清波溜溜入新渠，鄰曲來觀樂有餘。", "試手便同三日雨，滿陂已活十千魚。", "喜如雷動風行際，快若天開地闢初。", "萬物但令俱有託，吾曹安取愛吾廬。"]'),
('72ab4d65-2713-4d49-960c-4958dcbb6639','一齒動摇已久然餘皆堅甚戲作','陸游','宋','宋诗','song-poetry','','[]','病齒元知不更全，漂浮杌𣕕已三年。',33,'全唐诗/poet.song.132000.json','["病齒元知不更全，漂浮杌𣕕已三年。", "一朝正讙使終辭去，大嚼猶能盡彘肩。"]'),
('df8eac4b-0e1b-4243-82fe-a12b9be0b906','晚至新塘','陸游','宋','宋诗','song-poetry','','[]','青鞋隨意出柴荆，聊向南塘曳杖行。',64,'全唐诗/poet.song.132000.json','["青鞋隨意出柴荆，聊向南塘曳杖行。", "歸鳥已從烟際沒，斷虹猶在柳梢明。", "城頭層塔凌空立，浦口孤舟並岸橫。", "向道有詩渾不信，爲君擁鼻作吳聲。"]'),
('826f9c89-f4ec-4321-9fd3-974271df6074','夜泛湖中','陸游','宋','宋诗','song-poetry','','[]','水鴨鵁鶄拍拍飛，菰蒲深處弄烟霏。',32,'全唐诗/poet.song.132000.json','["水鴨鵁鶄拍拍飛，菰蒲深處弄烟霏。", "喚回二十年前夢，半醉姑溪棹月歸。"]'),
('6dc142ea-7d52-4d76-904f-91cf981129fa','立秋後作','陸游','宋','宋诗','song-poetry','','[]','宋玉悲秋千載後，詩人例有早秋詩。',32,'全唐诗/poet.song.132000.json','["宋玉悲秋千載後，詩人例有早秋詩。", "老夫自笑心如石，三日秋風漫不知。"]'),
('7a2a3a40-b267-4b6d-a6e0-e5b1170978c9','覽鏡','陸游','宋','宋诗','song-poetry','','[]','此頭那可著貂蟬，瘦似騎驢孟浩然。',32,'全唐诗/poet.song.132000.json','["此頭那可著貂蟬，瘦似騎驢孟浩然。", "一事比渠差省力，閉門無句與人傳。"]'),
('ab6e39f1-35fe-4b6f-8965-a2e47502892c','早秋南堂夜興','陸游','宋','宋诗','song-poetry','','[]','水注橫塘藻荇香，候蟲唧唧滿空廊。',64,'全唐诗/poet.song.132000.json','["水注橫塘藻荇香，候蟲唧唧滿空廊。", "風前落葉紛可掃，天際疏星森有芒。", "夜漏漸長愁少睡，秋衣未製怯新凉。", "明朝却有欣然處，寫得黄庭又幾行。"]'),
('3205439a-619b-4651-af4c-217b6b4bdbf1','菱歌','陸游','宋','宋诗','song-poetry','','[]','海內知心人漸少，眼前敗意事常多。',32,'全唐诗/poet.song.132000.json','["海內知心人漸少，眼前敗意事常多。", "問君底事渾忘却，月下菱舟一曲歌。"]'),
('f7c36bbc-aa99-4875-ab69-753b6e8bc5a9','聞角','陸游','宋','宋诗','song-poetry','','[]','河白如銀天淡青，角聲中有玉關情。',32,'全唐诗/poet.song.132000.json','["河白如銀天淡青，角聲中有玉關情。", "早知送老桑麻野，悔失安西萬里行。"]'),
('6944d30b-d6d7-410e-bb5e-782b0f049288','湖堤','陸游','宋','宋诗','song-poetry','','[]','新月纖纖淡欲無，時聞魚躍隔菰蒲。',32,'全唐诗/poet.song.132000.json','["新月纖纖淡欲無，時聞魚躍隔菰蒲。", "籃輿小放湖堤上，信有人間白玉壺。"]'),
('2dab4e80-8294-45e7-b98b-36ffc2db1242','秋旦','陸游','宋','宋诗','song-poetry','','[]','將旦溪風急，新秋天宇寬。',48,'全唐诗/poet.song.132000.json','["將旦溪風急，新秋天宇寬。", "凉生豎裁褐，爽入縮縫冠。", "拊翼雞頻唱，爭枝雀正讙。", "一簞吾已足，芋豆亦加餐。"]'),
('0f4e9b0f-c6dc-4424-ac5a-2bc10c3f75cd','龜堂晨起','陸游','宋','宋诗','song-poetry','','[]','培火螭爐起寶熏，滴泉鏊研聚玄雲。',64,'全唐诗/poet.song.132000.json','["培火螭爐起寶熏，滴泉鏊研聚玄雲。", "屏圍燕几成山字，簟展凉軒作水紋。", "絕口不談浮世事，洗心聊策退居勳。", "耄年猶健非無自，一卷丹經受鄭君。"]'),
('1a6a9975-d71b-4b52-b46b-4b817e58fce1','柳橋秋夕','陸游','宋','宋诗','song-poetry','','[]','柳疏橋盡見，水落路全通。',48,'全唐诗/poet.song.132000.json','["柳疏橋盡見，水落路全通。", "衣杵家家月，漁舟浦浦風。", "眼明無俗物，步蹇有枯筇。", "野逸誰能那，悠然西復東。"]'),
('abe95600-4dcb-4b22-9f67-cf5fe4e0cf86','道室雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','早訪丹砂上岣嶁，晚提河派泝崑崙。',32,'全唐诗/poet.song.132000.json','["早訪丹砂上岣嶁，晚提河派泝崑崙。", "陰符後出君無忽，三百奇文要細論。"]'),
('fae328bc-980f-4b5a-9bdd-7d573c5a44ca','道室雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','聞說湖中有釣舟，烟波出沒雜輕鷗。',32,'全唐诗/poet.song.132000.json','["聞說湖中有釣舟，烟波出沒雜輕鷗。", "一聲清嘯去已遠，我欲從之何處求。"]'),
('4cb4374e-12a1-4e4a-b245-d69c4d62569f','道室雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','山中有草名長生，丹砂可死金可成。',32,'全唐诗/poet.song.132000.json','["山中有草名長生，丹砂可死金可成。", "服之刀圭齒髮換，要看東封告太平。"]'),
('be2ef044-41ae-4781-bdc1-dba6aec95172','道室雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','勘書窗下松明火，采藥溪頭槲葉衣。',32,'全唐诗/poet.song.132000.json','["勘書窗下松明火，采藥溪頭槲葉衣。", "只在人間人不識，秋風又見雁南飛。"]'),
('715eb08d-4131-43d6-b057-7ae6d33598fc','儒生','陸游','宋','宋诗','song-poetry','','[]','儒生安義命，所遇委之天。',48,'全唐诗/poet.song.132000.json','["儒生安義命，所遇委之天。", "用可重九鼎，窮寧直一錢。", "雖云髮種種，未害腹便便。", "高卧茅簷下，羹藜法不傳。"]'),
('b22ff190-7642-4b7d-801a-dadfda260d52','秋夜','陸游','宋','宋诗','song-poetry','','[]','老病睡眠少，如斯秋夜何。',48,'全唐诗/poet.song.132000.json','["老病睡眠少，如斯秋夜何。", "長庚未配月，織女已斜河。", "莎徑蟲吟苦，柴門葉落多。", "誰知窮甯戚，不作飯牛歌。"]'),
('b61bd770-e47f-44e1-94f8-5ae188d59b66','寺閣','陸游','宋','宋诗','song-poetry','','[]','三髽初得牧牛童，兩扇新成釣舸篷。',64,'全唐诗/poet.song.132000.json','["三髽初得牧牛童，兩扇新成釣舸篷。", "偶訪野僧過射的，却衝微雨上樵風。", "登山未減青鞋興，到手俄驚綠酒空。", "自笑此身猶健在，試憑重閣送飛鴻。"]'),
('cc9eb0bc-6686-4d3c-a1c0-fb64fcbb8f99','秋暑夜興','陸游','宋','宋诗','song-poetry','','[]','寂寂空廊絡緯鳴，消摇岸幘近南榮。',64,'全唐诗/poet.song.132000.json','["寂寂空廊絡緯鳴，消摇岸幘近南榮。", "閑眠簟作波紋冷，新浴衣如蟬翼輕。", "微雨已收雲盡散，眾星俱隱月徐行。", "呼童持燭開藤紙，一首清詩取次成。"]'),
('a493b956-e036-4d88-876a-119f734fd191','漁父','陸游','宋','宋诗','song-poetry','','[]','千錢買一舟，百錢買兩槳。',72,'全唐诗/poet.song.132000.json','["千錢買一舟，百錢買兩槳。", "朝看潮水落，暮看潮水長。", "持魚換鹽酪，縣郭時下上。", "亦或得濁醪，不復計瓶盎。", "浩歌忘遠近，醉夢墮莽蒼。", "玄真不可逢，悠然寄遐想。"]'),
('415584ca-d03e-48ee-8ca5-984a579d0ecb','省事','陸游','宋','宋诗','song-poetry','','[]','車馬聲都絕，比鄰迹亦疏。',48,'全唐诗/poet.song.132000.json','["車馬聲都絕，比鄰迹亦疏。", "淺傾家釀酒，細讀手鈔書。", "薄飯惟羹芋，閑遊不借驢。", "有時還自笑，省事更誰如。"]'),
('b1b9758a-76c9-4377-9b3c-69d7fade93b0','新凉書懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','烏帽圍寬带眼移，閉門慣忍日長饑。',64,'全唐诗/poet.song.132000.json','["烏帽圍寬带眼移，閉門慣忍日長饑。", "文章雖愧聲名誤，志節寧隨血氣衰。", "天地無私非困我，聖賢可學有餘師。", "短檠正嘆經時別，凉入郊墟喜可知。"]'),
('b05ae01c-a174-4ed1-b286-9d044857fbfd','新凉書懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','藥物扶持病少蘇，殘年不恨老菰蘆。',64,'全唐诗/poet.song.132000.json','["藥物扶持病少蘇，殘年不恨老菰蘆。", "潦收溪椴魚爭售，歲樂村場酒易沽。", "無日榿林無墜葉，有時燕戶有新雛。", "秋風剩起扁舟興，安得州家復鏡湖。"]'),
('3d4cb038-c15f-4a95-880c-456b63054764','新凉書懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','鄰曲今年又有年，垂髫戴白各欣然。',64,'全唐诗/poet.song.132000.json','["鄰曲今年又有年，垂髫戴白各欣然。", "先輸官庾無逋賦，共賽神祠有社錢。", "退傅寄聲情縝密，晦翁入夢語蟬聯。", "燈前細與兒曹說，蠹簡猶堪數世傳。"]'),
('7b1ea532-9ae5-41a3-be9e-029559ad0dd1','新凉書懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','山川遺迹晉唐餘，水竹相望許洛居。',64,'全唐诗/poet.song.132000.json','["山川遺迹晉唐餘，水竹相望許洛居。", "一齒屢摇猶决肉，雙眸雖澀尚耽書。", "郊原夜夜驅耕犢，村店時時秣蹇驢。", "客問若爲娛老境，吾兒未與短檠疏。"]'),
('1a2a068a-c0b3-43b1-9377-f0a83d203afc','七月十七晚行湖塘雷雨大作','陸游','宋','宋诗','song-poetry','','[]','電火雷車下九關，我行暮出郊原間。',64,'全唐诗/poet.song.132000.json','["電火雷車下九關，我行暮出郊原間。", "鬅鬙暗樹類奇鬼，突兀黑雲如壞山。", "江潮默應鰻岫溢，鐵鎖自脫梅梁還。", "今夕虛簷瀉懸瀑，預知高枕聽淙潺。"]'),
('7028c423-e410-413a-bf9c-5abe95a02002','七月十八夜枕上作','陸游','宋','宋诗','song-poetry','','[]','電掣光如晝，雷轟意未平。',48,'全唐诗/poet.song.132000.json','["電掣光如晝，雷轟意未平。", "亂雲俄卷盡，孤月却徐行。", "露草蛩相語，風枝鵲自驚。", "一凉吾事足，美睡到窗明。"]'),
('690ec506-3942-4c4c-89d5-adbae65283a8','梅市','陸游','宋','宋诗','song-poetry','','[]','梅市柯山小繫船，開篷驚起醉中眠。',64,'全唐诗/poet.song.132000.json','["梅市柯山小繫船，開篷驚起醉中眠。", "橋橫風柳荒寒外，月墮烟鍾縹渺邊。", "客思况經孤驛路，詩情又入早秋天。", "如今老病知何恨，判斷江山六十年。"]'),
('8df18d82-2afb-4bd3-9e43-bc8796589271','秋思','陸游','宋','宋诗','song-poetry','','["\u5411\u5f80", "\u79cb\u5929"]','利欲驅人萬火牛，江湖浪迹一沙鷗。',64,'全唐诗/poet.song.132000.json','["利欲驅人萬火牛，江湖浪迹一沙鷗。", "日長似歲閑方覺，事大如山醉亦休。", "衣杵相望深巷月，井桐摇落故園秋。", "欲舒老眼無高處，安得元龍百尺樓。"]'),
('a054c0d9-a4b7-46f2-9ede-6cf281cf1e82','小舟湖中夜歸追和孟浩然夜歸鹿門歌','陸游','宋','宋诗','song-poetry','','[]','山光漸淡川氣昏，急雨亂打荷葉喧。',64,'全唐诗/poet.song.132000.json','["山光漸淡川氣昏，急雨亂打荷葉喧。", "小舟橫掠湖邊村，人家收網半閉門。", "吾廬未見見堤樹，舟人指點孤燈處。", "蒲叢姑惡最可哀，衝雨飛鳴背人去。"]'),
('787c05c3-54e1-4b89-b12f-c366f717b18d','酒盡','陸游','宋','宋诗','song-poetry','','[]','飲酒但飲溼，吾聞之老坡。',72,'全唐诗/poet.song.132000.json','["飲酒但飲溼，吾聞之老坡。", "渠非惜酒錢，無如久窮何。", "我窮乃過之，空罍倒餘溼。", "日來彌可笑，溼亦不可得。", "平生忍饑多，得飯已有餘。", "父子茅簷下，清坐談詩書。"]'),
('9bf60f93-3af2-4310-a5be-a91751e71029','燒香','陸游','宋','宋诗','song-poetry','','[]','寶熏清夜起氤氳，寂寂中庭伴月痕。',64,'全唐诗/poet.song.132000.json','["寶熏清夜起氤氳，寂寂中庭伴月痕。", "小斮海沉非弄水，旋開山麝取當門。", "蜜房割處春方半，花露收時日未暾。", "安得故人同晤語，一燈相對看雲屯。"]'),
('f5223596-f9a9-4677-8c39-0645bf98cf94','自述二首  其一','陸游','宋','宋诗','song-poetry','','[]','寄懷魚鳥卧烟汀，結友松筠醉草亭。',64,'全唐诗/poet.song.132000.json','["寄懷魚鳥卧烟汀，結友松筠醉草亭。", "拜賜龜章紆舊紫，養成鵠鬢掃餘青。", "遺經在櫝傳家學，大字書牆作座銘。", "浪迹江湖遂終老，此身何啻一浮萍。"]'),
('872b784b-5a5c-4e17-a19c-92235f292868','自述二首  其二','陸游','宋','宋诗','song-poetry','','[]','意望天公本自廉，甘餐美睡偶容兼。',64,'全唐诗/poet.song.132000.json','["意望天公本自廉，甘餐美睡偶容兼。", "一生憂患如山重，此日安閑抵蜜甜。", "拙宦雖無齊虜舌，早歸亦免楚人鉗。", "但餘一味疏慵在，儲藥千斤未易砭。"]'),
('290e4856-bcb3-4b10-9192-6161ed787fde','風雨','陸游','宋','宋诗','song-poetry','','[]','風摇北斗柄欲折，雨溢天河浪正生。',32,'全唐诗/poet.song.132000.json','["風摇北斗柄欲折，雨溢天河浪正生。", "一盞昏燈北窗下，腐儒未輟讀書聲。"]'),
('4eee1167-21ab-40c3-9d9f-1949d374d495','白露前一日已如深秋有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','匹馬曾防玉塞秋，豈知八十老漁舟。',32,'全唐诗/poet.song.132000.json','["匹馬曾防玉塞秋，豈知八十老漁舟。", "非無丈二殳堪請，只恐傍人笑白頭。"]'),
('1e15b094-8ec6-402e-a495-0df554065697','白露前一日已如深秋有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','護塞寧須右北平，拂雲祠是受降城。',32,'全唐诗/poet.song.132000.json','["護塞寧須右北平，拂雲祠是受降城。", "誰知此志成虛語，白首燈前聽雁聲。"]'),
('33796e26-05ca-4d5a-b209-58c0c659fbd3','東村晚歸','陸游','宋','宋诗','song-poetry','','[]','蜀道還吳鬢已絲，歷年二紀固應衰。',64,'全唐诗/poet.song.132000.json','["蜀道還吳鬢已絲，歷年二紀固應衰。", "寧知病思沉綿日，又見秋風摇落時。", "錦雉白魚供野餉，青林紅樹入新詩。", "東村寂寂風烟晚，酒挂驢肩又一奇。"]'),
('f6d9c34a-c59b-4f8d-88c9-6717dcc5f9f1','秋望','陸游','宋','宋诗','song-poetry','','[]','快哉一雨洗浮塵，却喜郊原霽色勻。',64,'全唐诗/poet.song.132000.json','["快哉一雨洗浮塵，却喜郊原霽色勻。", "野火已亡秦相篆，江濤猶託伍胥神。", "登臨頓覺清秋早，流落空悲白髮新。", "東望思陵鬰葱裏，老民猶及見時巡。"]'),
('9002d3fb-c48c-4573-b5d5-aadbc31afa59','郭西','陸游','宋','宋诗','song-poetry','','[]','鵲下川原黑，船行浦溆空。',48,'全唐诗/poet.song.132000.json','["鵲下川原黑，船行浦溆空。", "橋燈摇水影，樓角散天風。", "野眺飛埃外，漁歌冷翠中。", "不須嘲病翼，要是脫樊籠。"]'),
('74869a66-8624-45ce-9c30-551dad76ba28','舍北','陸游','宋','宋诗','song-poetry','','[]','支徑秋原上，衡門夕照中。',48,'全唐诗/poet.song.132000.json','["支徑秋原上，衡門夕照中。", "野烟山半失，溪漲浦橫通。", "鬢禿難藏老，衣穿可諱窮。", "浩歌終自得，心事寄冥鴻。"]'),
('428fdc6b-2c3a-4939-8dab-7ee17f467574','夜坐示子聿','陸游','宋','宋诗','song-poetry','','[]','久客誠當去，無心偶小留。',48,'全唐诗/poet.song.132000.json','["久客誠當去，無心偶小留。", "掃空閑夢想，閱盡舊朋儔。", "學術非時好，文章幸自由。", "不嫌秋夜永，問事有長頭。"]'),
('afd845e4-9804-4e60-8ad9-d1e7487e562c','柳橋晚眺','陸游','宋','宋诗','song-poetry','','[]','小浦聞魚躍，橫林待鶴歸。',24,'全唐诗/poet.song.132000.json','["小浦聞魚躍，橫林待鶴歸。", "閑雲不成雨，故傍碧山飛。"]'),
('641f5497-ffef-4f4c-8ce8-9bffe6ddc3a4','秋興五首  其一','陸游','宋','宋诗','song-poetry','','[]','秋風吹我夜，植杖溪橋側。',24,'全唐诗/poet.song.132000.json','["秋風吹我夜，植杖溪橋側。", "木葉雖未凋，慘澹無顔色。"]'),
('d6becb4d-de34-4d32-89e3-56c81408eb63','秋興五首  其二','陸游','宋','宋诗','song-poetry','','[]','功名不垂世，富貴但堪傷。',24,'全唐诗/poet.song.132000.json','["功名不垂世，富貴但堪傷。", "底事杜陵老，時時矜省郎。"]'),
('2cdf626d-316a-4b6f-aa25-44c685b0738d','秋興五首  其三','陸游','宋','宋诗','song-poetry','','[]','秋暑勢已窮，風雨縱橫至。',24,'全唐诗/poet.song.132000.json','["秋暑勢已窮，風雨縱橫至。", "白鷺立清灘，與我俱得意。"]'),
('2ce4d507-bdbf-45af-964b-dc5257d85655','秋興五首  其四','陸游','宋','宋诗','song-poetry','','[]','胸中萬卷書，一字用不著。',24,'全唐诗/poet.song.132000.json','["胸中萬卷書，一字用不著。", "歸休始太息，竟是爲農樂。"]'),
('892a5105-c12d-4023-a57a-52c78e70f61d','秋興五首  其五','陸游','宋','宋诗','song-poetry','','[]','酌酒桑陰下，邠風入醉歌。',24,'全唐诗/poet.song.132000.json','["酌酒桑陰下，邠風入醉歌。", "何須繩檢外，名教樂還多。"]'),
('98881a3a-f789-483a-9b78-3559f8b9d0fc','嘉泰辛酉八月四日雨後殊凄冷新雁已至夜復風雨不止是歲八月一日白露二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘暑方炎忽痛摧，無情風雨亦奇哉。',32,'全唐诗/poet.song.132000.json','["殘暑方炎忽痛摧，無情風雨亦奇哉。", "但嗟不爲貧人計，未動秋砧雁已來。"]'),
('cf682afb-1b32-4134-846c-86044a5f67ff','嘉泰辛酉八月四日雨後殊凄冷新雁已至夜復風雨不止是歲八月一日白露二首  其二','陸游','宋','宋诗','song-poetry','','[]','仲秋四日雁橫天，閉戶垂帷意已便。',32,'全唐诗/poet.song.132000.json','["仲秋四日雁橫天，閉戶垂帷意已便。", "方嘆今年時候早，夜深風雨更凄然。"]'),
('61de4dbe-9f92-4e6e-8011-db122731987e','近村民舍小飲','陸游','宋','宋诗','song-poetry','','[]','秋風吹細雨，蕭然濯炎熾。',144,'全唐诗/poet.song.132000.json','["秋風吹細雨，蕭然濯炎熾。", "老夫疾頓平，甘食仍熟寐。", "春物財幾何，摇落已復至。", "昔人喻死生，謂若屈伸臂。", "愚公顧不靈，白首沒榮利。", "嗟予幸學道，了此直差易。", "三拜散人號，退志獲早遂。", "弦歌萬二千，盡力不能祟。", "瘦驢骨可數，渺渺入空翠。", "霜蟹初把螯，絲蓴小添豉。", "平生笑巨君，老嚙乾肉糒。", "異味幸滿前，萬事付一醉。"]'),
('e01ce98f-b315-4060-8973-c558a6327a18','閑適二首  其一','陸游','宋','宋诗','song-poetry','','[]','飲酒不至狂，對客不至疲。',72,'全唐诗/poet.song.132000.json','["飲酒不至狂，對客不至疲。", "讀書以自娛，不强所不知。", "一窗袖手坐，往往晝漏移。", "初非能養生，簡事頗似之。", "四時俱可喜，最好新秋時。", "柴門傍野水，鄰叟閑相期。"]'),
('cf6fdeeb-c1e1-45cc-817d-9b7aa03a15f2','閑適二首  其二','陸游','宋','宋诗','song-poetry','','[]','陸子居山陰，杜門輒經年。',72,'全唐诗/poet.song.132000.json','["陸子居山陰，杜門輒經年。", "有時思出遊，兩屨凌風烟。", "長鑱斸靈苗，大瓢挹飛泉。", "眼長不及寸，能著萬里天。", "不飲顔常丹，不食腹果然。", "金丹亦棄置，我是地行仙。"]'),
('fe3d4943-461f-4b0a-9eda-bd6634651d87','夜歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','今年寒到江鄉早，未及中秋見雁飛。',32,'全唐诗/poet.song.132000.json','["今年寒到江鄉早，未及中秋見雁飛。", "八十老翁頑似鐵，三更風雨采菱歸。"]'),
('ba019e1e-e35c-483e-a7e7-4d672e43c8d9','夜歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','芡浦菱陂夜半時，小舟更著疾風吹。',32,'全唐诗/poet.song.132000.json','["芡浦菱陂夜半時，小舟更著疾風吹。", "青熒一炬楓林外，鬼火漁燈兩不知。"]'),
('d8ce509d-0759-4947-bd93-8f347a40052c','自詠','陸游','宋','宋诗','song-poetry','','[]','宦遊疇昔徧天涯，萬里東歸歲月賒。',64,'全唐诗/poet.song.132000.json','["宦遊疇昔徧天涯，萬里東歸歲月賒。", "古道泥塗居士屩，荒畦烟雨故侯瓜。", "園公谿父逢皆友，野寺山郵到即家。", "病思漸輕重九近，又將烏帽插黄花。"]'),
('e1d04a6d-3979-4d17-a6d8-cf34c01ef193','老歎','陸游','宋','宋诗','song-poetry','','[]','一齒危將墮，雙瞳久已昏。',48,'全唐诗/poet.song.132000.json','["一齒危將墮，雙瞳久已昏。", "謀生賴蔬圃，養拙閉柴門。", "多病從來慣，虛名不足論。", "自憐餘一念，猶欲濟元元。"]'),
('bf90055b-39be-4cbb-b4e8-b6f3adb68e73','秋社','陸游','宋','宋诗','song-poetry','','[]','雨餘殘日照庭槐，社鼓鼕鼕賽廟回。',64,'全唐诗/poet.song.132000.json','["雨餘殘日照庭槐，社鼓鼕鼕賽廟回。", "又見神盤分肉至，不堪沙雁带寒來。", "書因忌作閑終日，酒爲治聾醉一杯。", "記取鏡湖無限景，蘋花零落蓼花開。"]'),
('58a062e5-046b-4fea-93c4-5b567e74a0f2','晨起','陸游','宋','宋诗','song-poetry','','[]','雞已參差唱，窗纔曨{日悤}明。',51,'全唐诗/poet.song.132000.json','["雞已參差唱，窗纔曨{日悤}明。", "高林風不止，叢竹露如傾。", "夢爲多難記，詩緣嬾少成。", "晨興了無事，散髮遶堦行。"]'),
('75580bb5-c0ee-43a6-82e2-298c52548543','中夜睡覺兩目每有光如初日歷歷照物晁文元公自謂養生之驗予則偶然耳感而有作','陸游','宋','宋诗','song-poetry','','[]','人情所願欲，莫若貴與富。',288,'全唐诗/poet.song.132000.json','["人情所願欲，莫若貴與富。", "是皆有命焉，非力可成就。", "予昔未有聞，無與發其覆。", "趦趄强干祿，時命適大謬。", "方行蛇當道，未至獒已嗾。", "適燕乃南轅，之楚顧北首。", "風波起平地，兩耳厭嘲詬。", "隴蜀萬里餘，數遍道傍堠。", "六十歸爲郎，數月草章奏。", "夫豈或使之，擊去惟恐後。", "嗟彼亦何心，喜慍出邂逅。", "還山惟自訟，衡茅屏幽陋。", "乘除得少健，上下歷巖岫。", "得飽豈復擇，百口同飯糗。", "寒龜久猶息，野鶴老益瘦。", "又如已放馬，寧當夢華廐。", "造物念途窮，畀以樗櫟壽。", "雖無熊鳥術，坐空陰陽寇。", "兩眥若有光，夜視如正晝。", "物生稟定數，此語聞自舊。", "置冰鳥覆翼，棄野於菟穀。", "偶然當後死，鬼錄自遺漏。", "山陂粟屢收，池水麻可漚。", "鄰父相歡娛，席地醉醇酎。"]'),
('5074e836-98cd-47c6-8f96-dac119292ca7','錢道人不飲酒食肉囊中不畜一錢所須飯及草屨二物皆臨時乞錢買之非此雖强與不取也二首  其一','陸游','宋','宋诗','song-poetry','','[]','萬里飄如不繫船，空囊短褐過年年。',32,'全唐诗/poet.song.132000.json','["萬里飄如不繫船，空囊短褐過年年。", "食時無飯芒鞋破，只向街頭旋乞錢。"]'),
('6306c983-0ef9-4bac-9a8f-80e705608248','錢道人不飲酒食肉囊中不畜一錢所須飯及草屨二物皆臨時乞錢買之非此雖强與不取也二首  其二','陸游','宋','宋诗','song-poetry','','[]','誤辱君王賜鏡湖，身隨鷗鷺寄菰蒲。',32,'全唐诗/poet.song.132000.json','["誤辱君王賜鏡湖，身隨鷗鷺寄菰蒲。", "行年八十猶强健，欲伴先生去得無。"]'),
('efe5018b-0336-4c85-b73f-9e7d9175c007','枕上','陸游','宋','宋诗','song-poetry','','[]','呼兒初夜上門關，怕冷貪眠自笑孱。',64,'全唐诗/poet.song.132000.json','["呼兒初夜上門關，怕冷貪眠自笑孱。", "月色橫分窗一半，秋聲正在樹中間。", "暮年不復樽前樂，浮世無如枕上閑。", "鍊句未安姑棄置，明朝追記尚班班。"]'),
('b8799597-604d-4852-8487-950156739791','山園書觸目','陸游','宋','宋诗','song-poetry','','[]','山近雲生易，人稀鳥下頻。',48,'全唐诗/poet.song.132000.json','["山近雲生易，人稀鳥下頻。", "瘦篁穿石竅，古蔓絡松身。", "熟摘巖邊果，乾收澗底薪。", "經過不相識，喚作避秦人。"]'),
('f712ac85-9d19-4c01-8b1e-44f590a74547','苦貧戲作','陸游','宋','宋诗','song-poetry','','[]','五窮作祟不容支，蟬腹龜腸旋過時。',64,'全唐诗/poet.song.132000.json','["五窮作祟不容支，蟬腹龜腸旋過時。", "客散難求門外轍，衣穿徒有鬢邊絲。", "兒能解事甘藜藿，婢苦無薪睨扊扅。", "箕踞浩歌君會否，書癡終覺勝錢癡。"]'),
('dc5671f8-7471-4b47-af63-00bcd22e514a','秋曉書感','陸游','宋','宋诗','song-poetry','','[]','天公息我半生勞，寄傲江湖亦足豪。',64,'全唐诗/poet.song.132000.json','["天公息我半生勞，寄傲江湖亦足豪。", "淡盡月痕知夜艾，飄殘桐葉喜秋高。", "讀書時亦挂牛角，對酒正須持蟹螯。", "縱有故人終自絕，安能從汝望綈袍。"]'),
('620b629f-53f4-40b6-8a2a-c2359ff03b4c','秋夜','陸游','宋','宋诗','song-poetry','','[]','抱病齒髮非，閱世城市換。',96,'全唐诗/poet.song.132000.json','["抱病齒髮非，閱世城市換。", "朋儕冢纍纍，在者亦雲散。", "窮居懶出戶，俯仰秋已半。", "疏鐘到倦枕，微火耿幽幔。", "平生疑著處，忽若河冰泮。", "百年寓逆旅，萬事真既灌。", "紛紛彼方寱，袖手不須喚。", "蘿月忽滿窗，悠然付長嘆。"]'),
('a93b56f5-1da4-458b-9414-fb2d2b5852cd','村舍二首  其一','陸游','宋','宋诗','song-poetry','','[]','篠屋楓林下，柴門芡浦旁。',48,'全唐诗/poet.song.132000.json','["篠屋楓林下，柴門芡浦旁。", "先鳴雞腷膊，徐上日蒼凉。", "服藥貧寧輟，觀書老有常。", "仍須教童稚，世世力耕桑。"]'),
('5351fd7f-8e12-4347-b3d3-ec5bd49914f6','村舍二首  其二','陸游','宋','宋诗','song-poetry','','[]','生理嗟彌薄，吾居久未完。',48,'全唐诗/poet.song.132000.json','["生理嗟彌薄，吾居久未完。", "蝶飛窗紙碎，龜坼壁泥乾。", "小雨牛欄溼，微霜碓舍寒。", "晚禾蟲獨少，鄰里共相寬。"]'),
('34bb3ddb-a237-455e-af90-b6ef8cfd231b','天凉時往來湖山間有作','陸游','宋','宋诗','song-poetry','','[]','萬壑千巖自古傳，青鞋布襪更誰先。',64,'全唐诗/poet.song.132000.json','["萬壑千巖自古傳，青鞋布襪更誰先。", "泛舟菰脆鱸肥地，把酒橙黄橘綠天。", "秦篆舊碑荒草棘，禹書遺穴慘風烟。", "誰知陸子登臨日，已近浮生八十年。"]'),
('eddecf06-af29-46c1-a942-d676ff14238f','雨夜嘆','陸游','宋','宋诗','song-poetry','','[]','秋雨何曾住一滴，老夫危坐欲三更。',64,'全唐诗/poet.song.132000.json','["秋雨何曾住一滴，老夫危坐欲三更。", "開元貞觀事誰問，溫洛榮河塵未清。", "豐年猶有餓死慮，破屋自愛讀書聲。", "刺經作制豈不美，無奈人間痛哭生。"]'),
('871fd12c-409d-42ae-8977-fcd2853dbdd6','病足晝卧夢中譫諄乃誦尚書也既覺口占絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','唐虞已遠三千歲，每誦遺書涕泗潸。',32,'全唐诗/poet.song.132000.json','["唐虞已遠三千歲，每誦遺書涕泗潸。", "濟濟九官十二牧，我獨不得居其間。"]'),
('e76d567f-b3da-43b2-b818-181f52c4dd6c','病足晝卧夢中譫諄乃誦尚書也既覺口占絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','人能不食十二日，惟書安可一日無。',32,'全唐诗/poet.song.132000.json','["人能不食十二日，惟書安可一日無。", "唐虞雖遠典謨在，病卧蓬窗時囁嚅。"]'),
('7ce50652-272e-43ac-97ca-89e0681a6b12','新買啼雞','陸游','宋','宋诗','song-poetry','','[]','峨峨赤幘聲甚雄，意氣不與其曹同。',160,'全唐诗/poet.song.132000.json','["峨峨赤幘聲甚雄，意氣不與其曹同。", "我求長鳴久未獲，一見便覺千群空。", "主人燒神議已决，知我此意遽見從。", "秋衣初縫惜不得，急典三百新青銅。", "憐渠亦復解人意，來宿庭樹不待籠。", "狐狸熟睨那敢犯，蕭蕭清露和微風。", "五更引吭震戶牖，橫梃無復須元戎。", "明星已高啼未已，雲際騰上朝陽紅。", "老夫抱病氣已索，賴汝豪壯生胸中。", "明朝舂黍得碎粒，第一當冊司晨功。"]'),
('821d67e5-93fd-4c72-9b3c-28fdcac44a29','幽棲二首  其一','陸游','宋','宋诗','song-poetry','','[]','幽棲少人客，積病得衰殘。',48,'全唐诗/poet.song.132000.json','["幽棲少人客，積病得衰殘。", "身納分司祿，兒須遠次官。", "新寒換衣典，閑日借書觀。", "更嘆秋來瘦，晨興覺帽寬。"]'),
('8305ecc3-694c-42f8-87cc-400fa8c8453e','幽棲二首  其二','陸游','宋','宋诗','song-poetry','','[]','自卜幽棲地，頻驚歲月移。',48,'全唐诗/poet.song.132000.json','["自卜幽棲地，頻驚歲月移。", "鄉鄰崇禮讓，子弟習書詩。", "喔喔雞鳴樹，狺狺犬吠籬。", "謀生已過足，富貴亦何爲。"]'),
('1f38aa50-97df-484a-a890-1de30ac677d9','秋日雜詠八首  其一','陸游','宋','宋诗','song-poetry','','[]','都門初出若登仙，弄水穿雲喜欲顛。',32,'全唐诗/poet.song.132000.json','["都門初出若登仙，弄水穿雲喜欲顛。", "只恐光陰已無幾，不知又過十三年。"]'),
('e1711529-7e57-4b45-8443-f77923b5dce6','秋日雜詠八首  其二','陸游','宋','宋诗','song-poetry','','[]','五百年前賀季真，再來依舊作閑人。',32,'全唐诗/poet.song.132000.json','["五百年前賀季真，再來依舊作閑人。", "一生看盡佳風月，不負湖山不負身。"]'),
('269ec293-3cd1-4e46-8c30-6a12235f34b4','秋日雜詠八首  其三','陸游','宋','宋诗','song-poetry','','[]','菰蒲風起暮蕭蕭，烟斂林疏見斷橋。',32,'全唐诗/poet.song.132000.json','["菰蒲風起暮蕭蕭，烟斂林疏見斷橋。", "白蟹䱥魚初上市，輕舟無數去乘潮。"]'),
('6efd9940-eacf-478e-85bd-35915a37041a','秋日雜詠八首  其四','陸游','宋','宋诗','song-poetry','','[]','葉底珍禽不受呼，弄風小蝶點殘蕪。',32,'全唐诗/poet.song.132000.json','["葉底珍禽不受呼，弄風小蝶點殘蕪。", "舍南舍北秋光好，到處皆成一畫圖。"]'),
('ee013abc-0892-43bc-95f5-61167ef99fc7','秋日雜詠八首  其五','陸游','宋','宋诗','song-poetry','','[]','紅莧如丹照眼明，卧開石竹亂縱橫。',32,'全唐诗/poet.song.132000.json','["紅莧如丹照眼明，卧開石竹亂縱橫。", "騷人見處終然別，只說清秋采落英。"]'),
('f3cbc503-c61a-4027-bfec-4a269b596fb4','秋日雜詠八首  其六','陸游','宋','宋诗','song-poetry','','[]','桐葉吹殘柳亦稀，溪頭倚杖立斜暉。',32,'全唐诗/poet.song.132000.json','["桐葉吹殘柳亦稀，溪頭倚杖立斜暉。", "誰知老子無窮喜，待得吾兒小艇歸。"]'),
('388f008f-f37b-464e-b63a-b2f3e8a363d4','秋日雜詠八首  其七','陸游','宋','宋诗','song-poetry','','[]','久雨初晴喜欲迷，青鞋踏徧舍東西。',32,'全唐诗/poet.song.132000.json','["久雨初晴喜欲迷，青鞋踏徧舍東西。", "忽然來到柳橋下，露溼蓼花紅一溪。"]'),
('22a71999-2816-4741-b581-60e54b8af378','秋日雜詠八首  其八','陸游','宋','宋诗','song-poetry','','[]','十里秋風畫角哀，夕陽光景亦佳哉。',32,'全唐诗/poet.song.132000.json','["十里秋風畫角哀，夕陽光景亦佳哉。", "正疑白鷺歸何晚，一片雪從天際來。"]'),
('defb6034-7e13-4977-a5f7-7ac0c5d6d54a','望永阜陵','陸游','宋','宋诗','song-poetry','','[]','龍飛回首尚如新，忽閱人間四十春。',64,'全唐诗/poet.song.132000.json','["龍飛回首尚如新，忽閱人間四十春。", "聖主已嚴天上駕，孤臣歸作道傍民。", "傾河尚恨難供泪，衛社何由得致身。", "獨立秋風吹白髮，感恩肝膽漫輪囷。"]'),
('991c00ba-344b-4e94-b67b-b31e7dc02f7b','排悶','陸游','宋','宋诗','song-poetry','','[]','悠然不覺歲時遷，楚水楓林繫釣船。',64,'全唐诗/poet.song.132000.json','["悠然不覺歲時遷，楚水楓林繫釣船。", "貧悴只如行卷日，衰遲忽過挂冠年。", "閑遊野寺騎驢去，倦擁殘書聽雨眠。", "賴有一籌差自慰，小兒筆墨日翩翩。"]'),
('14a39883-0df2-424f-8675-a0e22c8c0263','秋日晨起','陸游','宋','宋诗','song-poetry','','[]','翻樹鴉知旦，橫空雁戒寒。',48,'全唐诗/poet.song.132000.json','["翻樹鴉知旦，橫空雁戒寒。", "但欣蘇肺渴，未暇議衣單。", "粥鼎湯初沸，香篝火半殘。", "讀書心漸懶，顧影一長嘆。"]'),
('5d228dc8-7ff4-40c1-b2e2-c1dceaacdea8','出遊暮歸戲作','陸游','宋','宋诗','song-poetry','','[]','終年兀兀復騰騰，眼看朱門幾廢興。',64,'全唐诗/poet.song.132000.json','["終年兀兀復騰騰，眼看朱門幾廢興。", "造物偶容窮不死，眾人共養老無能。", "逢山自有閑遊侶，入寺寧無淡話僧。", "莫道歸來却岑寂，小兒同守短檠燈。"]'),
('25e9640f-0a4d-499e-9dbb-530fec0a029a','自詒','陸游','宋','宋诗','song-poetry','','[]','荒圃風烟入荷鉏，孤村巷陌看騎驢。',64,'全唐诗/poet.song.132000.json','["荒圃風烟入荷鉏，孤村巷陌看騎驢。", "少年曾縱千場醉，老境惟存一束書。", "作意買山雖已矣，忍慚乞米獨何歟。", "所欣肺病秋來減，白髮蕭蕭可自梳。"]'),
('12cebd9f-e9a4-42a2-bb24-7800c1600259','予出蜀日嘗遣僧則華乞籤于射洪陸使君祠使君以老杜詩爲籤予得遣興詩五首中第二首其言教戒甚至退休暇日因用韵賦五首  其一','陸游','宋','宋诗','song-poetry','','[]','我幼入家塾，結髮知苦心。',60,'全唐诗/poet.song.132000.json','["我幼入家塾，結髮知苦心。", "稍長謬聞道，篤守至于今。", "淡然朱絲弦，三嘆有遺音。", "詎敢負所學，枉尺求直尋。", "彼哉孔光輩，千載污儒林。"]'),
('ff96666f-dfc0-4026-9ff5-8fd59156377e','予出蜀日嘗遣僧則華乞籤于射洪陸使君祠使君以老杜詩爲籤予得遣興詩五首中第二首其言教戒甚至退休暇日因用韵賦五首  其二','陸游','宋','宋诗','song-poetry','','[]','童子丹元家，湛然居靈府。',60,'全唐诗/poet.song.132000.json','["童子丹元家，湛然居靈府。", "世人不少悟，役役徒自苦。", "江湖豈不廣，魚乃投數罟。", "是身如璞玉，要經大火聚。", "萬卷讀丹經，孰能精去取。"]'),
('0c9d1d7a-a828-448d-8088-be388776e41b','予出蜀日嘗遣僧則華乞籤于射洪陸使君祠使君以老杜詩爲籤予得遣興詩五首中第二首其言教戒甚至退休暇日因用韵賦五首  其三','陸游','宋','宋诗','song-poetry','','[]','少壯不自料，慷慨志四方。',60,'全唐诗/poet.song.132000.json','["少壯不自料，慷慨志四方。", "謝病還故山，始覺白日長。", "命薄類蟬翼，功名安可望。", "狐狸不足問，力不當豺狼。", "惟有卧釣船，仰看白鷺行。"]'),
('2fbbc6b1-2d4f-4f41-a957-97913230ef44','予出蜀日嘗遣僧則華乞籤于射洪陸使君祠使君以老杜詩爲籤予得遣興詩五首中第二首其言教戒甚至退休暇日因用韵賦五首  其四','陸游','宋','宋诗','song-poetry','','[]','孤雲起江郊，萬木酣天風。',60,'全唐诗/poet.song.132000.json','["孤雲起江郊，萬木酣天風。", "水鳥何所恨，終夜號菰叢。", "我興視中庭，北斗挂寒空。", "誰言秋夜長，明星已生東。", "丈夫老憂國，百慮蟠胸中。"]'),
('724cd2a7-f3be-4e76-8b68-0bd54e65e2ec','予出蜀日嘗遣僧則華乞籤于射洪陸使君祠使君以老杜詩爲籤予得遣興詩五首中第二首其言教戒甚至退休暇日因用韵賦五首  其五','陸游','宋','宋诗','song-poetry','','[]','我昔遊青城，萬仞窮躋攀。',60,'全唐诗/poet.song.132000.json','["我昔遊青城，萬仞窮躋攀。", "巢居上官翁，許我分半山。", "且言牡丹平，可卜茅三間。", "報國未能忘，承詔遂東還。", "蹭蹬意何成，看雲徒汗顔。"]'),
('e288e0b6-391b-4286-bcf5-cb12d8726344','悲歌行','陸游','宋','宋诗','song-poetry','','[]','有口但可讀離騷，有手但可持蟹螯。',160,'全唐诗/poet.song.132000.json','["有口但可讀離騷，有手但可持蟹螯。", "人生墮地各有命，窮達禍福隨所遭。", "嗟予一世蹈謗藪，洶如八月秋江濤。", "尊拳纔奮肋已碎，曹射箭盡弓未弢。", "形尪骨悴吹可倒，摧拉未足稱雄豪。", "一身百憂偶得活，殘年幸許歸蓬蒿。", "時時照水輒自笑，霜顱雪頷不可薅。", "脫身仕路棄衫笏，如病癬疥逢爬搔。", "見事苦遲已莫悔，監戒尚可貽兒曹。", "勉騎款段乘下澤，州縣豈必真徒勞。"]'),
('cac9b261-f7c9-44c2-b582-75fd8ef35cdd','秋夜讀書','陸游','宋','宋诗','song-poetry','','[]','門前客三千，帳下兵十萬。',120,'全唐诗/poet.song.132000.json','["門前客三千，帳下兵十萬。", "人生可意事，隨手風雨散。", "不如一編書，相伴過昏旦。", "豈惟洗貧病，亦足捍患難。", "老夫垂八十，巖電尚爛爛。", "孤燈對細字，堅坐常夜半。", "吾兒幸能繼，書亦未殘斷。", "安知不遭時，清廟薦玉瓚。", "不然老空山，亦足化里閈。", "我死斯言存，觀者有追嘆。"]'),
('9b6eea82-0e2c-4dcc-883e-281e33cf10f6','對食戲詠','陸游','宋','宋诗','song-poetry','','[]','一飽欣逢歲小穰，時憑野餉誑枯腸。',64,'全唐诗/poet.song.132000.json','["一飽欣逢歲小穰，時憑野餉誑枯腸。", "橙黄出臼金齏美，菰脆供盤玉片香。", "客送輪囷霜後蟹，僧分磊落社前薑。", "秋來幸是身强健，聊爲佳時舉一觴。"]'),
('aade5acc-8e98-4f48-894c-cbac5bcc9f65','懷昔','陸游','宋','宋诗','song-poetry','','[]','偶住人間日月長，細思方覺少年狂。',64,'全唐诗/poet.song.132000.json','["偶住人間日月長，細思方覺少年狂。", "眾中論事歸多悔，醉後題詩醒已忘。", "鼉作鯨吞吁莫測，谷堙山塹浩難量。", "老來境界全非昨，卧看縈簾一縷香。"]'),
('ab518082-46aa-4223-ae24-cc6b4e0598b8','偶得雙鯽二首  其一','陸游','宋','宋诗','song-poetry','','[]','今朝溪女留鮮鯽，灑掃茅簷旋置樽。',32,'全唐诗/poet.song.132000.json','["今朝溪女留鮮鯽，灑掃茅簷旋置樽。", "養老不須煩祝鯁，從來楚俗慣魚飧。"]'),
('07c59f47-dafe-4e71-baa6-7f1598629fb5','偶得雙鯽二首  其二','陸游','宋','宋诗','song-poetry','','[]','酒興森然不可回，重陽未到菊先開。',32,'全唐诗/poet.song.132000.json','["酒興森然不可回，重陽未到菊先開。", "一雙鱍剌明吾眼，催喚厨人斫鱠來。"]'),
('bd2da9e7-d93a-4345-a655-f3ba75ba7357','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其一','陸游','宋','宋诗','song-poetry','','[]','我非王子猷，賦性亦愛竹。',48,'全唐诗/poet.song.132000.json','["我非王子猷，賦性亦愛竹。", "舍外地十畝，不藝凡草木。", "長吟雜清嘯，觸目皆此族。", "更招竹林人，枕藉糟與麯。"]'),
('0dd969dc-df34-420c-90f9-9fc5875e2a47','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其二','陸游','宋','宋诗','song-poetry','','[]','短裘入重雲，長鑱求靈藥。',48,'全唐诗/poet.song.132000.json','["短裘入重雲，長鑱求靈藥。", "人葠四體具，狗杞群吠惡。", "采實去條枚，摘花棄跗萼。", "長嘯忽躡空，天台赴幽約。"]'),
('bbeaef45-806d-4725-beac-6ad664d08bb5','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其三','陸游','宋','宋诗','song-poetry','','[]','惟王居法宮，玉帛來四裔。',48,'全唐诗/poet.song.132000.json','["惟王居法宮，玉帛來四裔。", "一朝啟戎心，邊城或晝閉。", "養生能體此，皆可閱千歲。", "利欲喜乘人，日夜勤自勵。"]'),
('a792c4b2-d1f7-4f68-9ac2-197a23478f8b','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其四','陸游','宋','宋诗','song-poetry','','[]','飲酒可不病，自酌隨淺深。',48,'全唐诗/poet.song.132000.json','["飲酒可不病，自酌隨淺深。", "處世可無患，惟勿欺此心。", "此心實通天，一念天所臨。", "子能守吾言，可度豺虎林。"]'),
('b37cb501-a50e-41c1-9799-db5ec6889bd8','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其五','陸游','宋','宋诗','song-poetry','','[]','吾道久寂寞，不絕如一線。',48,'全唐诗/poet.song.132000.json','["吾道久寂寞，不絕如一線。", "至人隱市塵，我輩何由見。", "安得世外士，與之共談宴。", "僧話亦或佳，聊可過竹院。"]'),
('f5fb4051-2789-4c08-8664-79be3cffcc92','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其六','陸游','宋','宋诗','song-poetry','','[]','小人方盛時，瓦礫視黄金。',48,'全唐诗/poet.song.132000.json','["小人方盛時，瓦礫視黄金。", "及其大勢去，或不遺一簪。", "郿塢今尚存，遺戒豈不深。", "所以栗里翁，惟蓄一素琴。"]'),
('af502334-182c-44b4-9e70-649c4c458efd','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其七','陸游','宋','宋诗','song-poetry','','[]','世事本何常，賀吊更在門。',48,'全唐诗/poet.song.132000.json','["世事本何常，賀吊更在門。", "棄爲溝中斷，亦何羨犧樽。", "禍福要其終，愚智始可言。", "君看驪山墓，何若楊王孫。"]'),
('41666a97-0635-46f3-9c52-7e7527160011','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其八','陸游','宋','宋诗','song-poetry','','[]','今日天微寒，處處菊花開。',48,'全唐诗/poet.song.132000.json','["今日天微寒，處處菊花開。", "永懷杜拾遺，抱病起登臺。", "古路逢僧過，溼雲聞雁來。", "我亦秋風客，詩成有餘哀。"]'),
('73049e7b-b2d6-4d1d-b70e-f55138382d1c','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其九','陸游','宋','宋诗','song-poetry','','[]','天鏡環千峰，蒼翠立雲表。',48,'全唐诗/poet.song.132000.json','["天鏡環千峰，蒼翠立雲表。", "漁舟破浪來，泛泛一葉小。", "雲門若耶間，迨此素秋杪。", "登覽不可遲，去若孤鴻矯。"]'),
('2722bf0c-7d94-4fef-91a3-9927733e3a4d','秋懷十首以竹藥閉深院琴樽開小軒爲韵  其一○','陸游','宋','宋诗','song-poetry','','[]','丈夫素所學，致主齊羲軒。',48,'全唐诗/poet.song.132000.json','["丈夫素所學，致主齊羲軒。", "恨無同志人，徒欲起九原。", "痛哭驚世俗，著書成空言。", "歲月去衮衮，吾其死空村。"]'),
('648f0925-2986-4df1-8a1e-acca14600524','示客','陸游','宋','宋诗','song-poetry','','[]','枳縛藩籬荆作門，蕭條何以致諸君。',64,'全唐诗/poet.song.132000.json','["枳縛藩籬荆作門，蕭條何以致諸君。", "歸休正得求吾志，老病猶能誦所聞。", "紫蟹迎霜徑盈尺，白魚脫水重兼斤。", "一杯瀲灧無辭醉，秋稼登場合策勳。"]'),
('27823325-d8b5-4694-9fcc-382f17b16d4a','秋晚村舍雜詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','村巷翳桑麻，蕭然野老家。',48,'全唐诗/poet.song.132000.json','["村巷翳桑麻，蕭然野老家。", "園丁種冬菜，鄰女賣秋茶。", "啄木矜奇服，牽牛蔓碧花。", "一樽雖草草，笑語且喧譁。"]'),
('9c6668cb-d572-4d84-88bf-d54268dcad2f','秋晚村舍雜詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','秋晚年中熟，湖鄉未寂寥。',48,'全唐诗/poet.song.132000.json','["秋晚年中熟，湖鄉未寂寥。", "步頭橫畫舫，柳外出朱橋。", "潮壯知多蟹，霜遲不損蕎。", "家家新釀美，鄰里遞相邀。"]'),
('2770164e-552e-4250-8ebc-f011b1c2791b','卧病累日羸甚偶復小健戲作三首  其一','陸游','宋','宋诗','song-poetry','','[]','病忽迨旬日，衰如增十年。',48,'全唐诗/poet.song.132000.json','["病忽迨旬日，衰如增十年。", "難求秦緩藥，空負宋清錢。", "微火秋先跨，閑房晝亦眠。", "偶賒書鬼錄，遇酒又陶然。"]'),
('55f0a066-7279-413e-93f2-88e3993bff8d','卧病累日羸甚偶復小健戲作三首  其二','陸游','宋','宋诗','song-poetry','','[]','伏枕瀕九死，下床如再生。',48,'全唐诗/poet.song.132000.json','["伏枕瀕九死，下床如再生。", "幸回蒿里駕，猶作越吟聲。", "拂几嗟塵積，開書覺眼明。", "淖糜方自養，未敢憶南烹。"]'),
('3d231798-5e0d-4450-b8a8-428ebbcb736f','卧病累日羸甚偶復小健戲作三首  其三','陸游','宋','宋诗','song-poetry','','[]','行年當大耋，卧病涉高秋。',48,'全唐诗/poet.song.132000.json','["行年當大耋，卧病涉高秋。", "丸藥作奇驗，俶裝仍小留。", "輕漚元泛泛，破屋已颼颼。", "尚有江湖興，沙頭問釣舟。"]'),
('60b22b04-5804-4a45-a4ae-16bf8322a70d','縱筆四首  其一','陸游','宋','宋诗','song-poetry','','[]','莫笑畸翁迫耄期，從來不許俗人知。',64,'全唐诗/poet.song.132000.json','["莫笑畸翁迫耄期，從來不許俗人知。", "繫船慣聽巴東雨，畫策曾從渭北師。", "袖劍客同樓上醉，爛柯人看洞中棋。", "如今更欲滄溟去，鯨浪浮天信所之。"]'),
('4cc82e4b-07fe-4e45-8f36-3044341afcf9','縱筆四首  其二','陸游','宋','宋诗','song-poetry','','[]','常笑相如賦上林，肯爲子政鑄黄金。',64,'全唐诗/poet.song.132000.json','["常笑相如賦上林，肯爲子政鑄黄金。", "心光自發誰能障，踵息無聲不厭深。", "摇齒復牢堪决肉，枯顱再茁已勝簪。", "老松澗底雖終棄，霜雪元知不解侵。"]'),
('d4e4a1bf-0d46-48a4-847c-47069dd125e5','縱筆四首  其三','陸游','宋','宋诗','song-poetry','','[]','拖得烏藤到處行，看山看水眼猶明。',64,'全唐诗/poet.song.132000.json','["拖得烏藤到處行，看山看水眼猶明。", "但期少健遊潼華，豈必長生似老彭。", "一緉青鞋吾事了，半甔綠酒萬緣輕。", "安知不作希夷叟，生長兵間老太平。"]'),
('48defb5b-0092-45cd-ac18-5531fb196525','縱筆四首  其四','陸游','宋','宋诗','song-poetry','','[]','未說無功爵位叨，昔人所畏在功高。',64,'全唐诗/poet.song.132000.json','["未說無功爵位叨，昔人所畏在功高。", "印如斗大寧常保，劍拄頤長祇自勞。", "酒社極知身可隱，獵場猶得氣差豪。", "世間見透渾無事，狐貉安能詫縕袍。"]'),
('a2aeef22-7b58-4732-b7f0-7911b3a912e5','村興','陸游','宋','宋诗','song-poetry','','[]','折花持博酒，種菜賣供家。',48,'全唐诗/poet.song.132000.json','["折花持博酒，種菜賣供家。", "請藥人何壅，爭棋客正譁。", "漁翁足踸踔，牧豎手丫叉。", "短景匆匆晚，橫林又宿鴉。"]'),
('0d966f2e-d754-4d50-a991-1111a5b3a390','賽神','陸游','宋','宋诗','song-poetry','','[]','歲熟鄉鄰樂，辰良祭賽多。',48,'全唐诗/poet.song.132000.json','["歲熟鄉鄰樂，辰良祭賽多。", "荒園拋鬼飯，高机置神鵝。", "人散叢祠寂，巫歸醉臉酡。", "饑鴉更堪笑，鳴噪下庭柯。"]'),
('1a46da74-cd52-4cab-8dbd-852aae95d557','小立','陸游','宋','宋诗','song-poetry','','[]','紅樹園廬晚，碧花籬落秋。',48,'全唐诗/poet.song.132000.json','["紅樹園廬晚，碧花籬落秋。", "荒陂船護鴨，斷岸笛呼牛。", "酒賤村村醉，山寒寺寺幽。", "聊須岸烏幘，小立埭西頭。"]'),
('e742b736-8d6c-48a2-8e0a-d014ef001c9d','窮老','陸游','宋','宋诗','song-poetry','','[]','窮老寧須嘆，吾生得已多。',48,'全唐诗/poet.song.132000.json','["窮老寧須嘆，吾生得已多。", "風埃棄朝幘，烟雨弄漁蓑。", "富屋烏爰止，閑門爵可羅。", "人生只此是，得酒且高歌。"]'),
('1fcc953e-fd81-4cd5-838f-b71ca5bf1e2d','晚步舍東','陸游','宋','宋诗','song-poetry','','[]','籬槿花開柿葉丹，土溝東去過牛欄。',32,'全唐诗/poet.song.132000.json','["籬槿花開柿葉丹，土溝東去過牛欄。", "草烟漠漠天將暮，布褐蕭蕭客正寒。"]'),
('57b0f01c-0b20-4e22-b742-f31e95721bc8','述野人語二首  其一','陸游','宋','宋诗','song-poetry','','[]','白米乾薪好井泉，甘餐美睡若登仙。',32,'全唐诗/poet.song.132000.json','["白米乾薪好井泉，甘餐美睡若登仙。", "從來不慣嘗鹽酪，席下何須有一錢。"]'),
('99ebcaa0-3626-45a3-94a0-b351cca4c1f2','述野人語二首  其二','陸游','宋','宋诗','song-poetry','','[]','重重大布敵風霜，籬外桑陰五月凉。',32,'全唐诗/poet.song.132000.json','["重重大布敵風霜，籬外桑陰五月凉。", "軟飯一盂千萬足，那知世有郭汾陽。"]'),
('73df38ce-00df-425e-844d-8a0b0ca12845','戲答野人二首  其一','陸游','宋','宋诗','song-poetry','','[]','日飲雲根一脈泉，知君骨相自應仙。',32,'全唐诗/poet.song.132000.json','["日飲雲根一脈泉，知君骨相自應仙。", "曲肱閑卧茅簷下，買斷南山不用錢。"]'),
('71c667d4-d441-4860-80fb-da1b7bf4513d','戲答野人二首  其二','陸游','宋','宋诗','song-poetry','','[]','木葉凋疏天欲霜，老懷多感易凄凉。',32,'全唐诗/poet.song.132000.json','["木葉凋疏天欲霜，老懷多感易凄凉。", "得君數語開人意，徑就湖橋醉夕陽。"]'),
('2c0c519c-028f-4656-90b4-f8a53dd883fd','建安陳希周官海南爲予致兩拄杖其一促節竹其一桄榔也','陸游','宋','宋诗','song-poetry','','[]','雨漬嵐侵蘚暈重，石砮楛矢正相同。',64,'全唐诗/poet.song.132000.json','["雨漬嵐侵蘚暈重，石砮楛矢正相同。", "取從萬里鯨波路，來伴三山鶴髮翁。", "雪上有時留醉草，花前隨處打殘紅。", "化龍徑去吾何憾，且與人間作歲豐。"]'),
('6daaed4a-4c32-4072-85f6-77ca11c5626e','排悶','陸游','宋','宋诗','song-poetry','','[]','棄官謂逍遥，勞苦殊未既。',96,'全唐诗/poet.song.132000.json','["棄官謂逍遥，勞苦殊未既。", "荒疇須墾闢，破屋欠塗塈。", "疾深藥難求，食盡穀暴貴。", "安能作經營，但覺睡有味。", "秋高霜露逼，更苦薪炭費。", "雖云未遽死，饑凍亦可畏。", "頗思從李廣，小獵聊吐氣。", "復恐灞亭歸，邂逅逢醉尉。"]'),
('19d57f8c-a3ce-4d58-a1bb-51ca8d09b224','九月十二日折菊','陸游','宋','宋诗','song-poetry','','[]','黄菊芬芳絕世奇，重陽錯把配萸枝。',32,'全唐诗/poet.song.132000.json','["黄菊芬芳絕世奇，重陽錯把配萸枝。", "開遲愈見凌霜操，堪笑兒童道過時。"]'),
('b0edd1cc-5d97-41c1-b654-bc87e1720f6a','表侄江坰種竹名筠坡來求詩','陸游','宋','宋诗','song-poetry','','[]','奉常遺緒冷如秋，閉戶知君頗好修。',64,'全唐诗/poet.song.132000.json','["奉常遺緒冷如秋，閉戶知君頗好修。", "千里可嗟妨晤語，兩書猶喜免沉浮。", "但令有竹能醫俗，何患無天可寄愁。", "一事却須常自勉，勿容凡子得同遊。"]'),
('8cfe682a-e9af-49d3-b9d0-4bab786593f6','微雨','陸游','宋','宋诗','song-poetry','','[]','晡後氣殊濁，黄昏月尚明。',48,'全唐诗/poet.song.132000.json','["晡後氣殊濁，黄昏月尚明。", "忽吹微雨過，便覺小寒生。", "樹杪雀初定，草根蟲已鳴。", "呼童取半臂，吾欲傍階行。"]'),
('d081c5c0-de96-4d51-8b19-d856fd89157a','秋晚寓嘆六首  其一','陸游','宋','宋诗','song-poetry','','[]','荷葉枯已盡，菊花殘更香。',48,'全唐诗/poet.song.132000.json','["荷葉枯已盡，菊花殘更香。", "带酲嘗野橘，和夢聽啼螿。", "鬢畔流年速，燈前舊話長。", "寒龜且未死，不必恨搘床。"]'),
('00da89e8-4544-4083-a1d8-ff07ac1a1ebd','秋晚寓嘆六首  其二','陸游','宋','宋诗','song-poetry','','[]','野處仍多病，經年無與遊。',48,'全唐诗/poet.song.132000.json','["野處仍多病，經年無與遊。", "僧庸幾市井，醫傲過公侯。", "不睡愁逢夜，無衣怯到秋。", "一端聊自慰，問事有長頭。"]'),
('90a50aec-2b79-44e0-ab7c-2f8501793763','秋晚寓嘆六首  其三','陸游','宋','宋诗','song-poetry','','[]','幽夢雞呼覺，孤愁雨滴成。',48,'全唐诗/poet.song.132000.json','["幽夢雞呼覺，孤愁雨滴成。", "天高那可問，年往若爲情。", "孱虜猶遺育，神州未削平。", "登高西北望，衰涕對誰傾。"]'),
('b80f224e-c097-462b-8ca5-0d296923eb1f','秋晚寓嘆六首  其四','陸游','宋','宋诗','song-poetry','','[]','老嘆交朋盡，閑知日月長。',48,'全唐诗/poet.song.132000.json','["老嘆交朋盡，閑知日月長。", "著書終覆瓿，得句漫投囊。", "霜樹昏鴉黑，風簾小蝶黄。", "村醪如水薄，也復答年光。"]'),
('d597d3f0-b659-4932-90f8-35b6dad2ab28','秋晚寓嘆六首  其五','陸游','宋','宋诗','song-poetry','','[]','十里丹楓岸，三家小麥村。',48,'全唐诗/poet.song.132000.json','["十里丹楓岸，三家小麥村。", "山多妨極目，秋晚易消魂。", "火舉船過埭，人行犬吠門。", "窮愁已如許，那更雨昏昏。"]'),
('d915ac62-147e-4415-82fb-fd18b3eeaec1','秋晚寓嘆六首  其六','陸游','宋','宋诗','song-poetry','','[]','行年垂大耋，久矣少朋儔。',48,'全唐诗/poet.song.132000.json','["行年垂大耋，久矣少朋儔。", "舊事同誰說，新詩或自酬。", "廢書眠過日，泥酒醉經秋。", "遲速皆當死，時來莫預愁。"]'),
('0a40bb87-067f-419e-8cc2-89b898bb70bc','秋晚湖上','陸游','宋','宋诗','song-poetry','','[]','已過西成賽廟期，家家下麥不容遲。',64,'全唐诗/poet.song.132000.json','["已過西成賽廟期，家家下麥不容遲。", "夕陽遍野人歸後，秋水生灘鷺集時。", "靈藥不治懷抱惡，好詩空益鬢毛衰。", "從來未識蘇司業，愁絕西風滿酒旗。"]'),
('7f097a74-6004-4393-8696-fecb6bfbdd26','縱遊歸泊湖橋有作','陸游','宋','宋诗','song-poetry','','[]','西蜀東吳到處遊，千巖萬壑獨吾州。',64,'全唐诗/poet.song.132000.json','["西蜀東吳到處遊，千巖萬壑獨吾州。", "短篷載月娥江夜，小蹇尋詩禹寺秋。", "村酒可賒常痛飲，野人有興即相求。", "何由喚得王摩詰，爲畫湖橋一片愁。"]'),
('343fd0fe-54ef-4d47-8098-2f5f60d455cb','九月十八日至山園是日頗有春意','陸游','宋','宋诗','song-poetry','','[]','烏藤真好友，伴我出荆扉。',48,'全唐诗/poet.song.132000.json','["烏藤真好友，伴我出荆扉。", "落葉紛如積，鳴禽暖不歸。", "露濃松鬣長，土潤朮苗肥。", "未盡幽尋興，還家趁夕暉。"]'),
('4c7806db-aafd-425d-9733-cb1fb6be0c2d','明日又來天微陰再賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','烏臼赤于楓，園林九月中。',48,'全唐诗/poet.song.132000.json','["烏臼赤于楓，園林九月中。", "天寒山慘淡，雲薄日曈曨。", "旋摘分猿果，寬編養鶴籠。", "身閑足幽事，歸卧莫匆匆。"]'),
('9a419abb-2953-457d-b049-7621ab241a3d','明日又來天微陰再賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','河岸風檣遠，村陂牧笛長。',48,'全唐诗/poet.song.132000.json','["河岸風檣遠，村陂牧笛長。", "短籬圍麂眼，幽徑繚羊腸。", "照水鬚眉見，搓橙指爪香。", "衣裘又關念，碪杵滿斜陽。"]'),
('c2397014-e08e-4b5a-9b6d-189d1177d538','雨後至近村二首  其一','陸游','宋','宋诗','song-poetry','','[]','夜雨曉方止，朝雲猶作陰。',48,'全唐诗/poet.song.132000.json','["夜雨曉方止，朝雲猶作陰。", "山餘一寸碧，溪長半篙深。", "卧泛白鷗渚，行穿黄葉林。", "老農能共語，真率會人心。"]'),
('6b89990f-ca7c-4652-9f05-fdd9dc6a829b','雨後至近村二首  其二','陸游','宋','宋诗','song-poetry','','[]','年耄身猶健，秋高疾已平。',48,'全唐诗/poet.song.132000.json','["年耄身猶健，秋高疾已平。", "鄰翁思問訊，蔬圃要巡行。", "竹杖輕無迹，芒鞋捷有聲。", "相逢無別語，努力事冬耕。"]'),
('92583911-18a4-4609-9f4d-bd64bc6a50d0','雨復作自近村歸','陸游','宋','宋诗','song-poetry','','[]','夜聽蕭蕭未漲溪，朝行㶁㶁已成泥。',64,'全唐诗/poet.song.132000.json','["夜聽蕭蕭未漲溪，朝行㶁㶁已成泥。", "可憐鳩取招麾速，誰似雲知出處齊。", "野菊枝長半狼藉，江楓葉落正凄迷。", "行人也識龜堂老，小榼村醪手自携。"]'),
('59401f15-5437-4957-bf2c-e6673174b358','雨寒戲作','陸游','宋','宋诗','song-poetry','','[]','掃園收槲葉，掊地甃磚爐。',24,'全唐诗/poet.song.132000.json','["掃園收槲葉，掊地甃磚爐。", "幸有藜烹粥，何慚紙作襦。"]'),
('6603b831-8837-462b-b38d-8ea88557121e','衡門晚眺','陸游','宋','宋诗','song-poetry','','[]','幽居端似玉川生，茅屋支撐不更營。',64,'全唐诗/poet.song.132000.json','["幽居端似玉川生，茅屋支撐不更營。", "青旆荒寒增酒興，錦囊零落負詩情。", "殘蕪色襯斜陽遠，落葉飛如野鳥輕。", "徂歲崢嶸忽如許，雁來又過會稽城。"]'),
('d88d3064-7aa2-4695-8a55-f16629300785','不寐','陸游','宋','宋诗','song-poetry','','[]','麗譙聽盡短長更，幽夢無端故不成。',64,'全唐诗/poet.song.132000.json','["麗譙聽盡短長更，幽夢無端故不成。", "寒雨似從心上滴，孤燈偏向枕邊明。", "讀書有味身忘老，報國無期涕每傾。", "敢爲衰殘便虛死，誓先鄰曲事春耕。"]'),
('34c83b98-344e-4af5-9ca7-10f13a250ae6','示子虡','陸游','宋','宋诗','song-poetry','','[]','好學承家夙所奇，蠹編殘簡共娛嬉。',64,'全唐诗/poet.song.132000.json','["好學承家夙所奇，蠹編殘簡共娛嬉。", "一婚倘畢吾無累，三釜雖微汝有期。", "聿弟元知是難弟，德兒稍長豈常兒。", "要令舟過三山者，弦誦常聞夜艾時。"]'),
('24e59a29-9886-49e7-831c-8125b4b36112','弊廬','陸游','宋','宋诗','song-poetry','','[]','弊廬雖陋甚，鄙性頗所宜。',144,'全唐诗/poet.song.132000.json','["弊廬雖陋甚，鄙性頗所宜。", "欹傾十許間，草覆實半之。", "碓聲隔柴門，績火出枳籬。", "縛木爲彘牢，附垣作雞塒。", "黄犢放林莽，蒼鵝戲陂池。", "傭耕食于我，客主同爨炊。", "瓦盎設大杓，葅莧羹園葵。", "一飽荷鋤出，作勞非所辭。", "上以奉租賦，下以及我私。", "有錢即沽酒，阡陌恣遊嬉。", "亦有扶持者，婢跣奴髻椎。", "欲畫恨無人，後世考此詩。"]'),
('0ce0e160-b6e8-4cc7-9ff3-24103384e57d','予未冠即交諸名勝今無復在者感嘆有作','陸游','宋','宋诗','song-poetry','','[]','早歲鄉閭接勝流，老來零落嘆山丘。',64,'全唐诗/poet.song.132000.json','["早歲鄉閭接勝流，老來零落嘆山丘。", "欲尋共語人難得，却是封侯印易求。", "數酌不能成兀兀，一枰且復寄悠悠。", "世間只有身差重，惆悵今年白盡頭。"]'),
('96309913-0d70-4321-b30c-b324dd960722','夜雨','陸游','宋','宋诗','song-poetry','','[]','吾詩滿篋笥，最多夜雨篇。',120,'全唐诗/poet.song.132000.json','["吾詩滿篋笥，最多夜雨篇。", "四時雨皆佳，莫若初寒天。", "紙帳白于氈，紙被軟于綿。", "枕傍小銅匜，海沉起微烟。", "是時聞夜雨，如絲竹管弦。", "恨我未免俗，吟諷勤雕鎸。", "南朝空階語，妙出建安前。", "意謂奪造化，百世莫比肩。", "安知梧桐句，乃復與並傳。", "夜雨何時無，奇語付後賢。"]'),
('609db76f-54a2-4e81-8475-5908b43c294c','題嚴州王秀才山水枕屏','陸游','宋','宋诗','song-poetry','','[]','我行天下路幾何，三巴小益山最多。',160,'全唐诗/poet.song.132000.json','["我行天下路幾何，三巴小益山最多。", "翠崖青嶂高嵯峨，紅棧如带縈巖阿。", "下有駭浪千盤渦，一跌性命委蛟鼉。", "日馳三百一烏騾，雪壓披氈泥滿靴。", "驛亭沃酒醉臉酡，長笛腰鼓雜巴歌。", "大散關上方橫戈，豈料世變如翻波。", "東歸輕舟下江沱，回首歲月悲蹉跎。", "壯君落筆寫岷嶓，意匠自到非身過。", "偉哉千仞天相摩，谷裏人家藏綠蘿。", "使我恍然越關河，熟視粉墨頻摩挲。"]'),
('71b4b258-3c53-4069-8039-c9a74e46babc','小飲示座中','陸游','宋','宋诗','song-poetry','','[]','鏡裏蕭蕭兩鬢衰，閑人正與老相宜。',64,'全唐诗/poet.song.133000.json','["鏡裏蕭蕭兩鬢衰，閑人正與老相宜。", "誰知翦燭焚香夜，恰是搓橙破橘時。", "莫道閉門無逸氣，尚能爲客誦新詩。", "君看江海寬多少，是處皆堪理釣絲。"]'),
('d4e41048-58a1-4055-afa4-945d223720a1','摇落吟','陸游','宋','宋诗','song-poetry','','[]','素秋欲盡風雨惡，千林如掃俱摇落。',96,'全唐诗/poet.song.133000.json','["素秋欲盡風雨惡，千林如掃俱摇落。", "年運而往秋復冬，念念元知已非昨。", "癡人顧欲吝此生，放翁憫汝笑絕纓。", "髮毛爪齒俱外物，天地大化終無情。", "我貧無以遺兒子，惟有一言持付爾。", "仕宦要能當百挫，爲農饑死無游惰。"]'),
('8ce24ebc-cbbd-44e3-997f-e1cee778b03e','插花','陸游','宋','宋诗','song-poetry','','[]','有花君不插，有酒君不持。',72,'全唐诗/poet.song.133000.json','["有花君不插，有酒君不持。", "時過花枝空，人老酒戶衰。", "今年病止酒，虛負菊花時。", "早梅行可探，家醞綠滿卮。", "君不强一醉，歲月復推移。", "新詩亦當賦，勿計字傾欹。"]'),
('561d1413-f575-45d7-8a20-ece0e55a547b','雨過行視舍北菜圃因望北村久之二首  其一','陸游','宋','宋诗','song-poetry','','[]','蔬畦躡屐愜幽情，檢校園丁日有程。',32,'全唐诗/poet.song.133000.json','["蔬畦躡屐愜幽情，檢校園丁日有程。", "得雨尚慳須灌溉，我來時聽桔槔聲。"]'),
('3fe9b9fc-d5b6-4910-bf88-ce143e9137a0','雨過行視舍北菜圃因望北村久之二首  其二','陸游','宋','宋诗','song-poetry','','[]','吳牛嚙草卧斜陽，烏臼青紅未飽霜。',32,'全唐诗/poet.song.133000.json','["吳牛嚙草卧斜陽，烏臼青紅未飽霜。", "急趁路乾來寓目，十分閑事却成忙。"]'),
('2b827ccd-3ae0-4660-84d7-6618c2b86411','居三山時方四十餘今三十六年久已謝事而連歲小稔喜甚有作','陸游','宋','宋诗','song-poetry','','[]','自問湖邊舍，衰殘俯仰中。',96,'全唐诗/poet.song.133000.json','["自問湖邊舍，衰殘俯仰中。", "謀身悲日拙，造物假年豐。", "稅足催科靜，禾登債負空。", "社醅邀里巷，膰肉飫兒童。", "衣及霜晨贖，爐先雪夜紅。", "陂塘趨版筑，垣屋訖宮功。", "盜息時雍象，人淳太古風。", "退夫無一事，鼓缶伴鄰翁。"]'),
('90c66b38-50a6-42ed-b08e-f379df54bb42','幽居','陸游','宋','宋诗','song-poetry','','[]','百事徒勞無一成，幽居偶得稱幽情。',64,'全唐诗/poet.song.133000.json','["百事徒勞無一成，幽居偶得稱幽情。", "傍籬叢枳寒猶綠，繞舍流泉夜有聲。", "饑坐炮燔多巨栗，醉歸懷袖有新橙。", "愛閑自是從來癖，敢竊區區納祿名。"]'),
('8d88bf1b-4bf1-4c57-b06f-8f8caa48b345','曉晴肩輿至湖上','陸游','宋','宋诗','song-poetry','','[]','多稼如雲穫併空，牛闌樵擔畫圖中。',64,'全唐诗/poet.song.133000.json','["多稼如雲穫併空，牛闌樵擔畫圖中。", "梧桐已逐晨霜盡，烏臼猶爭夕照紅。", "脫網噞喁奔遠浦，避鷹撲握保深叢。", "旗亭人語燈初上，一醉何妨野老同。"]'),
('6f41a25a-1b3f-4250-9977-4f43577ca555','戲作野興六首  其一','陸游','宋','宋诗','song-poetry','','[]','省事貧猶富，寬懷客勝家。',48,'全唐诗/poet.song.133000.json','["省事貧猶富，寬懷客勝家。", "充虛一簞飯，遣睡半甌茶。", "有興閑垂釣，逢歡醉插花。", "皋橋亦可死，處處是生涯。"]'),
('9c6772ec-d522-4337-bff5-5ef1fc08ddae','戲作野興六首  其二','陸游','宋','宋诗','song-poetry','','[]','擾擾亭中客，悠悠局上棋。',48,'全唐诗/poet.song.133000.json','["擾擾亭中客，悠悠局上棋。", "所遭元有命，自苦竟何爲。", "馮衍深尤婦，陶潜過責兒。", "奇文雖可貴，寱語豈非癡。"]'),
('7755c6c2-b535-4dc4-a7a4-9b48ba9c44b8','戲作野興六首  其三','陸游','宋','宋诗','song-poetry','','[]','久已挂吾冠，江邊歲又殘。',48,'全唐诗/poet.song.133000.json','["久已挂吾冠，江邊歲又殘。", "心惟無愧怍，身取不饑寒。", "小酌三杯足，安居一席寬。", "東岡有泉脈，携杖試尋看。"]'),
('3b9dcaf3-6bb5-4d07-b2b3-8fe776ace181','戲作野興六首  其四','陸游','宋','宋诗','song-poetry','','[]','今年病微減，耕稼樂江村。',48,'全唐诗/poet.song.133000.json','["今年病微減，耕稼樂江村。", "燈火耿破屋，歌呼圍老盆。", "常時但葵莧，盛饌有雞豚。", "客散茅簷寂，蹣跚自閉門。"]'),
('7bdcfff2-df3a-4c30-8d23-6dee2e7adc2a','戲作野興六首  其五','陸游','宋','宋诗','song-poetry','','[]','出戶語鄰叟，與卿同一愚。',48,'全唐诗/poet.song.133000.json','["出戶語鄰叟，與卿同一愚。", "逢人即如舊，臨事不勝迂。", "髮白花猶插，囊空酒亦沽。", "回思五十載，何處有榮枯。"]'),
('4a8d4a7b-577b-4ce8-b978-5288ba0a08dc','戲作野興六首  其六','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','有酒皆堪醉，無山不可廬。',48,'全唐诗/poet.song.133000.json','["有酒皆堪醉，無山不可廬。", "遂初成近賦，孤憤悔前書。", "湘寺分經帙，廬山寄藥鉏。", "江頭霜葉滿，詩興屬騎驢。"]'),
('dce14be0-905d-4c4a-9494-2fdf31c210b6','道室書事','陸游','宋','宋诗','song-poetry','','[]','榻上一琴橫，中函太古聲。',48,'全唐诗/poet.song.133000.json','["榻上一琴橫，中函太古聲。", "丹砂燒已死，芝草種初生。", "道勝魔軍破，方靈疾豎平。", "明朝有蜀使，細字報青城。"]'),
('0f0850ad-cd7b-4fb6-aed0-4b45f4ce2ccc','行飯至湖桑堰東小市','陸游','宋','宋诗','song-poetry','','[]','飽食無營是處遊，偶然來到埭東頭。',64,'全唐诗/poet.song.133000.json','["飽食無營是處遊，偶然來到埭東頭。", "芒鞋也似雙鳧快，漁艇真如一葉浮。", "樵擔行歌衝暝色，酒旗遮路賣新篘。", "任朱二老今安在，嘆息黄茅擁故丘。"]'),
('a1cc9801-bb60-4fa6-b9fd-077b95f07d3d','負日戲作','陸游','宋','宋诗','song-poetry','','[]','困來兩眥似膠黏，底怪吳人號黑甜。',32,'全唐诗/poet.song.133000.json','["困來兩眥似膠黏，底怪吳人號黑甜。", "安得他生不識字，朝朝就日卧茅簷。"]'),
('b48fcef9-e379-4306-9bb2-5845d8efe32d','遊西村','陸游','宋','宋诗','song-poetry','','[]','昨夜雨多溪水渾，不妨喚渡到西村。',64,'全唐诗/poet.song.133000.json','["昨夜雨多溪水渾，不妨喚渡到西村。", "出遊始覺此身健，無食更知吾道尊。", "藥笈可賒山店酒，筇枝時打野僧門。", "歸來燈火茅簷夜，且復狂歌鼓盎盆。"]'),
('ddc92eb1-8f39-4f2b-a2e6-06ba0df30c42','初冬','陸游','宋','宋诗','song-poetry','','[]','平生詩句領流光，絕愛初冬萬瓦霜。',64,'全唐诗/poet.song.133000.json','["平生詩句領流光，絕愛初冬萬瓦霜。", "楓葉欲殘看愈好，梅花未動意先香。", "暮年自適何妨退，短景無營亦自長。", "况有小兒同此趣，一窗相對弄朱黄。"]'),
('ea9424e4-76af-4ac2-8cc0-5d3c7df28625','遣懷','陸游','宋','宋诗','song-poetry','','[]','寬袂新裁大布裘，低篷初買小漁舟。',64,'全唐诗/poet.song.133000.json','["寬袂新裁大布裘，低篷初買小漁舟。", "舊交只有青山在，壯志皆因白髮休。", "漫道卧羆吞貉子，安能淅米向矛頭。", "山園芋栗秋方熟，一飽今知本易謀。"]'),
('59eeffe2-eace-4b03-9304-d5ba268b24b6','策杖','陸游','宋','宋诗','song-poetry','','[]','山翁老病入腰膂，坐覺諸兒行步奔。',32,'全唐诗/poet.song.133000.json','["山翁老病入腰膂，坐覺諸兒行步奔。", "暫出衡門須策杖，千回上樹更堪論。"]'),
('042ce082-46f8-46f8-a1ef-955ea61af2a2','汲東山下井','陸游','宋','宋诗','song-poetry','','[]','從來耽酒須微祿，絕祿三年酒盞疏。',32,'全唐诗/poet.song.133000.json','["從來耽酒須微祿，絕祿三年酒盞疏。", "百尺轆轤新浚井，一杯聊慰渴相如。"]'),
('0c34564b-33c0-4438-8f55-d564ec1f379d','園中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','誰采桄榔寄一枝，北來萬里爲扶衰。',64,'全唐诗/poet.song.133000.json','["誰采桄榔寄一枝，北來萬里爲扶衰。", "風光最愛初寒候，懷抱殊勝未老時。", "閑引微泉成曲澗，盡除枯蔓補疏籬。", "花前自笑童心在，更伴群兒竹馬嬉。"]'),
('e548ca0e-f96c-4e01-8c53-e4189abfcf54','園中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','病侵衰境頻須藥，日漏寒雲旋作晴。',64,'全唐诗/poet.song.133000.json','["病侵衰境頻須藥，日漏寒雲旋作晴。", "幽鳥喚回殘枕夢，蠻童扶下野堂行。", "書生本自安窮處，豐歲何妨樂太平。", "新買西村兩黄犢，閑招鄰曲議春耕。"]'),
('71212c22-69b3-4226-be1a-e39c6fc324bb','園中','陸游','宋','宋诗','song-poetry','','[]','霜凋櫸柳枝無葉，風拆安榴子滿房。',32,'全唐诗/poet.song.133000.json','["霜凋櫸柳枝無葉，風拆安榴子滿房。", "冬日園林元自好，老人懷抱自多傷。"]'),
('047d063e-4a54-4082-8f06-d9c4b8ab7a31','短篷','陸游','宋','宋诗','song-poetry','','[]','射的山前繫短篷，快如魚鳥出池籠。',64,'全唐诗/poet.song.133000.json','["射的山前繫短篷，快如魚鳥出池籠。", "試臨清鏡枯顱茁，不待丹砂兩頰紅。", "逐妄百年真自苦，造微一日有餘功。", "不須更說岷峨約，已覺蓬壺在眼中。"]'),
('0da7daef-ec65-4c82-9630-a76d3c0e97f2','自適','陸游','宋','宋诗','song-poetry','','[]','遠遊思里巷，久困念耕桑。',48,'全唐诗/poet.song.133000.json','["遠遊思里巷，久困念耕桑。", "家釀傾醇碧，園蔬摘矮黄。", "利名因醉遠，日月爲閑長。", "今歲雖中熟，吾徒亦小康。"]'),
('a5fe772d-7c61-4541-a1b5-0179333b3edc','堂東小室深丈袤半之戲作','陸游','宋','宋诗','song-poetry','','[]','小室舍東偏，滿窗朝日妍。',48,'全唐诗/poet.song.133000.json','["小室舍東偏，滿窗朝日妍。", "研池生細浪，香岫起微烟。", "欲極圖書樂，少須冰雪天。", "猶勝禪榻上，僅僅占三椽。"]'),
('eaa9d14a-702a-4a6f-bbdb-f0dfb65728eb','獨處二首  其一','陸游','宋','宋诗','song-poetry','','[]','蓬門終日閉，寂寂少人聲。',48,'全唐诗/poet.song.133000.json','["蓬門終日閉，寂寂少人聲。", "納祿知身貴，傳家覺責輕。", "朝餐烹芋糝，夜坐爇松明。", "剗却彈棋局，此心如砥平。"]'),
('3c8d4ff2-b669-4359-81b3-06ad8566f581','獨處二首  其二','陸游','宋','宋诗','song-poetry','','[]','白氎敷床穩，烏藤倚壁斜。',48,'全唐诗/poet.song.133000.json','["白氎敷床穩，烏藤倚壁斜。", "灰深惟畫字，燈暗不成花。", "似客猶居里，如僧未出家。", "孤村夜無月，何事有啼鴉。"]'),
('c546271c-8d42-48b3-a2f4-f68b9473436f','探梅至東村','陸游','宋','宋诗','song-poetry','','[]','乞得殘骸已累年，柴車破弊不堪懸。',64,'全唐诗/poet.song.133000.json','["乞得殘骸已累年，柴車破弊不堪懸。", "閑愁正要供詩思，小疾何妨省酒錢。", "忍事漸多心混混，貯書雖少腹便便。", "今朝偶有尋梅興，春色爭來拄杖前。"]'),
('36a5ccf6-c01a-419a-a7b5-31c3f4fc7057','讀史','陸游','宋','宋诗','song-poetry','','[]','青燈耿耿夜沉沉，掩卷凄然感獨深。',64,'全唐诗/poet.song.133000.json','["青燈耿耿夜沉沉，掩卷凄然感獨深。", "恤緯不遑嫠婦嘆，美芹欲獻野人心。", "孤忠要有天知我，萬事當思後視今。", "君看宣王何似主，一篇庭燎未忘箴。"]'),
('bb3aded5-7002-4fc3-80cc-62d50d238596','漁翁二首  其一','陸游','宋','宋诗','song-poetry','','[]','船入蘆花日暮時，雙瞳炯炯鬢如絲。',32,'全唐诗/poet.song.133000.json','["船入蘆花日暮時，雙瞳炯炯鬢如絲。", "世間豈少磻溪叟，老向烟波人不知。"]'),
('a6d34ebf-db16-4355-ba94-2cf5e4bb4132','漁翁二首  其二','陸游','宋','宋诗','song-poetry','','[]','文叔君房兩故人，可憐俱作白頭新。',32,'全唐诗/poet.song.133000.json','["文叔君房兩故人，可憐俱作白頭新。", "桐江歸伴鄰翁醉，一笑相看意却真。"]'),
('82d97b61-0ffc-40a5-b1f7-5b36e67cffa4','寓言三首  其一','陸游','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','濟劇人才易，扶顛力量難。',48,'全唐诗/poet.song.133000.json','["濟劇人才易，扶顛力量難。", "爲謀須遠大，守節要堅完。", "氣與秋天杳，胸吞夢澤寬。", "方知至危地，自有泰山安。"]'),
('5cce1bc1-a428-41c4-8721-f4f7a815509d','寓言三首  其二','陸游','宋','宋诗','song-poetry','','[]','出仕謝招麾，還家美蕨薇。',48,'全唐诗/poet.song.133000.json','["出仕謝招麾，還家美蕨薇。", "深居全素志，大路息危機。", "世變生呼吸，人情忽細微。", "床頭周易在，捨此欲安歸。"]'),
('9e643ef1-f644-4526-9f4a-4189059c3cfe','寓言三首  其三','陸游','宋','宋诗','song-poetry','','[]','山海三家市，風烟五畝園。',48,'全唐诗/poet.song.133000.json','["山海三家市，風烟五畝園。", "藜羹均玉食，茅屋陋朱門。", "耕釣此身老，乾坤吾道尊。", "故交淪落盡，至理與誰論。"]'),
('fe179a47-bcd5-4d8b-bd22-7ee86f71616e','夜四鼓睡覺起行簷間觀新作南籬','陸游','宋','宋诗','song-poetry','','[]','星斗闌干天宇清，起披短褐繞廊行。',64,'全唐诗/poet.song.133000.json','["星斗闌干天宇清，起披短褐繞廊行。", "葉聲颯颯飛霜重，籬影疏疏落月明。", "沙冷斷鴻投別浦，風高殘漏下孤城。", "衰遲自笑情猶在，一首新詩取次成。"]'),
('c22fbb31-c765-4e48-88fc-1445cfe2a522','客去追記坐間所言','陸游','宋','宋诗','song-poetry','','[]','征西幕罷幾經春，嘆息兒音尚带秦。',64,'全唐诗/poet.song.133000.json','["征西幕罷幾經春，嘆息兒音尚带秦。", "每爲後生談舊事，始知老子是陳人。", "建隆乾德開王業，溫洛榮河厭虜塵。", "倘得此生重少壯，臨危敢愛不貲身。"]'),
('16bcee3f-b32c-41e9-a995-56323c21d943','疇昔','陸游','宋','宋诗','song-poetry','','[]','行路悲疇昔，驅車每戴星。',48,'全唐诗/poet.song.133000.json','["行路悲疇昔，驅車每戴星。", "數殘雙隻堠，歷盡短長亭。", "飛蓋交迎餞，聽歌半醉醒。", "至今湖海夜，猶夢隴山青。"]'),
('c0eedf10-bbbd-4813-bd99-9ba014155439','飲牛歌','陸游','宋','宋诗','song-poetry','','[]','門外一溪清見底，老翁牽牛飲溪水。',96,'全唐诗/poet.song.133000.json','["門外一溪清見底，老翁牽牛飲溪水。", "溪清喜不污牛腹，豈畏踐霜寒墮趾。", "舍東土瘦多瓦礫，父子勤勞藝黍稷。", "勿言牛老行苦遲，我今八十耕猶力。", "牛能生犢我有孫，世世相從老故園。", "人生得飽萬事足，捨牛相齊何足言。"]'),
('d678d6d5-dda7-49de-8681-af3c1597555f','牧羊歌','陸游','宋','宋诗','song-poetry','','[]','牧羊忌太早，太早羊輒傷。',56,'全唐诗/poet.song.133000.json','["牧羊忌太早，太早羊輒傷。", "一羊病尚可，舉群無全羊。", "日高露晞原草綠，羊散如雲滿川谷。", "小童但搢竹一枝，豈必習詩知考牧。"]'),
('fcc8145d-cd37-4ece-b478-95a9f37f8e4f','生日子聿作五字詩十首爲壽追懷先親泫然有作','陸游','宋','宋诗','song-poetry','','[]','我生尚及宣和末，頒曆頻驚歲月移。',64,'全唐诗/poet.song.133000.json','["我生尚及宣和末，頒曆頻驚歲月移。", "負米養親無復日，蓼莪廢講豈勝悲。", "渡江百口今誰在，抱恨終身祇自知。", "文字虛名何足道，樽前愧汝十章詩。"]'),
('555118e3-06f3-4e27-8403-9601dc791830','園中書觸目','陸游','宋','宋诗','song-poetry','','[]','氣候今年晚，濃霜始此回。',48,'全唐诗/poet.song.133000.json','["氣候今年晚，濃霜始此回。", "殘梧未全槁，晚菊有初開。", "烏桕先楓赤，寒鴉後雁來。", "西窗夕陽暖，摘橘薦新醅。"]'),
('4fc9f49b-71e6-4937-9d45-635441be21d5','養生','陸游','宋','宋诗','song-poetry','','[]','武丁命傅說，治國如和羹。',48,'全唐诗/poet.song.133000.json','["武丁命傅說，治國如和羹。", "天亦命放翁，用此以養生。", "抑過補不足，輔相其適平。", "千歲汝自有，不必師廣成。"]'),
('1493c180-dd32-4d9a-9436-838b231c678d','齋中雜興二首  其一','陸游','宋','宋诗','song-poetry','','[]','八十頹齡安所歸，蕭然終日掩柴扉。',64,'全唐诗/poet.song.133000.json','["八十頹齡安所歸，蕭然終日掩柴扉。", "清心始信幽棲樂，窮理方知俗學非。", "山果滿筐猿食足，石泉通筧藥苗肥。", "衰翁莫道渾無事，掃葉歸來又落暉。"]'),
('861c9b4c-3119-4366-a22d-6a118ebef0fe','齋中雜興二首  其二','陸游','宋','宋诗','song-poetry','','[]','倒掩衡門手自關，老身著在亂書間。',64,'全唐诗/poet.song.133000.json','["倒掩衡門手自關，老身著在亂書間。", "有詩尚作清宵祟，無事能妨白日閑。", "薄暮上樓聊試步，經旬止酒自酡顔。", "兒曹莫笑衰翁懶，擬遍淮南大小山。"]'),
('8b200b43-b9c9-467b-98a5-b2eed5222734','江上','陸游','宋','宋诗','song-poetry','','[]','禹會橋頭江渺然，隔江村店起孤烟。',64,'全唐诗/poet.song.133000.json','["禹會橋頭江渺然，隔江村店起孤烟。", "冷雲垂野雪方作，斷雁叫群人未眠。", "萬里漂流歸故國，一生蹭蹬付蒼天。", "暮年尚欲師周孔，未遽長齋繡佛前。"]'),
('91fe8644-77b6-4020-91f2-f53a339aa443','追憶征西幕中舊事四首  其一','陸游','宋','宋诗','song-poetry','','[]','大散關頭北望秦，自期談笑掃胡塵。',32,'全唐诗/poet.song.133000.json','["大散關頭北望秦，自期談笑掃胡塵。", "收身死向農桑社，何止明明兩世人。"]'),
('09fcd25b-9c53-47bd-b5be-ec2c3680dea1','追憶征西幕中舊事四首  其二','陸游','宋','宋诗','song-poetry','','[]','小獵南山雪未消，繡旗斜卷玉驄驕。',32,'全唐诗/poet.song.133000.json','["小獵南山雪未消，繡旗斜卷玉驄驕。", "不如意事常千萬，空想先鋒宿渭橋。"]'),
('0c6c2ba0-b252-4daa-bb8e-06575d3d4d7e','追憶征西幕中舊事四首  其三','陸游','宋','宋诗','song-poetry','','[]','憶昨王師戍隴回，遺民日夜望行臺。',32,'全唐诗/poet.song.133000.json','["憶昨王師戍隴回，遺民日夜望行臺。", "不論夾道壺漿滿，洛筍河魴次第來。"]'),
('c8a012ff-ec7e-4a02-9bf9-ee3e3557dce0','追憶征西幕中舊事四首  其四','陸游','宋','宋诗','song-poetry','','[]','關輔遺民意可傷，蠟封三寸絹書黄。',32,'全唐诗/poet.song.133000.json','["關輔遺民意可傷，蠟封三寸絹書黄。", "亦知虜法如秦酷，列聖恩深不忍忘。"]'),
('56a48fd3-e1ba-4e68-990b-8eacbdf0107c','冬夜','陸游','宋','宋诗','song-poetry','','[]','颼颼黄葉欲辭枝，况著霜風抵死吹。',64,'全唐诗/poet.song.133000.json','["颼颼黄葉欲辭枝，况著霜風抵死吹。", "投老難逢身健日，讀書偏愛夜長時。", "孤村月白聞衣杵，破竈烟青煮芋糜。", "不是用心希陋巷，爲儒自合耐寒饑。"]'),
('8cf0ca97-261e-4162-9d75-474ca5e9597a','冬日','陸游','宋','宋诗','song-poetry','','[]','室中恰受一蒲團，也抵三千世界寬。',64,'全唐诗/poet.song.133000.json','["室中恰受一蒲團，也抵三千世界寬。", "上策莫如扃戶坐，苦閑猶復取書看。", "蔬青飯軟枝梧老，窗白爐新準備寒。", "堪笑此翁幽獨慣，却嫌兒女話團欒。"]'),
('8286305c-86a6-4a23-8957-b66cb6d62533','冬朝','陸游','宋','宋诗','song-poetry','','[]','風入園林徹夜鳴，曉看黄葉與階平。',64,'全唐诗/poet.song.133000.json','["風入園林徹夜鳴，曉看黄葉與階平。", "篝爐火著衣初暖，爨釜薪乾粥已成。", "潔己工夫先盥頮，正心事業始冠纓。", "聖賢雖遠詩書在，殊勝鄰翁擊磬聲。"]'),
('b59aaed4-0486-4ed2-9dfd-a95ef89538a8','冬暮','陸游','宋','宋诗','song-poetry','','[]','曉角昏鐘爲底忙，豈容老子更禁當。',64,'全唐诗/poet.song.133000.json','["曉角昏鐘爲底忙，豈容老子更禁當。", "乘除富貴惟身健，補貼光陰有夜長。", "臨水小軒初見月，滿庭殘葉不禁霜。", "巴江尺素合時到，剩著新詩寄斷腸。"]'),
('8173dbf2-d5fd-45ca-a0b1-1e7da9a71de4','風月','陸游','宋','宋诗','song-poetry','','[]','鏡中日日鬢毛衰，八十還思七十時。',32,'全唐诗/poet.song.133000.json','["鏡中日日鬢毛衰，八十還思七十時。", "風月不知人意緒，酒醒夢斷又催詩。"]'),
('b2df9658-1606-4818-88c7-806d2fd0bdff','落葉','陸游','宋','宋诗','song-poetry','','[]','萬瓦清霜伴月明，卧聽殘漏若爲情。',32,'全唐诗/poet.song.133000.json','["萬瓦清霜伴月明，卧聽殘漏若爲情。", "無端木葉蕭蕭下，更與愁人作雨聲。"]'),
('92839479-7696-4468-8a57-745893feec15','邠風','陸游','宋','宋诗','song-poetry','','[]','少學詩三百，邠風最力行。',48,'全唐诗/poet.song.133000.json','["少學詩三百，邠風最力行。", "春前耕犢健，節近祭豬鳴。", "簷日桑榆暖，園蔬風露清。", "金丹不須問，持此畢吾生。"]'),
('2ff2e91f-dd0b-41ce-b4c7-2dfda3a965bc','擁爐不出輒終日自嘲','陸游','宋','宋诗','song-poetry','','[]','柴門木落葉成堆，十日元無一再開。',64,'全唐诗/poet.song.133000.json','["柴門木落葉成堆，十日元無一再開。", "書坐藏多爲飽祟，詩緣吟苦作窮媒。", "兒言山圃當收栗，僧約溪橋共探梅。", "堪笑此翁推不動，地爐無火畫寒灰。"]'),
('67829078-2c19-423d-8248-6e1b50056393','嘲梅未開','陸游','宋','宋诗','song-poetry','','[]','梅蕊如紅稻，中藏無盡香。',24,'全唐诗/poet.song.133000.json','["梅蕊如紅稻，中藏無盡香。", "何時來鼻境，更待幾番霜。"]'),
('61758874-8c04-4306-b511-486b597cde90','自嘲','陸游','宋','宋诗','song-poetry','','[]','僻學論交少，貧居卜地偏。',48,'全唐诗/poet.song.133000.json','["僻學論交少，貧居卜地偏。", "不逢方謝事，垂老旋希僊。", "兀兀醒如醉，昏昏晝亦眠。", "却慚農與圃，一飽餞餘年。"]'),
('56c034cf-a1d6-47fc-a2da-cb5a7f553aa9','解嘲','陸游','宋','宋诗','song-poetry','','[]','一壑棲遲久，多生習氣消。',48,'全唐诗/poet.song.133000.json','["一壑棲遲久，多生習氣消。", "行藏無愧怍，夢覺兩逍遥。", "倩鶴傳山信，疏泉洗藥苗。", "晚來幽興極，乘月過溪橋。"]'),
('8fc85019-9b8d-4fa8-82da-1329daed4a6d','野興','陸游','宋','宋诗','song-poetry','','[]','晨炊畬粟薦園蔬，默計生涯已有餘。',64,'全唐诗/poet.song.133000.json','["晨炊畬粟薦園蔬，默計生涯已有餘。", "舉世方誇稽古力，滿懷空貯活人書。", "悶呼赤脚行沽酒，出遣蒼頭旋僦驢。", "不爲歸休習疏懶，愛閑元與市朝疏。"]'),
('47a120e9-2c9d-4c35-9432-bd9523323a47','枕上','陸游','宋','宋诗','song-poetry','','[]','送盡小窗月，數殘孤戍更。',48,'全唐诗/poet.song.133000.json','["送盡小窗月，數殘孤戍更。", "清詩時自至，幽夢久方成。", "衣杵斷還續，燈花落復生。", "細衾剩得暖，紙帳不知明。"]'),
('6d16b57b-2ac0-430e-85f2-5d779fe0450c','遠遊','陸游','宋','宋诗','song-poetry','','[]','老子平生喜遠遊，流塵不惜闇貂裘。',64,'全唐诗/poet.song.133000.json','["老子平生喜遠遊，流塵不惜闇貂裘。", "江亭吹笛三巴夜，關路騎驢二華秋。", "但使澄心同止水，自知幻境等浮漚。", "悠然飽聽松風睡，勾漏丹砂底用求。"]'),
('a3366cb4-64c2-4690-ba1f-7d1fd3b5aa3b','晚遊','陸游','宋','宋诗','song-poetry','','[]','垣屋參差出，溝谿曲折通。',48,'全唐诗/poet.song.133000.json','["垣屋參差出，溝谿曲折通。", "亂鴉空際黑，落日竹間紅。", "軋軋輿竿語，摇摇旛脚風。", "吾行本無定，隨意入空濛。"]'),
('2b0297c1-df0b-491b-927c-e33ae0172c6b','夜坐','陸游','宋','宋诗','song-poetry','','[]','流落知聞絕，歸休寵辱空。',48,'全唐诗/poet.song.133000.json','["流落知聞絕，歸休寵辱空。", "酒狂寧限老，詩思正須窮。", "活火生新焰，殘燈委碎紅。", "平生會心處，正在兀然中。"]'),
('dc2e9ad7-03c0-4211-9d32-6bc3b2a782ed','酒熟醉中作短歌','陸游','宋','宋诗','song-poetry','','[]','陸子壯已窮，百計不救口。',120,'全唐诗/poet.song.133000.json','["陸子壯已窮，百計不救口。", "蜀道如上天，十年厭奔走。", "還鄉困猶昨，負郭無百畝。", "雖云饑欲死，亦未喪所守。", "虛名一畫餅，陳迹幾芻狗。", "但思從壯士，大獵雲夢藪。", "長戈白如霜，爛漫載牛酒。", "箭穿乳虎立，車轔蒼兕吼。", "歸來數禽獲，毛血灑戶牖。", "人生貴適意，富貴安可苟。"]'),
('8e89f3dd-27f0-404d-99ae-413cc30ccbb0','冬夜讀書有感','陸游','宋','宋诗','song-poetry','','[]','落葉殘蕪又一冬，老人光景易匆匆。',64,'全唐诗/poet.song.133000.json','["落葉殘蕪又一冬，老人光景易匆匆。", "不論病惰耕桑業，但恨貧分學問功。", "馬昔騰驤離冀北，鶴今憔悴返遼東。", "六經未與秦灰冷，尚付餘年斷簡中。"]'),
('d381f535-e642-4e9b-8a85-6d22f959daec','散步湖上至野人家','陸游','宋','宋诗','song-poetry','','[]','湖上霜高水落時，一藤信步出尋詩。',64,'全唐诗/poet.song.133000.json','["湖上霜高水落時，一藤信步出尋詩。", "妄誇强健真堪笑，喚作清閑亦自欺。", "西埭又隨牛迹去，東村常望鸛巢知。", "漁翁留客頻辭謝，雞瘦難烹酒味漓。"]'),
('fd4b7570-42a8-4064-b450-8254439848fc','對食戲詠','陸游','宋','宋诗','song-poetry','','[]','癭榼傾桑落，毫杯點雨前。',48,'全唐诗/poet.song.133000.json','["癭榼傾桑落，毫杯點雨前。", "冰梨頳似頰，霜栗大如拳。", "洗鬴烹蔬甲，携鉏斸荀鞭。", "餘年只此是，切勿念腥膻。"]'),
('d477e487-b201-4f63-bd94-26cb50d103ab','昨非','陸游','宋','宋诗','song-poetry','','[]','溫飽從來與道違，書生只合卧牛衣。',64,'全唐诗/poet.song.133000.json','["溫飽從來與道違，書生只合卧牛衣。", "老狐五百生前錯，孤鶴三千歲後歸。", "舌自生肥勝玉食，腰常忘带况金圍。", "一官彭澤曾何有，元亮還家悔昨非。"]'),
('f89abd38-669f-449e-8f68-2ede3c550a5d','遂初','陸游','宋','宋诗','song-poetry','','[]','貧士善用短，屏居常自如。',48,'全唐诗/poet.song.133000.json','["貧士善用短，屏居常自如。", "出尋鄰叟語，歸讀古人書。", "過店亦沽酒，登山時跨驢。", "非關傲塵世，聊欲遂吾初。"]'),
('cacf18a1-b190-418b-b3e1-414fd207b1bb','小雨偶出鄰里小兒競隨吾後不知其意何也','陸游','宋','宋诗','song-poetry','','[]','雲生海澨初飛雨，日漏山椒旋作晴。',32,'全唐诗/poet.song.133000.json','["雲生海澨初飛雨，日漏山椒旋作晴。", "箬笠芒鞋橋下路，兒童爭逐放翁行。"]'),
('1817aa99-3bd7-4b43-b3dc-543a669b1c93','書喜','陸游','宋','宋诗','song-poetry','','[]','堪笑龜堂老更頑，天教白髮看青山。',64,'全唐诗/poet.song.133000.json','["堪笑龜堂老更頑，天教白髮看青山。", "家居禹廟蘭亭路，詩在林逋魏野間。", "略計未嘗三日醒，細推猶得半生閑。", "今年况展南湖面，朝借樵風暮可還。"]'),
('b6e0d7b2-35c1-4046-864f-564a448d5b54','書房雜書二首  其一','陸游','宋','宋诗','song-poetry','','[]','斂版一何久，懸車已後時。',48,'全唐诗/poet.song.133000.json','["斂版一何久，懸車已後時。", "狂酲醒始悔，窮獨老方知。", "世外乾坤大，林間日月遲。", "猶須采藥去，不愧鹿門期。"]'),
('06e45982-447a-40df-b163-603068214f89','書房雜書二首  其二','陸游','宋','宋诗','song-poetry','','[]','面槁髮鬅鬙，衰殘百不能。',48,'全唐诗/poet.song.133000.json','["面槁髮鬅鬙，衰殘百不能。", "夜房侵戶月，晨硯滿池冰。", "藥債多於酒，蔬餐薄過僧。", "年深拄杖折，自斫澗邊藤。"]'),
('86db9162-359c-4ed3-a14d-79d240d84e84','寒夕','陸游','宋','宋诗','song-poetry','','[]','夜扣銅壺徹旦吟，了無人會此時心。',64,'全唐诗/poet.song.133000.json','["夜扣銅壺徹旦吟，了無人會此時心。", "燈殘焰作孤螢小，火冷灰如積雪深。", "風急江天無過雁，月明庭戶有疏碪。", "此身畢竟歸何許，但憶藏舟黄葦林。"]'),
('7b732d96-0a73-4269-99d1-cdb22e1dbe42','讀經','陸游','宋','宋诗','song-poetry','','[]','半升粟飯養殘軀，晨起衣冠讀典謨。',32,'全唐诗/poet.song.133000.json','["半升粟飯養殘軀，晨起衣冠讀典謨。", "莫謂此生無用處，一身自是一唐虞。"]'),
('a5657c55-9dcd-429a-8435-801212cb1929','讀史','陸游','宋','宋诗','song-poetry','','[]','民間斗米兩三錢，萬里耕桑罷戍邊。',32,'全唐诗/poet.song.133000.json','["民間斗米兩三錢，萬里耕桑罷戍邊。", "常使屏風寫無逸，應無烽火照甘泉。"]'),
('81b48b4f-4f3f-4bd7-840c-f15391d13b8a','讀劉蕡策','陸游','宋','宋诗','song-poetry','','[]','志士仁人氣薄雲，唐家惟有一劉蕡。',32,'全唐诗/poet.song.133000.json','["志士仁人氣薄雲，唐家惟有一劉蕡。", "看渠放逐蛇龍手，那肯驅蠅與拍蚊。"]'),
('52ed3d4c-32ab-4615-bf0c-8a9a912cfd70','雨霰作雪不成大風散雲月色皎然','陸游','宋','宋诗','song-poetry','','[]','數間茅屋寄蓬蒿，天遣來歸息我勞。',64,'全唐诗/poet.song.133000.json','["數間茅屋寄蓬蒿，天遣來歸息我勞。", "月可一庭陳素練，風酣萬木起驚濤。", "病侵齒髮才雖盡，酒挾江山氣尚豪。", "安得人間掣鯨手，共提筆陣法莊騷。"]'),
('5aae61f3-8043-4be4-9322-c698dfd5aae4','中夜苦寒','陸游','宋','宋诗','song-poetry','','[]','困窮全素節，羸老愈剛腸。',48,'全唐诗/poet.song.133000.json','["困窮全素節，羸老愈剛腸。", "報國永無日，飯蔬那自傷。", "布衾如鐵冷，冬夜抵年長。", "推枕歌梁甫，中庭月似霜。"]'),
('28de5aca-a3c8-41a1-b5c0-a3356ec2cc4c','示子孫二首  其一','陸游','宋','宋诗','song-poetry','','[]','爲貧出仕退爲農，二百年來世世同。',32,'全唐诗/poet.song.133000.json','["爲貧出仕退爲農，二百年來世世同。", "富貴苟求終近禍，汝曹切勿墜家風。"]'),
('cfcde9b3-43f5-44ee-9c20-7e86ebb1c813','示子孫二首  其二','陸游','宋','宋诗','song-poetry','','[]','吾家世守農桑業，一挂朝衣即力耕。',32,'全唐诗/poet.song.133000.json','["吾家世守農桑業，一挂朝衣即力耕。", "汝但從師勤學問，不須念我叱牛聲。"]'),
('4dd04e76-85dc-478b-8795-d6277cf07b31','早梅','陸游','宋','宋诗','song-poetry','','[]','東塢梅初動，香來託意深。',24,'全唐诗/poet.song.133000.json','["東塢梅初動，香來託意深。", "明知在籬外，行到却難尋。"]'),
('9ceb23f5-30b4-4dad-b4c3-f9ab6b355385','縱筆二首  其一','陸游','宋','宋诗','song-poetry','','[]','晨炊躬稼米，夜讀世藏書。',24,'全唐诗/poet.song.133000.json','["晨炊躬稼米，夜讀世藏書。", "俯仰無多愧，心知死有餘。"]'),
('29a18fe8-7bb1-4b4e-ae35-591d86a75192','縱筆二首  其二','陸游','宋','宋诗','song-poetry','','[]','破囷供飯足，陋屋著身寬。',24,'全唐诗/poet.song.133000.json','["破囷供飯足，陋屋著身寬。", "小蹇勤芻秣，時時一跨鞍。"]'),
('ce6cb3d7-550b-4563-b7bd-34994e00ed0f','歲暮雜感四首  其一','陸游','宋','宋诗','song-poetry','','[]','衰髮如枯菅，殘齒如敗屐。',72,'全唐诗/poet.song.133000.json','["衰髮如枯菅，殘齒如敗屐。", "取米煮薄糜，便足度晨夕。", "欲知死遠近，不必訊龜筴。", "四序忽已過，如數堠雙隻。", "發裝陌上亭，具食水邊驛。", "會當一日歸，豈有終作客。"]'),
('beef2f74-32a9-4424-834f-eec8b0325d1f','歲暮雜感四首  其二','陸游','宋','宋诗','song-poetry','','[]','天風吹雪片，大者如飛鷗。',72,'全唐诗/poet.song.133000.json','["天風吹雪片，大者如飛鷗。", "豈惟平溝坑，直恐薶馬牛。", "百錢買薪蒸，千錢贖褐裘。", "雖無狐貉溫，要免溝壑憂。", "小兒爲我言，幸可具杯甌。", "園蔬亦復佳，過足翁豈求。"]'),
('5bfaa266-f9d4-4676-b165-e9fc1efb3c5d','歲暮雜感四首  其三','陸游','宋','宋诗','song-poetry','','[]','歲盡霜雪稠，相望僵萬木。',72,'全唐诗/poet.song.133000.json','["歲盡霜雪稠，相望僵萬木。", "天豈私梅花，獨畀此芬馥。", "高標我自有，何憾老空谷。", "人言和羹實，晚或參鼎餗。", "哀哉世論卑，汙我塵外躅。", "誰能湔祓之，寫真配修竹。"]'),
('8be6176e-8d95-49cb-9e65-042f38e364bc','歲暮雜感四首  其四','陸游','宋','宋诗','song-poetry','','[]','我少雖嗜書，賦性實慵惰。',72,'全唐诗/poet.song.133000.json','["我少雖嗜書，賦性實慵惰。", "初志略未酬，白髮已無那。", "吾兒猶好勇，世事如棄唾。", "呻吟編簡中，徹旦或未卧。", "爾來愈自勵，日讀易一過。", "勉終大學功，吾道要負荷。"]'),
('899a6190-79c7-4fe7-b01c-d40c059379e9','自責','陸游','宋','宋诗','song-poetry','','[]','晨起登堂正幅巾，蕭然聊欲養吾神。',64,'全唐诗/poet.song.133000.json','["晨起登堂正幅巾，蕭然聊欲養吾神。", "凡心未免更詩字，習氣猶思議古人。", "買屩爲登山寺去，徹燈緣愛月窗新。", "何時一切消除盡，終作無懷上古民。"]'),
('490a01d7-3881-455d-a10f-963a834f8ad9','懷舊用昔人蜀道詩韵','陸游','宋','宋诗','song-poetry','','[]','曩自白帝城，一馬獨入蜀。',252,'全唐诗/poet.song.133000.json','["曩自白帝城，一馬獨入蜀。", "晝行多水湄，夜宿必山麓。", "時聞木客嘯，常憂射工毒。", "蜿蜒蛇兩頭，踸踔夔一足。", "豈惟耳目駭，直恐性命促。", "稍歷葭萌西，遂出劍閣北。", "奴僵不敢訴，馬病猶盡力。", "我亦困人客，一日带屢束。", "最憶蒼溪縣，送客一亭綠。", "豆枯狐兔肥，霜早柿栗熟。", "酒酸壓查梨，妓野立土木。", "主別意益勤，我去疲已極。", "行行求旅店，借問久乃得。", "溪聲答歌長，燈焰照影獨。", "村深寒更甚，薪盡燒簀竹。", "須臾風雨至，終夕苦漏屋。", "於時厭道途，自誓棄微祿。", "猶幾三十年，始謝祝史職。", "君恩念篤老，內閣使寓直。", "亦思秋豪報，力憊藝黍稷。", "却尋少時書，開卷有慚色。"]'),
('453a08db-3998-4b7d-baf3-1caa5d1b7775','出遊','陸游','宋','宋诗','song-poetry','','[]','僧院軒窗酒市樓，過門自入不須留。',64,'全唐诗/poet.song.133000.json','["僧院軒窗酒市樓，過門自入不須留。", "恰來竹下尋棋局，又向沙邊上釣舟。", "詩放不能諧律呂，書狂猶足走蛟虯。", "秦碑禹窆風烟外，一吊興亡萬古愁。"]'),
('1d2c25ae-9d1c-4fd5-9fcc-40aaf290d375','辛酉冬至','陸游','宋','宋诗','song-poetry','','[]','今日日南至，吾門方寂然。',48,'全唐诗/poet.song.133000.json','["今日日南至，吾門方寂然。", "家貧輕過節，身老怯增年。", "畢祭皆扶拜，分盤獨早眠。", "惟應探春夢，已繞鏡湖邊。"]'),
('b56939e9-f680-41a6-8138-df4daa4e7a3f','冬至後一日書','陸游','宋','宋诗','song-poetry','','[]','霜霰新冬後，年齡大耋時。',48,'全唐诗/poet.song.133000.json','["霜霰新冬後，年齡大耋時。", "功名久無夢，文字略存詩。", "丘壟歸何憾，琴書付有兒。", "癡人癡到底，更欲數期頤。"]'),
('28475b35-19c7-4ac9-bbe7-81f57bc4582e','客至','陸游','宋','宋诗','song-poetry','','[]','何處軒車客，能來桑麥村。',48,'全唐诗/poet.song.133000.json','["何處軒車客，能來桑麥村。", "一奴先入市，此老自應門。", "野果嘗皆澀，村醅壓尚渾。", "殘年亦何恨，治世作黎元。"]'),
('9c196725-e26f-40d9-b10a-c4c533db33fb','子聿入城','陸游','宋','宋诗','song-poetry','','[]','小硯寒生凍，孤燈翳復明。',48,'全唐诗/poet.song.133000.json','["小硯寒生凍，孤燈翳復明。", "衰翁守微火，稚子隔重城。", "日落林無影，舟行水有聲。", "詩家忌草草，得句未須成。"]'),
('b361be8e-637e-4f5b-8c08-bbc9920855bc','降魔','陸游','宋','宋诗','song-poetry','','[]','老閱人間久，曾降百萬魔。',48,'全唐诗/poet.song.133000.json','["老閱人間久，曾降百萬魔。", "悲憂誠害性，喜悅亦傷和。", "省事常須勉，忘懷得最多。", "當年未知此，無奈月明何。"]'),
('3df89bda-c22a-4fc2-a2d2-66ef41737404','冬日二首  其一','陸游','宋','宋诗','song-poetry','','[]','故里躬耕後，頹齡耄及前。',48,'全唐诗/poet.song.133000.json','["故里躬耕後，頹齡耄及前。", "開門無客至，得句有僧傳。", "忽忽身如夢，迢迢日似年。", "會當乘小雪，夜上剡溪船。"]'),
('3aae8833-89a0-41a5-8ff3-6d3ab7913a7e','冬日二首  其二','陸游','宋','宋诗','song-poetry','','[]','客至惟清坐，真貧不是慳。',48,'全唐诗/poet.song.133000.json','["客至惟清坐，真貧不是慳。", "援琴排遣悶，合藥破除閑。", "引鶴時穿屐，逢梅一破顔。", "怪來寒徹骨，夜雪冒南山。"]'),
('0f9ee6db-dfd8-4f1c-a8b0-facccc18ea2e','客去','陸游','宋','宋诗','song-poetry','','[]','相對蒲團睡味長，主人與客兩相忘。',32,'全唐诗/poet.song.133000.json','["相對蒲團睡味長，主人與客兩相忘。", "須臾客去主人覺，一半西窗無夕陽。"]'),
('1891a4f4-32f8-4abe-81e3-2cd481bb9fa0','自勉四首  其一','陸游','宋','宋诗','song-poetry','','[]','妄出真成錯，歸耕惜已遲。',48,'全唐诗/poet.song.133000.json','["妄出真成錯，歸耕惜已遲。", "褐溫貧始覺，飯美淡方知。", "身外元無易，情中自有詩。", "窮源那得止，瞑目以爲期。"]'),
('3bf0c7cd-f77c-4069-af0c-8386919ccb59','自勉四首  其二','陸游','宋','宋诗','song-poetry','','[]','自信直如弦，殘年偶得全。',48,'全唐诗/poet.song.133000.json','["自信直如弦，殘年偶得全。", "老猶嗤佞佛，貧亦諱言錢。", "旦暮勤鞭策，塵埃痛洗湔。", "仍須語兒子，此事要家傳。"]'),
('429e38d6-4a79-4308-b32c-88dff2dffb3c','自勉四首  其三','陸游','宋','宋诗','song-poetry','','[]','臂弱傳鈔少，心煩記問衰。',48,'全唐诗/poet.song.133000.json','["臂弱傳鈔少，心煩記問衰。", "讀書猶自力，愛日似兒時。", "章句分無憾，聲形講不遺。", "明年幸强健，閉戶有餘師。"]'),
('ccc83b0f-913a-4f8a-be66-c3d2c185a1cc','自勉四首  其四','陸游','宋','宋诗','song-poetry','','[]','歸老寧常逸，時時學荷鉏。',48,'全唐诗/poet.song.133000.json','["歸老寧常逸，時時學荷鉏。", "室雖無長物，圃尚有餘蔬。", "壯志誠衰矣，貧居亦晏如。", "爲農當世業，安用筑門閭。"]'),
('62b5277b-4e7a-4364-8c0f-327a8543b0f5','午晴至園中','陸游','宋','宋诗','song-poetry','','[]','老不禁寒起每遲，出門蕭散午晴時。',64,'全唐诗/poet.song.133000.json','["老不禁寒起每遲，出門蕭散午晴時。", "春回九地梅先覺，霜霣千林竹不知。", "藥圃采苗芒屨溼，石泉照影角巾欹。", "歸來未過西簷日，袖手悠然獨詠詩。"]'),
('2db9e701-268c-4036-824f-91c1d5478b8a','七侄歲暮同諸孫來過偶得長句','陸游','宋','宋诗','song-poetry','','[]','雨墊林宗一角巾，蕭條村路並烟津。',64,'全唐诗/poet.song.133000.json','["雨墊林宗一角巾，蕭條村路並烟津。", "四朝遇主終身困，八世爲儒舉族貧。", "行摘殘蔬循廢圃，卧聞饑雀噪空囷。", "封胡羯末皆佳甚，剩喜團欒一笑新。"]'),
('159831ad-bc15-4eb8-9c50-e5977ccd7f77','苦寒','陸游','宋','宋诗','song-poetry','','[]','終日頻添季子裘，經旬不上仲宣樓。',64,'全唐诗/poet.song.133000.json','["終日頻添季子裘，經旬不上仲宣樓。", "摩挲酒榼雖堪喜，疏索梅花未免愁。", "正苦冰生退吟筆，却思雪作潤耕疇。", "乘除擾擾殊多事，獨擁青氈覓睡休。"]'),
('f2d6dfe7-68bf-49a3-995c-55a1317a2657','閑中書適二首  其一','陸游','宋','宋诗','song-poetry','','[]','棋廢機心息，書捐美睡多。',48,'全唐诗/poet.song.133000.json','["棋廢機心息，書捐美睡多。", "客來時淡話，酒後亦高歌。", "甚欲江湖去，無如老病何。", "平羌半輪月，依舊照漁蓑。"]'),
('34a3d8f2-bf36-40b7-a85f-11caed965a7b','閑中書適二首  其二','陸游','宋','宋诗','song-poetry','','[]','乞得殘骸久，天涯一禿翁。',48,'全唐诗/poet.song.133000.json','["乞得殘骸久，天涯一禿翁。", "瓢分春甕綠，甑絕太倉紅。", "短褐便冬暖，長歌樂歲豐。", "老腰那可折，步步賴枯筇。"]'),
('7a8a4ca3-7edd-454f-9ff0-9ec17f2d0e79','復湖','陸游','宋','宋诗','song-poetry','','[]','世事相尋敗與成，湖中畚鍤浩縱橫。',64,'全唐诗/poet.song.133000.json','["世事相尋敗與成，湖中畚鍤浩縱橫。", "共知陂壞行當復，敢恨臺高既已傾。", "天鏡忽看孤月墮，樵風長送片帆輕。", "下臨萬頃如雲稼，從此年年有頌聲。"]'),
('c575d20d-c9c4-4bd0-86be-3d900ba06532','梅花絕句四首  其一','陸游','宋','宋诗','song-poetry','','[]','體中頗覺不能佳，急就梅花一散懷。',32,'全唐诗/poet.song.133000.json','["體中頗覺不能佳，急就梅花一散懷。", "衝雨涉溪君會否，免教塵土涴青鞋。"]'),
('e50a248c-c2d1-442a-96c9-98a2a36e3cee','梅花絕句四首  其二','陸游','宋','宋诗','song-poetry','','[]','高韵知難折簡呼，溪頭掃地置芳壺。',32,'全唐诗/poet.song.133000.json','["高韵知難折簡呼，溪頭掃地置芳壺。", "梅如解語應惆悵，昔日名流一箇無。"]'),
('7e4cf931-0e2f-4efe-8a19-b2746de21c97','梅花絕句四首  其三','陸游','宋','宋诗','song-poetry','','[]','折得梅花古渡頭，詩凡却恐作花羞。',32,'全唐诗/poet.song.133000.json','["折得梅花古渡頭，詩凡却恐作花羞。", "清樽賴有平生約，爛醉千場死即休。"]'),
('aa590e1a-9ba7-499f-8d7a-469c6c91c944','梅花絕句四首  其四','陸游','宋','宋诗','song-poetry','','[]','疏枝冷蕊誰能畫，楊叟江西舊擅名。',32,'全唐诗/poet.song.133000.json','["疏枝冷蕊誰能畫，楊叟江西舊擅名。", "今日東窗閑拂拭，去人一尺眼先明。"]'),
('818c240a-c24c-4e37-81b5-1964fe3c9208','跋馮氏蘭亭二首  其一','陸游','宋','宋诗','song-poetry','','[]','堂堂淮陰侯，夫豈噲等伍。',24,'全唐诗/poet.song.133000.json','["堂堂淮陰侯，夫豈噲等伍。", "放翁評此本，可作蘭亭祖。"]'),
('f0136383-80c8-441f-aeb7-ad201dba94cc','跋馮氏蘭亭二首  其二','陸游','宋','宋诗','song-poetry','','[]','繭紙藏昭陵，千載不復見。',24,'全唐诗/poet.song.133000.json','["繭紙藏昭陵，千載不復見。", "此本得其骨，殊勝蘭亭面。"]'),
('e9dcd061-91ad-410c-b3d6-fb1749b035c0','十二月二日夜夢與客並馬行黄河上憩於古驛二首  其一','陸游','宋','宋诗','song-poetry','','[]','並轡徐驅百里中，雲開太華翠摩空。',32,'全唐诗/poet.song.133000.json','["並轡徐驅百里中，雲開太華翠摩空。", "是間合有神靈在，七十餘年墮犬戎。"]'),
('79d75348-692e-4f12-9e67-82f07f4e6d68','十二月二日夜夢與客並馬行黄河上憩於古驛二首  其二','陸游','宋','宋诗','song-poetry','','[]','河濱古驛闢重門，雉兔紛紛黍酒渾。',32,'全唐诗/poet.song.133000.json','["河濱古驛闢重門，雉兔紛紛黍酒渾。", "吾輩豈應徒醉飽，會傾東海洗中原。"]'),
('7baef3af-ef22-4797-be45-04d15e0a1fab','倚樓','陸游','宋','宋诗','song-poetry','','[]','暮雲細細鱗千疊，新月纖纖玉一釣。',32,'全唐诗/poet.song.133000.json','["暮雲細細鱗千疊，新月纖纖玉一釣。", "嘆息化工真妙手，衝寒來倚水邊樓。"]'),
('b8772801-714a-4cf1-a05d-1b2c9c6be062','讀書','陸游','宋','宋诗','song-poetry','','[]','先親愛我讀書聲，追慕慈顔涕每傾。',64,'全唐诗/poet.song.133000.json','["先親愛我讀書聲，追慕慈顔涕每傾。", "萬事到前心盡懶，一編相向眼偏明。", "致君正使違初志，爲己猶當畢此生。", "更祝吾兒思早退，雨蓑烟笠事春耕。"]'),
('b35bd98f-976e-44f7-8669-9745ee34bf8a','讀史','陸游','宋','宋诗','song-poetry','','[]','夜對遺編嘆復驚，古來成敗浩縱橫。',64,'全唐诗/poet.song.133000.json','["夜對遺編嘆復驚，古來成敗浩縱橫。", "功名多向窮中立，禍患常從巧處生。", "萬里關河歸夢想，千年王霸等棋枰。", "人間只有躬耕是，路過桑村最眼明。"]'),
('07f372d0-42cf-44e2-aabb-b654b1a73a38','閑遊','陸游','宋','宋诗','song-poetry','','[]','已破梅花一兩枝，並溪穿塢每歸遲。',64,'全唐诗/poet.song.133000.json','["已破梅花一兩枝，並溪穿塢每歸遲。", "老軀健似中年日，鄉俗淳如太古時。", "上疏清狂非復昔，據鞍矍鑠欲誇誰。", "一端尚被鄰翁笑，無事長吟費撚髭。"]'),
('fd2dc037-183f-4812-8dab-9792e08991ed','日暮','陸游','宋','宋诗','song-poetry','','[]','樸學無關道廢興，更堪衰與病相乘。',32,'全唐诗/poet.song.133000.json','["樸學無關道廢興，更堪衰與病相乘。", "眼看白日西南去，繩繫膠黏總不能。"]'),
('a32d557b-6c56-4145-94f8-0fdf4370535d','省事','陸游','宋','宋诗','song-poetry','','[]','老去終年卧草廬，事皆省盡略無餘。',64,'全唐诗/poet.song.133000.json','["老去終年卧草廬，事皆省盡略無餘。", "塵留鼠迹猶嗔拂，風作瓢聲固不除。", "興發舊醅何害醉，詩成拙筆亦堪書。", "投床睡美悠然覺，作計今知本不疏。"]'),
('98cdc2cb-4386-438f-a02c-c3c175f449ae','雪中作','陸游','宋','宋诗','song-poetry','','[]','鬢毛無奈歲華催，一笑登臨亦樂哉。',64,'全唐诗/poet.song.133000.json','["鬢毛無奈歲華催，一笑登臨亦樂哉。", "平地忽成三尺雪，繞湖何啻萬株梅。", "雲山疊疊朝憑閣，簾幕沉沉夜舉杯。", "節物鼎來方自此，酥花綵勝待春回。"]'),
('7f63b3d9-9f2a-443c-ae47-9c440f6c29d8','夢韓无咎王季夷諸公','陸游','宋','宋诗','song-poetry','','[]','積雪欲照夜，老雞方唱晨。',48,'全唐诗/poet.song.133000.json','["積雪欲照夜，老雞方唱晨。", "諸公逝已久，幽夢忽相親。", "話舊殷勤意，追歡見在身。", "悠然又驚覺，撫枕一悲辛。"]'),
('e6f64d85-daa9-40e6-a887-3e969ae43553','晴窗讀書自勉','陸游','宋','宋诗','song-poetry','','[]','今日雪始晴，繞舍鳥烏樂。',120,'全唐诗/poet.song.133000.json','["今日雪始晴，繞舍鳥烏樂。", "老來少睡眠，雖病亦早作。", "豈無案上書，可與共寂寞。", "弦歌始風雅，次第窺灝噩。", "高明仰河漢，曲折窮脈絡。", "唐虞誠未遠，洙泗亦如昨。", "委佩聞都俞，避席承博約。", "膏肓幸施砭，幽閟欣納鑰。", "天全魯壁藏，不墮秦火虐。", "吾生百世餘，其敢負所託。"]'),
('aa2aff93-cb96-48a1-9feb-9bf8e5d5249b','冬夜讀史有感','陸游','宋','宋诗','song-poetry','','[]','短檠膏涸夜將殘，感事懷人興未闌。',64,'全唐诗/poet.song.133000.json','["短檠膏涸夜將殘，感事懷人興未闌。", "酌酒淺深須自度，圍棋成敗有傍觀。", "斷粞作飯終年飽，大布裁袍稱意寬。", "世上閑愁千萬斛，不教一點上眉端。"]'),
('0d3a2e10-1e69-439f-b666-a5b9c1b1814e','大寒','陸游','宋','宋诗','song-poetry','','[]','大寒雪未消，閉戶不能出。',96,'全唐诗/poet.song.133000.json','["大寒雪未消，閉戶不能出。", "可憐切雲冠，局此容膝室。", "吾車適已懸，吾馭久罷叱。", "拂塵取一編，相對輒終日。", "亡羊戒多岐，學道當致一。", "信能宗闕里，百氏端可黜。", "爲山儻勿休，會見高崒嵂。", "頹齡雖已迫，孺子有美質。"]'),
('68da1eda-625f-4c59-b22e-542ab90b52b0','自詠','陸游','宋','宋诗','song-poetry','','[]','滿梳晨起髮凋零，亭午柴門未徹扃。',64,'全唐诗/poet.song.133000.json','["滿梳晨起髮凋零，亭午柴門未徹扃。", "萬事忘來尚憂國，百家屏盡獨窮經。", "楠枯倒壑雖無用，龜老搘床故有靈。", "夢裏騎驢華山去，破雲巉絕數峰青。"]'),
('6f9ad794-a84f-400b-87a6-e95dd157c5fe','晚興','陸游','宋','宋诗','song-poetry','','[]','斸芋挑蔬自煮羹，雪簷收滴暮寒生。',32,'全唐诗/poet.song.133000.json','["斸芋挑蔬自煮羹，雪簷收滴暮寒生。", "不嫌終日無來客，時聽荒園斲木聲。"]'),
('ce63bd4c-41ec-4e21-ae79-bd2c3c4aca23','雪後寒甚','陸游','宋','宋诗','song-poetry','','[]','日破重雲出，春從淺步來。',48,'全唐诗/poet.song.133000.json','["日破重雲出，春從淺步來。", "未融樓北雪，先綻水南梅。", "屏護清吟硯，缸鳴乍熟醅。", "平生羨李愬，入蔡夜銜枚。"]'),
('3267046c-f1d4-4fa7-b918-da27a23ea874','雪晴步至舍傍','陸游','宋','宋诗','song-poetry','','[]','雪消還似雨，冰釋旋成泥。',48,'全唐诗/poet.song.133000.json','["雪消還似雨，冰釋旋成泥。", "視菜荒陂北，尋梅小塢西。", "牆陰新犢卧，庭際午雞啼。", "幽興殊無極，歸來日已低。"]'),
('d0f16eb3-9954-4ac9-8412-5a898b2097d5','訪隱者','陸游','宋','宋诗','song-poetry','','[]','湖曲有隱者，時時容叩門。',48,'全唐诗/poet.song.133000.json','["湖曲有隱者，時時容叩門。", "人如釣渭叟，地似避秦村。", "笑語囂塵遠，衣冠古製存。", "山寒歸路晚，相與盡瓢樽。"]'),
('1625b6af-6d00-4a60-b624-0dcbba99d982','村野','陸游','宋','宋诗','song-poetry','','[]','村野易過日，閉門心自欣。',48,'全唐诗/poet.song.133000.json','["村野易過日，閉門心自欣。", "一身猶逆旅，萬事固浮雲。", "病厭詩爲祟，閑憑酒策勳。", "灌園雖舊業，隨事不須勤。"]'),
('40d1bb37-0197-40a0-96eb-4745720ca451','初夜','陸游','宋','宋诗','song-poetry','','[]','初夜多幽興，危闌偶獨憑。',48,'全唐诗/poet.song.133000.json','["初夜多幽興，危闌偶獨憑。", "月陞星盡沒，風勁雪重凝。", "身似遊邊客，心如退院僧。", "奇寒不可耐，歸對北窗燈。"]'),
('a0429412-d68f-4452-9b2d-286669e37ac1','雙松','陸游','宋','宋诗','song-poetry','','[]','東岡夭矯兩蒼龍，千尺蟠空黛色濃。',32,'全唐诗/poet.song.133000.json','["東岡夭矯兩蒼龍，千尺蟠空黛色濃。", "六十餘年松若此，誰知我更老於松。"]'),
('4c05fd72-5d48-48ea-add3-88c629c4d33a','兀兀','陸游','宋','宋诗','song-poetry','','[]','兀兀孤村客，悠悠兩世人。',48,'全唐诗/poet.song.133000.json','["兀兀孤村客，悠悠兩世人。", "夢忘身潦倒，醉覺膽輪囷。", "故里簪纓換，都門巷陌新。", "餘年猶有幾，撫事一傷神。"]'),
('a8a773dc-46bd-4dc0-87fd-09d15c0c002b','殘曆','陸游','宋','宋诗','song-poetry','','[]','殘曆不盈紙，苦寒侵弊裘。',48,'全唐诗/poet.song.133000.json','["殘曆不盈紙，苦寒侵弊裘。", "歲豬鳴屋角，儺鼓轉街頭。", "未死猶當學，長貧肯復憂。", "雪晴農事起，且復議租牛。"]'),
('f3c24c58-be5d-4cf7-aee3-c41e332fe0f9','戒言','陸游','宋','宋诗','song-poetry','','[]','饒舌憂患始，銘膺勸戒深。',48,'全唐诗/poet.song.133000.json','["饒舌憂患始，銘膺勸戒深。", "談空摩詰默，對酒子光瘖。", "久已忘齊語，何嘗解越吟。", "悠然嫌未足，更撫絕弦琴。"]'),
('db98a2a7-516a-4046-9af0-798dd1b6e92e','聞松風有感','陸游','宋','宋诗','song-poetry','','[]','重位每憂身後罵，虛名不救眼前饑。',32,'全唐诗/poet.song.133000.json','["重位每憂身後罵，虛名不救眼前饑。", "直須采藥名山去，日夜松風無歇時。"]'),
('b0b90dff-d638-4908-a999-c6f6df7aae04','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','侯印從來非所圖，赤丁子亦不容呼。',64,'全唐诗/poet.song.133000.json','["侯印從來非所圖，赤丁子亦不容呼。", "著低怯對新棋敵，量減愁逢舊酒徒。", "生世豈能常役役，酣歌且復和嗚嗚。", "扁舟到處皆吾境，莫問桐江與鏡湖。"]'),
('1d84115a-4700-4e8e-880f-2874de2212ac','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','家住城南剡曲傍，門前山色蘸湖光。',64,'全唐诗/poet.song.133000.json','["家住城南剡曲傍，門前山色蘸湖光。", "三朝執戟悲年往，二頃扶犁樂歲穰。", "名姓已隨身共隱，文辭終與道相妨。", "子孫勉守東皋業，小甑吳粳底樣香。"]'),
('db5e9fff-ab4e-4398-9e58-b5cc304ca438','有道流過門留與之語頗異口占贈之','陸游','宋','宋诗','song-poetry','','[]','萬里縱橫自在身，偶然來看剡溪春。',64,'全唐诗/poet.song.133000.json','["萬里縱橫自在身，偶然來看剡溪春。", "取將月去閑娛客，携得雲歸遠寄人。", "縮地不妨遊汗漫，移山隨處對嶙峋。", "須君更出囊中劍，一爲關河洗虜塵。"]'),
('704e178f-d2cb-46a8-b9c9-eaa0dcfd6919','閑記老境二首  其一','陸游','宋','宋诗','song-poetry','','[]','謝事久懸車，爲農懶荷鉏。',48,'全唐诗/poet.song.133000.json','["謝事久懸車，爲農懶荷鉏。", "破裘寒旋補，殘髮短猶梳。", "槁木忘榮謝，閑雲任卷舒。", "心知老當逸，先罷夜觀書。"]'),
('63f11a8b-c9dd-46f0-9948-59bee11dc486','閑記老境二首  其二','陸游','宋','宋诗','song-poetry','','[]','嫌鬧不入市，怕寒稀出門。',48,'全唐诗/poet.song.133000.json','["嫌鬧不入市，怕寒稀出門。", "擁爐愁兀兀，投枕睡昏昏。", "柳色新如染，梅花香滿村。", "猶嗟未免俗，薄酒誑空樽。"]'),
('310d652f-b7fd-422f-beb5-b2f553a2f1fe','小飲梅花下作','陸游','宋','宋诗','song-poetry','','[]','脫巾莫嘆髮成絲，六十年間萬首詩。',64,'全唐诗/poet.song.133000.json','["脫巾莫嘆髮成絲，六十年間萬首詩。", "排日醉過梅落後，通宵吟到雪殘時。", "偶容後死寧非幸，自乞歸耕已恨遲。", "青史滿前閑即讀，幾人爲我作蓍龜。"]'),
('00f4937c-7a98-432d-8b6a-2084243e0260','門外野望','陸游','宋','宋诗','song-poetry','','[]','野迥浮烟碧，門深反照紅。',48,'全唐诗/poet.song.133000.json','["野迥浮烟碧，門深反照紅。", "柳邊雙鷺渚，天際萬鴉風。", "僧唄家禳疫，神船社送窮。", "豐年隨處樂，忘却鬢如蓬。"]'),
('d1f9d696-28f1-4955-b416-d06f970fd97d','自題傳神','陸游','宋','宋诗','song-poetry','','[]','識字深村叟，加巾下版僧。',48,'全唐诗/poet.song.133000.json','["識字深村叟，加巾下版僧。", "擔挑隻草屨，壁倚一烏藤。", "得酒猶能醉，逢山未怯登。", "莫論明日事，死至亦騰騰。"]'),
('401fb890-7e70-411b-8d9d-c75d5ce61a04','歲暮貧甚戲書','陸游','宋','宋诗','song-poetry','','[]','阿堵元知不受呼，忍貧閉戶亦良圖。',64,'全唐诗/poet.song.133000.json','["阿堵元知不受呼，忍貧閉戶亦良圖。", "曲身得火纔微直，槁面持杯祇暫朱。", "食案闌干堆苜蓿，褐衣顛倒著天吳。", "誰知未減粗豪在，落筆猶能賦兩都。"]'),
('98e59a30-017a-46d1-a4c7-47c101b3308c','晚晴閑步鄰曲間有賦','陸游','宋','宋诗','song-poetry','','[]','湯沐身輕念出遊，近春原野霽烟浮。',64,'全唐诗/poet.song.133000.json','["湯沐身輕念出遊，近春原野霽烟浮。", "樓陰雪在玉三寸，雲罅月生銀一鈎。", "窮巷客稀常足睡，暮年詩退不禁愁。", "鄉鄰無事冬耕罷，獨倚籬門數過牛。"]'),
('1a4e1e55-137f-4057-a0a0-72b9ef652b91','誦書示子聿二首  其一','陸游','宋','宋诗','song-poetry','','[]','乃翁誦書舍東偏，吾兒相和山之巔。',64,'全唐诗/poet.song.133000.json','["乃翁誦書舍東偏，吾兒相和山之巔。", "翁老且衰常早眠，兒聲夜半方泠然。", "楚公著書數百編，少師手校世世傳。", "我生七十有八年，見汝任此寧非天。"]'),
('cd2667aa-c6ac-45fa-9a35-5c8cdf3824b3','誦書示子聿二首  其二','陸游','宋','宋诗','song-poetry','','[]','易傳三聖至仲尼，炎炎秦火乃見遺。',64,'全唐诗/poet.song.133000.json','["易傳三聖至仲尼，炎炎秦火乃見遺。", "經中獨無一字疑，正須虛心以受之。", "世衰道散吁可悲，我老欲學無碩師。", "父子共讀忘朝饑，此生有盡志不移。"]'),
('00bc5e14-ae3d-40dd-87e8-c03f7940ed1b','十二月二十九日夜半雨雪作披衣起聽','陸游','宋','宋诗','song-poetry','','[]','臘雪瑞豐登，春雨相發生。',72,'全唐诗/poet.song.133000.json','["臘雪瑞豐登，春雨相發生。", "二者皆可賀，愛此打窗聲。", "披衣起靜聽，蕭蕭亂疏更。", "豈惟肺渴蘇，耳目爲一清。", "孤燈不結花，相對翳復明。", "明朝遂除夕，歲月驚崢嶸。"]'),
('c953cce1-57de-4199-afdc-01be1110cd34','辛酉除夕','陸游','宋','宋诗','song-poetry','','[]','衰境遇白雞，自分墮幽墟。',120,'全唐诗/poet.song.133000.json','["衰境遇白雞，自分墮幽墟。", "造物偶見寬，俯仰復歲除。", "駸駸迫耄期，凜凜無根株。", "孰知尚堅頑，壯者有不如。", "銅瓶垂碧井，手自浸屠蘇。", "松煤染兔穎，秉燭題桃符。", "登梯挂鍾馗，祭竈分其餘。", "僮奴嘆我健，却立不敢扶。", "新春無五日，節物傾里閭。", "羅旛插紗帽，一醉當百壺。"]'),
('bd2696ee-9f3c-44d1-8d58-4907a73d4d19','除夕','陸游','宋','宋诗','song-poetry','','[]','六聖涵濡作幸民，明朝七十八年身。',32,'全唐诗/poet.song.133000.json','["六聖涵濡作幸民，明朝七十八年身。", "門前西走都城道，卧看無窮來往人。"]'),
('2771873f-d278-4151-adb3-68a332cc7248','開歲','陸游','宋','宋诗','song-poetry','','[]','綠襦新畫衛門扉，賀刺相欺可累欷。',64,'全唐诗/poet.song.133000.json','["綠襦新畫衛門扉，賀刺相欺可累欷。", "賣困不靈仍喜睡，送窮無術又來歸。", "相尋蠶市人何在，爛醉蟆津事亦非。", "惟有禹祠春漸好，從今剩判典春衣。"]'),
('dead1e7a-0b88-4bbe-9988-a0eeb544cac9','箕卜','陸游','宋','宋诗','song-poetry','','[]','孟春百草靈，古俗迎紫姑。',120,'全唐诗/poet.song.133000.json','["孟春百草靈，古俗迎紫姑。", "厨中取竹箕，冒以婦裙襦。", "豎子夾扶持，插筆祝其書。", "俄若有物憑，對答不須臾。", "豈必考中否，一笑聊相娛。", "詩章亦間作，酒食隨所須。", "興闌忽辭去，誰能執其袪。", "持箕畀竈婢，棄筆卧牆隅。", "几席亦已徹，狼籍果與蔬。", "紛紛竟何益，人鬼均一愚。"]'),
('02a7f60b-5434-45ab-b62f-0c408c9d8cde','梅花絕句六首  其一','陸游','宋','宋诗','song-poetry','','[]','幾年不到合江園，說著當時已斷魂。',32,'全唐诗/poet.song.133000.json','["幾年不到合江園，說著當時已斷魂。", "只有梅花知此恨，相逢月底却無言。"]'),
('43f1ea13-e682-4dff-9162-007d4cdbdc01','梅花絕句六首  其二','陸游','宋','宋诗','song-poetry','','[]','當年走馬錦城西，曾爲梅花醉似泥。',32,'全唐诗/poet.song.133000.json','["當年走馬錦城西，曾爲梅花醉似泥。", "二十里中香不斷，青羊宮到浣花溪。"]'),
('9969b8e9-9f48-4df4-b782-6518b8b89b4b','梅花絕句六首  其三','陸游','宋','宋诗','song-poetry','','["\u548f\u7269", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6885\u82b1", "\u5b8b\u8bd7", "\u548f\u7269\u8bd7", "\u6292\u6000"]','聞道梅花坼曉風，雪堆遍滿四山中。',32,'全唐诗/poet.song.133000.json','["聞道梅花坼曉風，雪堆遍滿四山中。", "何方可化身千億，一樹梅前一放翁。"]'),
('18c18325-b80f-4635-992a-83defd5b4925','梅花絕句六首  其四','陸游','宋','宋诗','song-poetry','','[]','小亭終日倚闌干，樹樹梅花看到殘。',32,'全唐诗/poet.song.133000.json','["小亭終日倚闌干，樹樹梅花看到殘。", "只怪此翁常謝客，元來不是怕春寒。"]'),
('423f9f95-9768-436f-b37c-b52114444435','梅花絕句六首  其五','陸游','宋','宋诗','song-poetry','','[]','亂簪桐帽花如雪，斜挂驢鞍酒滿壺。',32,'全唐诗/poet.song.133000.json','["亂簪桐帽花如雪，斜挂驢鞍酒滿壺。", "安得丹青如顧陸，憑渠畫我夜歸圖。"]'),
('58399fa4-7294-4336-9942-a418c6a55ab1','梅花絕句六首  其六','陸游','宋','宋诗','song-poetry','','[]','紅梅過後到緗梅，一種春風不並開。',32,'全唐诗/poet.song.133000.json','["紅梅過後到緗梅，一種春風不並開。", "造物無心還有意，引教日日放翁來。"]'),
('cc6ad977-90cf-4758-8737-4ef11015bae8','立春前一日作','陸游','宋','宋诗','song-poetry','','[]','開年化日已舒長，漸見風和鳥變吭。',64,'全唐诗/poet.song.133000.json','["開年化日已舒長，漸見風和鳥變吭。", "冒土萱芽抽嫩綠，拂橋柳色弄輕黄。", "重溫壽酒屠蘇釅，探借春盤餅餌香。", "不入城門今幾歲，遥知車馬正匆忙。"]'),
('414ae8c4-00c3-4efe-83dc-6d58b64a2f2c','立春日','陸游','宋','宋诗','song-poetry','','[]','日出風和宿醉醒，山家樂事滿餘齡。',64,'全唐诗/poet.song.133000.json','["日出風和宿醉醒，山家樂事滿餘齡。", "年豐臘雪經三白，地暖春郊已遍青。", "菜細簇花宜薄餅，酒香浮螘瀉長瓶。", "湖村好景吟難盡，乞與侯家作畫屏。"]'),
('1f745e3b-8864-4736-97e1-b3972d949fe2','送子龍赴吉州掾','陸游','宋','宋诗','song-poetry','','[]','我老汝遠行，知汝非得已。',288,'全唐诗/poet.song.133000.json','["我老汝遠行，知汝非得已。", "駕言當送汝，揮涕不能止。", "人誰樂離別，坐貧至于此。", "汝行犯胥濤，次第過彭蠡。", "波橫吞舟魚，林嘯獨脚鬼。", "野飯何店炊，孤櫂何岸檥。", "判司比唐時，猶幸免笞箠。", "庭參亦何辱，負職乃可耻。", "汝爲吉州吏，但飲吉州水。", "一錢亦分明，誰能肆讒毀。", "聚俸嫁阿惜，擇士教元禮。", "我食可自營，勿用念甘旨。", "衣穿聽露肘，履破從見指。", "山門雖被嘲，歸舍却睡美。", "益公名位重，凜若喬嶽峙。", "汝以通家故，或許望燕几。", "得見已足榮，切勿有所啟。", "又若楊誠齋，清介世莫比。", "一聞俗人言，三日歸洗耳。", "汝但問起居，餘事勿挂齒。", "希周有世好，敬叔乃鄉里。", "豈惟能文辭，實亦堅操履。", "相從勉講學，事業在積累。", "仁義本何常，蹈之則君子。"]'),
('122ef80b-40de-4521-84ca-9f29f578007f','正月五日出遊','陸游','宋','宋诗','song-poetry','','[]','久作閑人不慣愁，新春天氣更清柔。',64,'全唐诗/poet.song.133000.json','["久作閑人不慣愁，新春天氣更清柔。", "未爲遼海千年別，且繼斜川五日遊。", "細柳拂頭穿野徑，落梅黏袖上漁舟。", "此身定去神仙近，倚遍江南賣酒樓。"]'),
('54459d5f-b884-45b2-9153-e2364f9efab1','六日雲重有雪意獨酌','陸游','宋','宋诗','song-poetry','','[]','遍遊數澤一漁舠，盡歷風霜只縕袍。',64,'全唐诗/poet.song.133000.json','["遍遊數澤一漁舠，盡歷風霜只縕袍。", "天爲念貧偏與健，人因見懶誤稱高。", "地連海澨濤聲近，雲冒山椒雪意豪。", "偶得名罇當痛飲，凉州那得直蒲萄。"]'),
('2670e4d9-956d-4979-907d-6b199414e646','閑甚戲作','陸游','宋','宋诗','song-poetry','','[]','酒盡枵樽腹，書拋委架塵。',48,'全唐诗/poet.song.133000.json','["酒盡枵樽腹，書拋委架塵。", "漸能閑過日，始覺老催人。", "玉麈王夷甫，金龜賀季真。", "若論方外事，終愧葛天民。"]'),
('70fc48f1-117b-4402-bf3a-9540269a2280','莫笑','陸游','宋','宋诗','song-poetry','','[]','莫笑窮閻叟，人生亦已稀。',48,'全唐诗/poet.song.133000.json','["莫笑窮閻叟，人生亦已稀。", "眾中容後死，險處得先歸。", "初服還韋布，晨餐美蕨薇。", "床頭周易在，捨此復疇依。"]'),
('7984cf39-4a95-426c-9829-5d171ea5cf67','初春雜興五首  其一','陸游','宋','宋诗','song-poetry','','[]','戲續春寒賦，閑賡午醉詩。',48,'全唐诗/poet.song.133000.json','["戲續春寒賦，閑賡午醉詩。", "煎茶小石鼎，酌酒古銅卮。", "曝日龜浮沼，營巢鵲墮枝。", "村深無客過，幽興與誰期。"]'),
('e049c040-320c-45e8-97ee-18b2149b9b67','初春雜興五首  其二','陸游','宋','宋诗','song-poetry','','[]','水長鷗初泛，山寒茗未芽。',48,'全唐诗/poet.song.133000.json','["水長鷗初泛，山寒茗未芽。", "深林聞社鼓，落日照漁家。", "渡遠呼船久，橋傾取路斜。", "客愁慵遠眺，不是怯風沙。"]'),
('1bb401c4-54de-4ef8-b705-456c5ec8ad28','初春雜興五首  其三','陸游','宋','宋诗','song-poetry','','[]','問途來野店，秣蹇憩山郵。',48,'全唐诗/poet.song.133000.json','["問途來野店，秣蹇憩山郵。", "何處無詩思，平生慣旅愁。", "翩翩下鷗鷺，點點散羊牛。", "傳入王孫畫，千金未易酬。"]'),
('6b203685-8731-4ed6-b6d9-7001df0d25b5','初春雜興五首  其四','陸游','宋','宋诗','song-poetry','','[]','故歲愁聽雨，新春剩得晴。',48,'全唐诗/poet.song.133000.json','["故歲愁聽雨，新春剩得晴。", "暖催紅蕊鬧，漲入綠池平。", "遊馬行爭路，華燈賣滿城。", "江村獨無事，戶戶及時耕。"]'),
('1ce9cf5b-7f8b-4fd9-9175-ae39d69552d4','初春雜興五首  其五','陸游','宋','宋诗','song-poetry','','[]','老病倦遊陟，偶尋溪友期。',48,'全唐诗/poet.song.133000.json','["老病倦遊陟，偶尋溪友期。", "殘冰擁魚笱，新暖入桑枝。", "山崦巨然畫，烟村摩詰詩。", "何人爲收拾，愧我不能奇。"]'),
('deb20747-783a-4e1e-ab3b-6e8b470bad68','春曉','陸游','宋','宋诗','song-poetry','','[]','喔喔雞號野，昏昏月挂樓。',48,'全唐诗/poet.song.133000.json','["喔喔雞號野，昏昏月挂樓。", "夢隨殘漏斷，愁伴宿酲留。", "壯士看清鏡，春寒著弊裘。", "拂窗新柳色，最憶錦江頭。"]'),
('c0a0a169-e584-4815-84ab-bc4039807025','書感','陸游','宋','宋诗','song-poetry','','[]','投老羈孤久，臨觴感慨頻。',48,'全唐诗/poet.song.133000.json','["投老羈孤久，臨觴感慨頻。", "關河疏舊友，風雨敗新春。", "事固少如意，天終能勝人。", "所悲頭上髮，不與柳條新。"]'),
('a2e2c241-6928-4997-98ce-2a7afc061461','壬戌正月十四日','陸游','宋','宋诗','song-poetry','','[]','老子居然健，上元如許晴。',48,'全唐诗/poet.song.133000.json','["老子居然健，上元如許晴。", "湖平波不起，天闊月徐行。", "散髮漁舟穩，臨風野笛清。", "安能擁笳鼓，萬里將幽并。"]'),
('95c0bd96-7713-434a-b6e2-a1fd7ecaffd9','十五日','陸游','宋','宋诗','song-poetry','','[]','誰推圜鏡上天東，桂影婆娑滿鏡中。',64,'全唐诗/poet.song.133000.json','["誰推圜鏡上天東，桂影婆娑滿鏡中。", "天宇更無雲一點，譙門初報鼓三通。", "兒童草草杯盤喜，鄰曲紛紛笑語同。", "逐祿豈能無聚散，明年誰復伴衰翁。"]'),
('ae3d0496-8a32-4249-a973-dddfd96fe930','高枕','陸游','宋','宋诗','song-poetry','','[]','高枕閑看古篆香，世間萬事本茫茫。',64,'全唐诗/poet.song.133000.json','["高枕閑看古篆香，世間萬事本茫茫。", "偶亡塞馬寧非福，太察淵魚恐不祥。", "每與諸兒論今古，常思百世業耕桑。", "危機正在黄金印，笑殺初心繆激昂。"]'),
('294c5e13-42b3-4853-8e1c-17f9a1d768b4','送施武子通判','陸游','宋','宋诗','song-poetry','','[]','初入修門鬢未秋，安期千里接英遊。',64,'全唐诗/poet.song.133000.json','["初入修門鬢未秋，安期千里接英遊。", "退歸久散前三眾，邁往欣逢第一流。", "只道升沉方異趣，豈知氣類肯相求。", "龍鍾不得臨江別，目斷西陵烟雨舟。"]'),
('4051efda-7a4b-4c17-b41b-019697839319','老學庵自規','陸游','宋','宋诗','song-poetry','','[]','堯德被四表，其本在身修。',120,'全唐诗/poet.song.133000.json','["堯德被四表，其本在身修。", "江河水稽天，發源乃涓流。", "人忍於搏蝨，習熟且解牛。", "象箸與玉杯，漆器實其由。", "斯須失兢畏，惡名溢九州。", "始乎爲善士，終可蹈軻丘。", "孰置汝太山，孰擠汝污溝。", "降福孰汝私，得禍孰汝讎。", "聖狂在一念，禍福皆自求。", "易簀汝所知，垂死勿惰偷。"]'),
('ead1513c-93c8-4792-b3b8-b74134f0236c','雨夜','陸游','宋','宋诗','song-poetry','','[]','斷岸輕烟著柳條，孤村小雨夜蕭蕭。',64,'全唐诗/poet.song.133000.json','["斷岸輕烟著柳條，孤村小雨夜蕭蕭。", "荒雞隔浦聲相續，短燭無風焰自摇。", "樸學元知縻歲月，殘生竟是老漁樵。", "最憐鬢畔千莖雪，日日春風吹不消。"]'),
('ca8d9215-aba8-444d-9973-1e7478549536','子聿以剛日讀易柔日讀春秋常至夜分每聽之輒欣然忘百憂作長句示之','陸游','宋','宋诗','song-poetry','','[]','朱顔已去鬢絲稠，知復人間幾歲留。',64,'全唐诗/poet.song.133000.json','["朱顔已去鬢絲稠，知復人間幾歲留。", "正可床頭著周易，安能車上說春秋。", "齏鹽日昳從兒好，弦誦更闌解我憂。", "時發一言常中理，絕勝問事不能休。"]'),
('55246ada-213c-4fe0-8d60-af65a00bc966','記夢','陸游','宋','宋诗','song-poetry','','[]','信命從來不問天，經旬無酒亦陶然。',32,'全唐诗/poet.song.133000.json','["信命從來不問天，經旬無酒亦陶然。", "夢爲估客揚州去，水調聲中月滿船。"]'),
('13f14940-ad50-40d2-ac15-8446858a4fa2','夜賦','陸游','宋','宋诗','song-poetry','','[]','八十衰翁久挂冠，今年無酒敵春寒。',64,'全唐诗/poet.song.133000.json','["八十衰翁久挂冠，今年無酒敵春寒。", "亂雲入戶雨方急，斷雁叫群燈未殘。", "蠹簡幸存隨意讀，蝸廬雖小著身寬。", "支離自笑心猶壯，憂國憂家慮萬端。"]'),
('a30f6b62-40f1-4691-9389-6a02e801958b','杜叔高秀才雨雪中相過留一宿而別口誦此詩送之','陸游','宋','宋诗','song-poetry','','[]','久客方知行路難，關山無際水漫漫。',64,'全唐诗/poet.song.133000.json','["久客方知行路難，關山無際水漫漫。", "風吹欲倒孤城遠，雪落如簁野寺寒。", "暮挈衣囊投土室，晨沽村酒挂驢鞍。", "文章一字無人識，胸次徒勞萬卷蟠。"]'),
('996cf016-70e1-4f81-8578-4d2d87f3f5bd','曉賦','陸游','宋','宋诗','song-poetry','','[]','雞晨非一唱，鴉旦每三鳴。',48,'全唐诗/poet.song.133000.json','["雞晨非一唱，鴉旦每三鳴。", "萬物各有役，吾生何所營。", "書編猶未掩，窗紙已微明。", "稚子勇過我，琅琅誦易聲。"]'),
('65f69da1-9163-4f06-b4ce-4923da726ecc','雪後龜堂獨坐四首  其一','陸游','宋','宋诗','song-poetry','','[]','丈夫自重如拱璧，安用人看一錢直。',64,'全唐诗/poet.song.133000.json','["丈夫自重如拱璧，安用人看一錢直。", "簞食豆羹不虛受，富貴那可從人得。", "讀書萬卷行愧心，幽有鬼神爲君惜。", "龜堂樂處誰得知，紅日滿窗聽雪滴。"]'),
('38b8ec94-2198-479e-aabc-8242ca9b4bff','雪後龜堂獨坐四首  其二','陸游','宋','宋诗','song-poetry','','[]','兩手龜坼愁出袖，閉戶垂帷坐清晝。',64,'全唐诗/poet.song.133000.json','["兩手龜坼愁出袖，閉戶垂帷坐清晝。", "朝陽破雲雪漸消，點滴無窮聽簷溜。", "士生百行雖相補，第一要能安飯糗。", "詩書幸可教兒童，勿使後人憐晚謬。"]'),
('02e02b78-d28d-48f2-a745-f3c3462c5379','雪後龜堂獨坐四首  其三','陸游','宋','宋诗','song-poetry','','[]','牙齒欲落何足惜，爛煮藜羹自堪食。',64,'全唐诗/poet.song.133000.json','["牙齒欲落何足惜，爛煮藜羹自堪食。", "屋穿不害氣吐虹，客至從驚瘦如腊。", "天公鎸汝亦已至，春風裂面雪三尺。", "濁醪傾罷仰屋歌，尚友孫侔與徐積。"]');
